const LB_TO_KG = 0.45359237;
const IN_TO_CM = 2.54;

const formatNum = (val: any) => {
  const n = parseFloat(String(val).replace(/[^0-9.]/g, ''));
  return isNaN(n) ? '0' : parseFloat(n.toFixed(2)).toString();
};

interface ListingDetailProps {
  listing: Listing;
  onBack: () => void;
  onUpdate: (updatedListing: Listing) => void;
  onNext: () => void;
  uiLang: UILanguage;
}

type AIProvider = 'gemini' | 'openai' | 'deepseek';

// 定义点数消耗规则
const CREDIT_COSTS: Record<AIProvider, number> = {
  gemini: 3,
  openai: 2,
  deepseek: 1
};

export const ListingDetail: React.FC<ListingDetailProps> = ({ listing, onBack, onUpdate, onNext, uiLang }) => {
  const t = useTranslation(uiLang);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [lastSaved, setLastSaved] = useState<string | null>(null);
  const [isTranslating, setIsTranslating] = useState<string | null>(null);
  const [isTranslatingAll, setIsTranslatingAll] = useState(false);
  const [aiProvider, setAiProvider] = useState<AIProvider>(() => {
    const saved = localStorage.getItem('app_ai_provider') as AIProvider;
    return saved || 'gemini';
  });

  const [localListing, setLocalListing] = useState<Listing>(listing);
  const [selectedImage, setSelectedImage] = useState<string>(listing.cleaned?.main_image || '');
  const [activeMarketplace, setActiveMarketplace] = useState<string>('US'); 
  const [exchangeRates, setExchangeRates] = useState<ExchangeRate[]>([]);

  useEffect(() => {
    localStorage.setItem('app_ai_provider', aiProvider);
  }, [aiProvider]);

  useEffect(() => {
    fetchPricingData();
  }, []);

  const fetchPricingData = async () => {
    if (!isSupabaseConfigured()) return;
    const { data } = await supabase.from('exchange_rates').select('*');
    if (data) setExchangeRates(data);
  };

  const checkAndConsumeCredit = async (provider: AIProvider): Promise<boolean> => {
    if (!isSupabaseConfigured()) return false;
    const { data: { session } } = await supabase.auth.getSession();
    if (!session) return false;

    const { data: profile } = await supabase
      .from('user_profiles')
      .select('*')
      .eq('id', session.user.id)
      .single();

    const cost = CREDIT_COSTS[provider];
    if (!profile || (profile.credits_total - profile.credits_used) < cost) {
      alert(uiLang === 'zh' ? `余额不足。使用 ${provider} 需要 ${cost} 点，请前往财务中心升级。` : `Insufficient credits. ${provider} costs ${cost} credits.`);
      return false;
    }

    // 扣除点数并记录日志
    const { error: updateError } = await supabase
      .from('user_profiles')
      .update({ credits_used: profile.credits_used + cost })
      .eq('id', session.user.id);

    if (updateError) throw updateError;

    // 记录使用日志
    await supabase.from('usage_logs').insert([{
      user_id: session.user.id,
      model: provider,
      action: 'ai_process',
      credits_spent: cost
    }]);

    return true;
  };

  const handleOptimize = async () => {
    if (!(await checkAndConsumeCredit(aiProvider))) return;

    setIsOptimizing(true);
    try {
      let opt;
      if (aiProvider === 'openai') {
        opt = await optimizeListingWithOpenAI(localListing.cleaned!);
      } else if (aiProvider === 'deepseek') {
        opt = await optimizeListingWithDeepSeek(localListing.cleaned!);
      } else {
        opt = await optimizeListingWithAI(localListing.cleaned!);
      }
      const updated = { ...localListing, status: 'optimized' as const, optimized: opt };
      setLocalListing(updated);
      await syncToSupabase(updated);
    } catch (e: any) { alert("Optimization failed: " + e.message); } 
    finally { setIsOptimizing(false); }
  };

  const syncToSupabase = async (targetListing: Listing) => {
    if (!isSupabaseConfigured()) return;
    setIsSaving(true);
    try {
      const payload = {
        cleaned: targetListing.cleaned,
        optimized: targetListing.optimized || null,
        translations: targetListing.translations || null,
        status: targetListing.status,
        sourcing_data: targetListing.sourcing_data || [],
        updated_at: new Date().toISOString()
      };
      const { error } = await supabase.from('listings').update(payload).eq('id', targetListing.id);
      if (error) throw error;
      onUpdate({ ...targetListing, updated_at: new Date().toISOString() });
      setLastSaved(new Date().toLocaleTimeString());
    } catch (e: any) { 
      console.error("Save failed:", e);
    } finally { 
      setIsSaving(false); 
    }
  };

  // 渲染其余 UI (保持原样，仅展示计费逻辑更改)
  return (
    <div className="p-8 max-w-7xl mx-auto space-y-6 text-slate-900 font-inter animate-in fade-in duration-500 pb-20 relative">
      {/* 渲染内容 */}
      <div className="flex items-center justify-between bg-white/80 backdrop-blur-md p-4 rounded-2xl border border-slate-200 shadow-sm sticky top-4 z-40">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="flex items-center text-slate-500 hover:text-slate-900 font-black text-sm uppercase tracking-widest">
            <ArrowLeft size={18} className="mr-2" /> {t('back')}
          </button> 
          {lastSaved && <div className="flex items-center gap-1.5 text-[10px] font-black text-green-500 uppercase bg-green-50 px-3 py-1 rounded-full border border-green-100"><Check size={12} /> Auto-saved @ {lastSaved}</div>}
        </div>
        <div className="flex gap-4 items-center">
          <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200">
            <button onClick={() => setAiProvider('gemini')} className={`px-4 py-2 rounded-lg text-xs font-black uppercase transition-all ${aiProvider === 'gemini' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>Gemini (3)</button>
            <button onClick={() => setAiProvider('openai')} className={`px-4 py-2 rounded-lg text-xs font-black uppercase transition-all ${aiProvider === 'openai' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-400'}`}>GPT-4o (2)</button>
            <button onClick={() => setAiProvider('deepseek')} className={`px-4 py-2 rounded-lg text-xs font-black uppercase transition-all ${aiProvider === 'deepseek' ? 'bg-white text-orange-600 shadow-sm' : 'text-slate-400'}`}>DeepSeek (1)</button>
          </div>
          <button onClick={handleOptimize} disabled={isOptimizing} className="flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-sm text-slate-700 bg-white border border-slate-200 hover:bg-slate-50 transition-all uppercase">{isOptimizing ? <Loader2 className="animate-spin" size={18} /> : <Sparkles size={18} />} AI Optimize</button>
          <button onClick={() => syncToSupabase(localListing)} disabled={isSaving} className="flex items-center gap-2 px-8 py-2.5 rounded-xl font-black text-sm text-white bg-indigo-600 hover:bg-indigo-700 shadow-lg active:scale-95 transition-all uppercase">{isSaving ? <Loader2 size={18} className="animate-spin" /> : <Save size={18} />} {t('save')}</button>
        </div>
      </div>
      {/* 其他 ListingDetail 组件内容... */}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  Users, Package, Settings, Search, Filter, ShieldAlert, 
  MoreHorizontal, ChevronRight, Loader2, Save, Trash2, 
  Clock, CreditCard, Ban, CheckCircle, RefreshCcw, UserPlus, ShieldCheck 
} from 'lucide-react';
import { UserProfile, SubscriptionPlan, UILanguage } from '../types';
import { supabase, isSupabaseConfigured } from '../lib/supabaseClient';

interface AdminDashboardProps {
  uiLang: UILanguage;
}

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ uiLang }) => {
  const [activeTab, setActiveTab] = useState<'users' | 'plans'>('users');
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [isUpdating, setIsUpdating] = useState<string | null>(null);

  useEffect(() => {
    fetchData();
  }, [activeTab]);

  const fetchData = async () => {
    if (!isSupabaseConfigured()) return;
    setLoading(true);
    try {
      if (activeTab === 'users') {
        const { data } = await supabase.from('user_profiles').select('*').order('created_at', { ascending: false });
        if (data) setUsers(data);
      } else {
        const { data } = await supabase.from('subscription_plans').select('*').order('price_usd', { ascending: true });
        if (data) setPlans(data);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleToggleSuspension = async (user: UserProfile) => {
    setIsUpdating(user.id);
    const { error } = await supabase
      .from('user_profiles')
      .update({ is_suspended: !user.is_suspended })
      .eq('id', user.id);

    if (!error) {
      setUsers(users.map(u => u.id === user.id ? { ...u, is_suspended: !u.is_suspended } : u));
    }
    setIsUpdating(null);
  };

  const handleUpdateCredits = async (userId: string, newTotal: number) => {
    const { error } = await supabase
      .from('user_profiles')
      .update({ credits_total: newTotal })
      .eq('id', userId);
    if (!error) {
      setUsers(users.map(u => u.id === userId ? { ...u, credits_total: newTotal } : u));
    }
  };

  return (
    <div className="p-8 max-w-7xl mx-auto space-y-8 animate-in fade-in duration-500">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-5">
          <div className="w-16 h-16 bg-slate-900 rounded-3xl flex items-center justify-center text-white shadow-2xl">
            <ShieldCheck size={32} />
          </div>
          <div>
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Admin Console</h2>
            <p className="text-sm text-slate-400 font-bold uppercase tracking-widest italic">Operations & Control Hub</p>
          </div>
        </div>

        <div className="flex bg-slate-100 p-1 rounded-2xl border border-slate-200">
          <button 
            onClick={() => setActiveTab('users')}
            className={`px-8 py-3 rounded-xl text-xs font-black uppercase transition-all flex items-center gap-2 ${activeTab === 'users' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <Users size={16} /> Users
          </button>
          <button 
            onClick={() => setActiveTab('plans')}
            className={`px-8 py-3 rounded-xl text-xs font-black uppercase transition-all flex items-center gap-2 ${activeTab === 'plans' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <Package size={16} /> Plans
          </button>
        </div>
      </div>

      {activeTab === 'users' ? (
        <div className="space-y-6">
          <div className="flex items-center gap-4">
             <div className="relative flex-1">
               <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
               <input 
                type="text" 
                placeholder="Search user ID or email..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-12 pr-4 py-4 bg-white border border-slate-200 rounded-3xl focus:ring-4 focus:ring-indigo-500/5 outline-none font-bold"
               />
             </div>
             <button onClick={fetchData} className="p-4 bg-white border border-slate-200 rounded-3xl text-slate-400 hover:text-indigo-600 transition-all">
               <RefreshCcw size={20} className={loading ? 'animate-spin' : ''} />
             </button>
          </div>

          <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
             <table className="w-full text-left">
                <thead>
                  <tr className="bg-slate-50 border-b border-slate-100 text-[10px] font-black uppercase text-slate-400 tracking-widest">
                    <th className="p-8">User Info</th>
                    <th className="p-8">Subscription</th>
                    <th className="p-8">Credits Status</th>
                    <th className="p-8">Last Login</th>
                    <th className="p-8 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {users.filter(u => u.id.includes(searchTerm)).map(user => (
                    <tr key={user.id} className={`group hover:bg-slate-50/50 transition-all ${user.is_suspended ? 'opacity-50 grayscale' : ''}`}>
                      <td className="p-8">
                        <div className="flex items-center gap-4">
                           <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-black ${user.role === 'admin' ? 'bg-amber-100 text-amber-600' : 'bg-indigo-100 text-indigo-600'}`}>
                             {user.id.slice(0, 2).toUpperCase()}
                           </div>
                           <div>
                              <p className="font-black text-slate-900 text-sm">{user.id.slice(0, 8)}...</p>
                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tight">{user.role}</p>
                           </div>
                        </div>
                      </td>
                      <td className="p-8">
                        <span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-black uppercase border border-indigo-100">
                          {user.plan_type}
                        </span>
                      </td>
                      <td className="p-8">
                        <div className="flex items-center gap-3">
                           <div>
                             <p className="text-xs font-black text-slate-900">{user.credits_total - user.credits_used} / {user.credits_total}</p>
                             <div className="w-24 h-1 bg-slate-100 rounded-full mt-1">
                               <div 
                                className="h-full bg-indigo-500 rounded-full" 
                                style={{ width: `${Math.min(100, (user.credits_used / user.credits_total) * 100)}%` }}
                               ></div>
                             </div>
                           </div>
                        </div>
                      </td>
                      <td className="p-8">
                        <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase">
                          <Clock size={14} className="text-slate-200" />
                          {user.last_login_at ? new Date(user.last_login_at).toLocaleDateString() : 'Never'}
                        </div>
                      </td>
                      <td className="p-8 text-right">
                        <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-all">
                           <button 
                            onClick={() => {
                              const extra = prompt("Add how many credits?", "500");
                              if (extra) handleUpdateCredits(user.id, user.credits_total + parseInt(extra));
                            }}
                            className="p-3 text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl"
                           >
                             <CreditCard size={18} />
                           </button>
                           <button 
                            onClick={() => handleToggleSuspension(user)}
                            className={`p-3 rounded-xl transition-all ${user.is_suspended ? 'text-emerald-600 bg-emerald-50' : 'text-slate-400 hover:text-red-600 hover:bg-red-50'}`}
                           >
                             {isUpdating === user.id ? <Loader2 className="animate-spin" size={18} /> : (user.is_suspended ? <CheckCircle size={18} /> : <Ban size={18} />)}
                           </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
             </table>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
           {plans.map(plan => (
             <div key={plan.id} className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm space-y-8 flex flex-col">
                <div className="flex justify-between items-start">
                   <div>
                     <h4 className="text-2xl font-black text-slate-900">{plan.name_zh}</h4>
                     <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">{plan.id}</p>
                   </div>
                   <div className="text-right">
                     <p className="text-3xl font-black text-slate-900">${plan.price_usd}</p>
                   </div>
                </div>

                <div className="space-y-4 flex-1">
                   <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 space-y-2">
                      <p className="text-[10px] font-black text-slate-400 uppercase">Included Credits</p>
                      <p className="text-xl font-black text-indigo-600">{plan.credits}</p>
                   </div>

                   <div className="space-y-2">
                      <p className="text-[10px] font-black text-slate-400 uppercase ml-1">Plan Features</p>
                      {plan.features_zh.map((f, i) => (
                        <div key={i} className="flex items-center gap-2 text-xs font-bold text-slate-500">
                          <Check size={12} className="text-indigo-400" /> {f}
                        </div>
                      ))}
                   </div>
                </div>

                <button className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                   <Settings size={16} /> Edit Config
                </button>
             </div>
           ))}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './components/Dashboard';
import { ListingsManager } from './components/ListingsManager';
import { LandingPage } from './components/LandingPage';
import { ListingDetail } from './components/ListingDetail';
import { AuthPage } from './components/AuthPage';
import { TemplateManager } from './components/TemplateManager';
import { CategoryManager } from './components/CategoryManager';
import { PricingManager } from './components/PricingManager';
import { BillingCenter } from './components/BillingCenter';
import { AdminDashboard } from './components/AdminDashboard';
import { AppView, Listing, UILanguage, UserProfile } from './types';
import { supabase, isSupabaseConfigured } from './lib/supabaseClient';
import { AlertTriangle, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.LANDING);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedListing, setSelectedListing] = useState<Listing | null>(null);
  const [session, setSession] = useState<any>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const [isInitialFetch, setIsInitialFetch] = useState(false);
  const [lang, setLang] = useState<UILanguage>('zh');
  const [listings, setListings] = useState<Listing[]>([]);
  const [initError, setInitError] = useState<string | null>(null);

  useEffect(() => {
    const savedLang = localStorage.getItem('app_lang') as UILanguage;
    if (savedLang) setLang(savedLang);
  }, []);

  const fetchUserProfile = async (userId: string) => {
    if (!isSupabaseConfigured()) return;
    const { data, error } = await supabase
      .from('user_profiles')
      .select('*')
      .eq('id', userId)
      .single();

    if (data) {
      if (data.is_suspended) {
        alert("Your account is suspended. Contact support.");
        await supabase.auth.signOut();
        return;
      }
      setUserProfile(data);
      // 更新最后登录时间
      await supabase.from('user_profiles').update({ last_login_at: new Date().toISOString() }).eq('id', userId);
    }
  };

  useEffect(() => {
    if (!isSupabaseConfigured()) {
      setInitError("Supabase configuration is missing.");
      setLoading(false);
      return;
    }

    supabase.auth.getSession().then(({ data: { session: currentSession } }) => {
      setSession(currentSession);
      if (currentSession) {
        setView(AppView.DASHBOARD);
        fetchListings(currentSession.user.id);
        fetchUserProfile(currentSession.user.id);
      }
      setLoading(false);
    }).catch(err => {
      console.error("Auth init error:", err);
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, newSession) => {
      setSession(newSession);
      if (event === 'SIGNED_IN' && newSession) {
        setView(AppView.DASHBOARD);
        fetchListings(newSession.user.id);
        fetchUserProfile(newSession.user.id);
      } else if (event === 'SIGNED_OUT') {
        setView(AppView.LANDING);
        setListings([]);
        setSelectedListing(null);
        setUserProfile(null);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleLanguageChange = (newLang: UILanguage) => {
    setLang(newLang);
    localStorage.setItem('app_lang', newLang);
  };

  const fetchListings = useCallback(async (userId?: string) => {
    const uid = userId || session?.user?.id;
    if (!isSupabaseConfigured() || !uid) return;

    setIsInitialFetch(true);
    try {
      const { data, error } = await supabase
        .from('listings')
        .select('*')
        .eq('user_id', uid)
        .order('created_at', { ascending: false });

      if (error) throw error;
      setListings(data || []);
    } catch (e) {
      console.error("Fetch failed:", e);
    } finally {
      setIsInitialFetch(false);
    }
  }, [session]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  const handleTabChange = (tab: string) => {
    setActiveTab(tab);
    if (view === AppView.LISTING_DETAIL || view === AppView.ADMIN) {
      setView(AppView.DASHBOARD);
    }
  };

  const handleLoginClick = () => {
    if (session) setView(AppView.DASHBOARD);
    else setView(AppView.AUTH);
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-white">
      <div className="w-16 h-16 border-4 border-indigo-600/20 border-t-indigo-600 rounded-full animate-spin"></div>
      <p className="mt-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Initializing AMZBot</p>
    </div>
  );

  const renderContent = () => {
    if (view === AppView.ADMIN && userProfile?.role === 'admin') {
      return <AdminDashboard uiLang={lang} />;
    }
    if (view === AppView.LISTING_DETAIL && selectedListing) {
      return (
        <ListingDetail 
          listing={selectedListing} 
          onBack={() => { setView(AppView.DASHBOARD); fetchListings(); }}
          onUpdate={(updated) => {
            setListings(prev => prev.map(l => l.id === updated.id ? updated : l));
            setSelectedListing(updated);
          }}
          onNext={() => {
            const idx = listings.findIndex(l => l.id === selectedListing.id);
            if (idx === -1) return;
            const next = listings[(idx + 1) % listings.length];
            setSelectedListing(next);
          }}
          uiLang={lang}
        />
      );
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard listings={listings} lang={lang} isSyncing={isInitialFetch} onRefresh={() => fetchListings()} />;
      case 'listings': return <ListingsManager onSelectListing={(l) => { setSelectedListing(l); setView(AppView.LISTING_DETAIL); }} listings={listings} setListings={setListings} lang={lang} refreshListings={() => fetchListings()} isInitialLoading={isInitialFetch} />;
      case 'categories': return <CategoryManager uiLang={lang} />;
      case 'pricing': return <PricingManager uiLang={lang} />;
      case 'templates': return <TemplateManager uiLang={lang} />;
      case 'billing': return <BillingCenter uiLang={lang} />;
      case 'admin': 
        if (userProfile?.role === 'admin') {
          setView(AppView.ADMIN);
          return null;
        }
        return <Dashboard listings={listings} lang={lang} isSyncing={isInitialFetch} onRefresh={() => fetchListings()} />;
      default: return <Dashboard listings={listings} lang={lang} isSyncing={isInitialFetch} onRefresh={() => fetchListings()} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      {view !== AppView.LANDING && view !== AppView.AUTH && (
        <Sidebar 
          onLogout={handleLogout} 
          onLogoClick={() => setView(AppView.LANDING)} 
          activeTab={activeTab} 
          setActiveTab={handleTabChange} 
          lang={lang} 
          userEmail={session?.user?.email}
          userProfile={userProfile}
        />
      )}

      <main className={`${view !== AppView.LANDING && view !== AppView.AUTH ? 'ml-64' : 'w-full'} flex-1 flex flex-col h-screen overflow-hidden`}>
        <div className="flex-1 overflow-y-auto custom-scrollbar">
           {view === AppView.LANDING ? (
             <LandingPage onLogin={handleLoginClick} onLogoClick={() => setView(AppView.LANDING)} uiLang={lang} onLanguageChange={handleLanguageChange} />
           ) : view === AppView.AUTH ? (
             <AuthPage onBack={() => setView(AppView.LANDING)} onLogoClick={() => setView(AppView.LANDING)} uiLang={lang} />
           ) : (
             renderContent()
           )}
        </div>
      </main>
    </div>
  );
};

