import React, { useState, useRef, useEffect } from 'react';
import { Package, LogOut, LayoutDashboard, Settings, Layout, List, Tags, Coins, CreditCard, User, ChevronRight, Crown, Sparkles, Mail, ShieldCheck } from 'lucide-react';
