import React, { useState, useEffect } from 'react';
import { 
  Users, Package, Settings, Search, Filter, ShieldAlert, 
  MoreHorizontal, ChevronRight, Loader2, Save, Trash2, 
  Clock, CreditCard, Ban, CheckCircle, RefreshCcw, UserPlus, ShieldCheck, Check 
} from 'lucide-react';
import { UserProfile, SubscriptionPlan, UILanguage } from '../types';
import { supabase, isSupabaseConfigured } from '../lib/supabaseClient';

interface AdminDashboardProps {
  uiLang: UILanguage;
}

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ uiLang }) => {
  const [activeTab, setActiveTab] = useState<'users' | 'plans'>('users');
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [isUpdating, setIsUpdating] = useState<string | null>(null);

  useEffect(() => {
    fetchData();
  }, [activeTab]);

  const fetchData = async () => {
    if (!isSupabaseConfigured()) return;
    setLoading(true);
    try {
      if (activeTab === 'users') {
        const { data } = await supabase.from('user_profiles').select('*').order('created_at', { ascending: false });
        if (data) setUsers(data);
      } else {
        const { data } = await supabase.from('subscription_plans').select('*').order('price_usd', { ascending: true });
        if (data) setPlans(data);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleToggleSuspension = async (user: UserProfile) => {
    setIsUpdating(user.id);
    const { error } = await supabase
      .from('user_profiles')
      .update({ is_suspended: !user.is_suspended })
      .eq('id', user.id);

    if (!error) {
      setUsers(users.map(u => u.id === user.id ? { ...u, is_suspended: !u.is_suspended } : u));
    }
    setIsUpdating(null);
  };

  const handleUpdateCredits = async (userId: string, newTotal: number) => {
    const { error } = await supabase
      .from('user_profiles')
      .update({ credits_total: newTotal })
      .eq('id', userId);
    if (!error) {
      setUsers(users.map(u => u.id === userId ? { ...u, credits_total: newTotal } : u));
    }
  };

  return (
    <div className="p-8 max-w-7xl mx-auto space-y-8 animate-in fade-in duration-500">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-5">
          <div className="w-16 h-16 bg-slate-900 rounded-3xl flex items-center justify-center text-white shadow-2xl">
            <ShieldCheck size={32} />
          </div>
          <div>
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Admin Console</h2>
            <p className="text-sm text-slate-400 font-bold uppercase tracking-widest italic">Operations & Control Hub</p>
          </div>
        </div>

        <div className="flex bg-slate-100 p-1 rounded-2xl border border-slate-200">
          <button 
            onClick={() => setActiveTab('users')}
            className={`px-8 py-3 rounded-xl text-xs font-black uppercase transition-all flex items-center gap-2 ${activeTab === 'users' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <Users size={16} /> Users
          </button>
          <button 
            onClick={() => setActiveTab('plans')}
            className={`px-8 py-3 rounded-xl text-xs font-black uppercase transition-all flex items-center gap-2 ${activeTab === 'plans' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <Package size={16} /> Plans
          </button>
        </div>
      </div>

      {activeTab === 'users' ? (
        <div className="space-y-6">
          <div className="flex items-center gap-4">
             <div className="relative flex-1">
               <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
               <input 
                type="text" 
                placeholder="Search user ID or email..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-12 pr-4 py-4 bg-white border border-slate-200 rounded-3xl focus:ring-4 focus:ring-indigo-500/5 outline-none font-bold"
               />
             </div>
             <button onClick={fetchData} className="p-4 bg-white border border-slate-200 rounded-3xl text-slate-400 hover:text-indigo-600 transition-all">
               <RefreshCcw size={20} className={loading ? 'animate-spin' : ''} />
             </button>
          </div>

          <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
             <table className="w-full text-left">
                <thead>
                  <tr className="bg-slate-50 border-b border-slate-100 text-[10px] font-black uppercase text-slate-400 tracking-widest">
                    <th className="p-8">User Info</th>
                    <th className="p-8">Subscription</th>
                    <th className="p-8">Credits Status</th>
                    <th className="p-8">Last Login</th>
                    <th className="p-8 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {users.filter(u => u.id.includes(searchTerm)).map(user => (
                    <tr key={user.id} className={`group hover:bg-slate-50/50 transition-all ${user.is_suspended ? 'opacity-50 grayscale' : ''}`}>
                      <td className="p-8">
                        <div className="flex items-center gap-4">
                           <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-black ${user.role === 'admin' ? 'bg-amber-100 text-amber-600' : 'bg-indigo-100 text-indigo-600'}`}>
                             {user.id.slice(0, 2).toUpperCase()}
                           </div>
                           <div>
                              <p className="font-black text-slate-900 text-sm">{user.id.slice(0, 8)}...</p>
                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tight">{user.role}</p>
                           </div>
                        </div>
                      </td>
                      <td className="p-8">
                        <span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-black uppercase border border-indigo-100">
                          {user.plan_type}
                        </span>
                      </td>
                      <td className="p-8">
                        <div className="flex items-center gap-3">
                           <div>
                             <p className="text-xs font-black text-slate-900">{user.credits_total - user.credits_used} / {user.credits_total}</p>
                             <div className="w-24 h-1 bg-slate-100 rounded-full mt-1">
                               <div 
                                className="h-full bg-indigo-500 rounded-full" 
                                style={{ width: `${Math.min(100, (user.credits_used / user.credits_total) * 100)}%` }}
                               ></div>
                             </div>
                           </div>
                        </div>
                      </td>
                      <td className="p-8">
                        <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase">
                          <Clock size={14} className="text-slate-200" />
                          {user.last_login_at ? new Date(user.last_login_at).toLocaleDateString() : 'Never'}
                        </div>
                      </td>
                      <td className="p-8 text-right">
                        <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-all">
                           <button 
                            onClick={() => {
                              const extra = prompt("Add how many credits?", "500");
                              if (extra) handleUpdateCredits(user.id, user.credits_total + parseInt(extra));
                            }}
                            className="p-3 text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl"
                           >
                             <CreditCard size={18} />
                           </button>
                           <button 
                            onClick={() => handleToggleSuspension(user)}
                            className={`p-3 rounded-xl transition-all ${user.is_suspended ? 'text-emerald-600 bg-emerald-50' : 'text-slate-400 hover:text-red-600 hover:bg-red-50'}`}
                           >
                             {isUpdating === user.id ? <Loader2 className="animate-spin" size={18} /> : (user.is_suspended ? <CheckCircle size={18} /> : <Ban size={18} />)}
                           </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
             </table>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
           {plans.map(plan => (
             <div key={plan.id} className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm space-y-8 flex flex-col">
                <div className="flex justify-between items-start">
                   <div>
                     <h4 className="text-2xl font-black text-slate-900">{plan.name_zh}</h4>
                     <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">{plan.id}</p>
                   </div>
                   <div className="text-right">
                     <p className="text-3xl font-black text-slate-900">${plan.price_usd}</p>
                   </div>
                </div>

                <div className="space-y-4 flex-1">
                   <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 space-y-2">
                      <p className="text-[10px] font-black text-slate-400 uppercase">Included Credits</p>
                      <p className="text-xl font-black text-indigo-600">{plan.credits}</p>
                   </div>

                   <div className="space-y-2">
                      <p className="text-[10px] font-black text-slate-400 uppercase ml-1">Plan Features</p>
                      {plan.features_zh.map((f, i) => (
                        <div key={i} className="flex items-center gap-2 text-xs font-bold text-slate-500">
                          {/* Fix: Added missing Check icon import to fix line 213 error */}
                          <Check size={12} className="text-indigo-400" /> {f}
                        </div>
                      ))}
                   </div>
                </div>

                <button className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                   <Settings size={16} /> Edit Config
                </button>
             </div>
           ))}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './components/Dashboard';
import { ListingsManager } from './components/ListingsManager';
import { LandingPage } from './components/LandingPage';
import { ListingDetail } from './components/ListingDetail';
import { AuthPage } from './components/AuthPage';
import { TemplateManager } from './components/TemplateManager';
import { CategoryManager } from './components/CategoryManager';
import { PricingManager } from './components/PricingManager';
import { BillingCenter } from './components/BillingCenter';
import { AdminDashboard } from './components/AdminDashboard';
import { AppView, Listing, UILanguage, UserProfile } from './types';
import { supabase, isSupabaseConfigured } from './lib/supabaseClient';
import { Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.LANDING);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedListing, setSelectedListing] = useState<Listing | null>(null);
  const [session, setSession] = useState<any>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const [isInitialFetch, setIsInitialFetch] = useState(false);
  const [lang, setLang] = useState<UILanguage>('zh');
  const [listings, setListings] = useState<Listing[]>([]);

  useEffect(() => {
    const savedLang = localStorage.getItem('app_lang') as UILanguage;
    if (savedLang) setLang(savedLang);
  }, []);

  const fetchUserProfile = async (userId: string) => {
    if (!isSupabaseConfigured()) return;
    const { data } = await supabase
      .from('user_profiles')
      .select('*')
      .eq('id', userId)
      .single();

    if (data) {
      if (data.is_suspended) {
        alert("账户已被停用，请联系客服。");
        await supabase.auth.signOut();
        return;
      }
      setUserProfile(data);
      await supabase.from('user_profiles').update({ last_login_at: new Date().toISOString() }).eq('id', userId);
    }
  };

  useEffect(() => {
    if (!isSupabaseConfigured()) {
      setLoading(false);
      return;
    }

    supabase.auth.getSession().then(({ data: { session: currentSession } }) => {
      setSession(currentSession);
      if (currentSession) {
        setView(AppView.DASHBOARD);
        fetchListings(currentSession.user.id);
        fetchUserProfile(currentSession.user.id);
      }
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, newSession) => {
      setSession(newSession);
      if (event === 'SIGNED_IN' && newSession) {
        setView(AppView.DASHBOARD);
        fetchListings(newSession.user.id);
        fetchUserProfile(newSession.user.id);
      } else if (event === 'SIGNED_OUT') {
        setView(AppView.LANDING);
        setListings([]);
        setUserProfile(null);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchListings = useCallback(async (userId?: string) => {
    const uid = userId || session?.user?.id;
    if (!isSupabaseConfigured() || !uid) return;
    setIsInitialFetch(true);
    try {
      const { data } = await supabase.from('listings').select('*').eq('user_id', uid).order('created_at', { ascending: false });
      setListings(data || []);
    } catch (e) { console.error(e); } finally { setIsInitialFetch(false); }
  }, [session]);

  const handleTabChange = (tab: string) => {
    setActiveTab(tab);
    if (tab === 'admin') {
      setView(AppView.ADMIN);
    } else if (view === AppView.ADMIN || view === AppView.LISTING_DETAIL) {
      setView(AppView.DASHBOARD);
    }
  };

  const renderContent = () => {
    if (view === AppView.ADMIN && userProfile?.role === 'admin') {
      return <AdminDashboard uiLang={lang} />;
    }
    if (view === AppView.LISTING_DETAIL && selectedListing) {
      return <ListingDetail listing={selectedListing} onBack={() => { setView(AppView.DASHBOARD); fetchListings(); }} onUpdate={(u) => setListings(prev => prev.map(l => l.id === u.id ? u : l))} onNext={() => {}} uiLang={lang} />;
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard listings={listings} lang={lang} isSyncing={isInitialFetch} onRefresh={() => fetchListings()} userProfile={userProfile} onNavigate={handleTabChange} />;
      case 'listings': return <ListingsManager onSelectListing={(l) => { setSelectedListing(l); setView(AppView.LISTING_DETAIL); }} listings={listings} setListings={setListings} lang={lang} refreshListings={() => fetchListings()} />;
      case 'categories': return <CategoryManager uiLang={lang} />;
      case 'pricing': return <PricingManager uiLang={lang} />;
      case 'templates': return <TemplateManager uiLang={lang} />;
      case 'billing': return <BillingCenter uiLang={lang} />;
      default: return <Dashboard listings={listings} lang={lang} userProfile={userProfile} onNavigate={handleTabChange} />;
    }
  };

  if (loading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-white">
      <Loader2 className="animate-spin text-indigo-600" size={48} />
      <p className="mt-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Fueling AMZBot...</p>
    </div>
  );

  return (
    <div className="flex min-h-screen bg-slate-50">
      {view !== AppView.LANDING && view !== AppView.AUTH && (
        <Sidebar onLogout={() => supabase.auth.signOut()} onLogoClick={() => setView(AppView.LANDING)} activeTab={activeTab} setActiveTab={handleTabChange} lang={lang} userEmail={session?.user?.email} userProfile={userProfile} />
      )}
      <main className={`${view !== AppView.LANDING && view !== AppView.AUTH ? 'ml-64' : 'w-full'} flex-1 h-screen overflow-hidden`}>
        <div className="h-full overflow-y-auto custom-scrollbar">
          {view === AppView.LANDING ? <LandingPage onLogin={() => setView(AppView.AUTH)} onLogoClick={() => setView(AppView.LANDING)} uiLang={lang} onLanguageChange={(l) => setLang(l)} /> :
           view === AppView.AUTH ? <AuthPage onBack={() => setView(AppView.LANDING)} onLogoClick={() => setView(AppView.LANDING)} uiLang={lang} /> :
           renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { CheckCircle, TrendingUp, Package, Sparkles, Globe, Clock, Zap, RefreshCcw, Loader2, Layout, ShieldCheck, ArrowRight } from 'lucide-react';
import { Listing, UILanguage, UserProfile } from '../types';
import { useTranslation } from '../lib/i18n';
import { supabase, isSupabaseConfigured } from '../lib/supabaseClient';

interface DashboardProps {
  listings: Listing[];
  lang: UILanguage;
  isSyncing?: boolean;
  onRefresh?: () => void;
  userProfile?: UserProfile | null;
  onNavigate?: (tab: string) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ listings, lang, isSyncing, onRefresh, userProfile, onNavigate }) => {
  const t = useTranslation(lang);
  const [templateCount, setTemplateCount] = useState(0);

  useEffect(() => {
    const fetchTemplateCount = async () => {
      if (!isSupabaseConfigured()) return;
      const { count } = await supabase.from('templates').select('*', { count: 'exact', head: true });
      setTemplateCount(count || 0);
    };
    fetchTemplateCount();
  }, []);

  const stats = {
    total: listings.length,
    optimized: listings.filter(l => l.status === 'optimized').length,
    pending: listings.filter(l => l.status !== 'optimized').length,
    translated: listings.reduce((acc, curr) => acc + (curr.translations ? Object.keys(curr.translations).length : 0), 0)
  };

  return (
    <div className="p-8 max-w-7xl mx-auto space-y-8 animate-in fade-in duration-500">
      <div className="flex items-center justify-between">
        <div className="flex flex-col gap-2">
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">
            {lang === 'zh' ? '数据概览' : 'Overview'}
          </h2>
          <p className="text-slate-400 font-medium text-sm">Monitor your cross-border business performance.</p>
        </div>

        <div className="flex items-center gap-4">
          {userProfile?.role === 'admin' && (
            <button 
              onClick={() => onNavigate?.('admin')}
              className="flex items-center gap-2 px-5 py-2.5 bg-amber-500 text-white rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-amber-600 shadow-xl shadow-amber-200 transition-all active:scale-95"
            >
              <ShieldCheck size={16} />
              {lang === 'zh' ? '管理后台入口' : 'Admin Console'}
            </button>
          )}
          {onRefresh && (
            <button 
              onClick={onRefresh} 
              disabled={isSyncing}
              className={`flex items-center gap-2 px-5 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${
                isSyncing ? 'bg-slate-100 text-slate-400' : 'bg-white text-slate-600 hover:bg-slate-50 border border-slate-200 shadow-sm active:scale-95'
              }`}
            >
              {isSyncing ? <Loader2 size={16} className="animate-spin" /> : <RefreshCcw size={16} />}
              {isSyncing ? 'Syncing...' : 'Refresh Data'}
            </button>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title={t('totalListings')} value={stats.total} icon={<Package className="text-blue-500" />} />
        <StatCard title={t('optimized')} value={stats.optimized} icon={<Sparkles className="text-indigo-500" />} color="indigo" />

        <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col justify-between group hover:border-indigo-200 transition-all">
          <div className="flex justify-between items-start">
            <h3 className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{lang === 'zh' ? '当前剩余点数' : 'Credits Balance'}</h3>
            <div className="p-2 rounded-xl bg-amber-50 group-hover:scale-110 transition-transform"><Zap className="text-amber-500" size={18} /></div>
          </div>
          <p className="text-4xl font-black text-slate-900 mt-4 tracking-tighter">
            {(userProfile?.credits_total || 0) - (userProfile?.credits_used || 0)}
          </p>
        </div>

        <div className="bg-gradient-to-br from-indigo-600 to-blue-700 p-6 rounded-[2.5rem] shadow-xl text-white flex flex-col justify-between group hover:scale-[1.02] transition-transform">
          <h3 className="text-indigo-100 text-[10px] font-black uppercase tracking-widest">{lang === 'zh' ? '已维护模板' : 'Active Templates'}</h3>
          <div className="flex items-end justify-between mt-4">
            <p className="text-4xl font-black">{templateCount}</p>
            <Layout className="text-white/20" size={32} />
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm min-h-[500px] flex flex-col">
           <div className="flex items-center justify-between mb-8">
              <h3 className="font-black text-slate-900 flex items-center gap-2">
                 <TrendingUp size={20} className="text-emerald-500" /> Recent Activity
              </h3>
              {isSyncing && <div className="text-[10px] font-black text-indigo-500 uppercase animate-pulse">Syncing...</div>}
           </div>

           <div className="space-y-6 flex-1">
              {isSyncing && listings.length === 0 ? (
                <div className="space-y-4">
                  {[1, 2, 3, 4, 5].map(i => (
                    <div key={i} className="h-20 bg-slate-50 rounded-2xl animate-pulse"></div>
                  ))}
                </div>
              ) : listings.length === 0 ? (
                <div className="flex-1 flex flex-col items-center justify-center text-center py-20 opacity-20 space-y-4">
                  <Package size={64} />
                  <p className="font-black uppercase tracking-widest text-xs">No active listings in database</p>
                </div>
              ) : (
                listings.slice(0, 5).map(l => (
                  <div key={l.id} className="flex items-center gap-4 p-4 rounded-2xl hover:bg-slate-50 transition-all border border-transparent hover:border-slate-100">
                     <div className="w-12 h-12 bg-slate-100 rounded-xl overflow-hidden border border-slate-200">
                        <img src={l.cleaned?.main_image} className="w-full h-full object-contain" />
                     </div>
                     <div className="flex-1">
                        <p className="text-xs font-black text-slate-800 line-clamp-1">{l.cleaned?.title}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase mt-0.5">{l.asin} &bull; {l.status}</p>
                     </div>
                     <div className="text-[10px] font-black text-slate-300 flex items-center gap-1">
                        <Clock size={12} /> {new Date(l.created_at).toLocaleDateString()}
                     </div>
                  </div>
                ))
              )}
           </div>
        </div>

        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm flex flex-col gap-6">
           <div className="bg-slate-900 rounded-3xl p-6 text-white space-y-4">
              <h3 className="font-black uppercase text-xs tracking-widest text-slate-400">Account Summary</h3>
              <div className="flex items-center justify-between">
                <span className="text-xs font-bold text-slate-400">Current Plan</span>
                <span className="text-xs font-black text-indigo-400">{userProfile?.plan_type || 'Free'}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-xs font-bold text-slate-400">Credit Usage</span>
                <span className="text-xs font-black">{userProfile?.credits_used || 0} / {userProfile?.credits_total || 0}</span>
              </div>
              <button 
                onClick={() => onNavigate?.('billing')}
                className="w-full py-3 bg-white text-slate-900 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-50 transition-all"
              >
                Top up / Upgrade
              </button>
           </div>

           <h3 className="font-black text-slate-900 uppercase text-xs tracking-widest mt-2">Efficiency Tips</h3>
           <div className="space-y-4">
              <Tip icon={<Zap className="text-amber-500" />} text="Use AI Optimization for 30% higher conversion rates." />
              <Tip icon={<Globe className="text-blue-500" />} text="Expand to DE and FR markets for 2x reach." />
              <Tip icon={<CheckCircle className="text-green-500" />} text="Keep your EAN codes valid for Amazon entry." />
           </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon, color = "blue" }: any) => (
  <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col justify-between group hover:border-indigo-200 transition-all">
    <div className="flex justify-between items-start">
      <h3 className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{title}</h3>
      <div className={`p-2 rounded-xl bg-${color}-50 group-hover:scale-110 transition-transform`}>{icon}</div>
    </div>
    <p className="text-4xl font-black text-slate-900 mt-4 tracking-tighter">{value}</p>
  </div>
);

const Tip = ({ icon, text }: any) => (
  <div className="flex gap-3 p-4 bg-slate-50 rounded-2xl border border-slate-100">
    <div className="mt-0.5">{icon}</div>
    <p className="text-[11px] font-bold text-slate-600 leading-relaxed">{text}</p>
  </div>
);

import React, { useState, useEffect } from 'react';
import { 
  CreditCard, Check, Zap, Crown, ShieldCheck, 
  Loader2, Wallet, Star, ShieldAlert, BadgeCheck
} from 'lucide-react';
import { UILanguage, UserProfile } from '../types';
import { supabase, isSupabaseConfigured } from '../lib/supabaseClient';

interface BillingCenterProps {
  uiLang: UILanguage;
}

const PLANS = [
  {
    id: 'Free',
    name: 'Starter',
    name_zh: '初创版',
    price_usd: 0,
    price_cny: 0,
    credits: 30,
    features: ['10 AI Optimizations / mo', 'Basic Collect Tool', 'Community Support'],
    features_zh: ['每月 10 次 AI 优化', '基础采集工具', '社区支持'],
    color: 'slate'
  },
  {
    id: 'Pro',
    name: 'Growth',
    name_zh: '专业版',
    price_usd: 29,
    price_cny: 199,
    credits: 2000,
    features: ['Unlimited Product Collect', '2,000 AI Credits', 'Visual 1688 Search', 'Priority Support'],
    features_zh: ['无限量产品采集', '2,000 AI 点数', '以图搜搜 1688', '优先技术支持'],
    color: 'blue'
  },
  {
    id: 'Elite',
    name: 'Elite',
    name_zh: '旗舰版',
    price_usd: 79,
    price_cny: 549,
    credits: 10000,
    features: ['5 User Collaboration', '10,000 AI Credits', 'Custom Template Export', 'Full API Access'],
    features_zh: ['5 用户协作', '10,000 AI 点数', '自定义刊登模板导出', '全接口 API 访问'],
    color: 'indigo'
  }
];

export const BillingCenter: React.FC<BillingCenterProps> = ({ uiLang }) => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const [processingId, setProcessingId] = useState<string | null>(null);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    if (!isSupabaseConfigured()) return;
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) { setLoading(false); return; }

      const { data: profileData } = await supabase
        .from('user_profiles')
        .select('*')
        .eq('id', session.user.id)
        .single();

      if (profileData) setProfile(profileData);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handlePay = async (plan: typeof PLANS[0], method: 'alipay' | 'paypal') => {
    if (plan.id === 'Free' || plan.id === profile?.plan_type) return;

    setProcessingId(plan.id);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) throw new Error(uiLang === 'zh' ? "请先登录" : "Please sign in.");

      const { data: order, error: orderError } = await supabase
        .from('payment_orders')
        .insert([{
          user_id: session.user.id,
          amount: uiLang === 'zh' ? plan.price_cny : plan.price_usd,
          plan_id: plan.id,
          provider: method,
          currency: uiLang === 'zh' ? 'CNY' : 'USD',
          status: 'pending'
        }])
        .select().single();

      if (orderError) throw orderError;

      const { data, error: invokeError } = await supabase.functions.invoke('create-payment', {
        body: { 
          orderId: order.id, 
          amount: uiLang === 'zh' ? plan.price_cny : plan.price_usd, 
          planName: plan.name,
          method: method 
        }
      });

      if (invokeError) throw invokeError;
      if (data?.url) window.location.href = data.url;
    } catch (err: any) {
      alert(`Payment Error: ${err.message}`);
    } finally {
      setProcessingId(null);
    }
  };

  if (loading) return (
    <div className="flex items-center justify-center p-20"><Loader2 className="animate-spin text-indigo-600" size={32} /></div>
  );

  return (
    <div className="p-8 max-w-7xl mx-auto space-y-12 animate-in fade-in duration-500 pb-24">
      <div className="flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="flex items-center gap-5">
          <div className="w-16 h-16 bg-slate-900 rounded-[1.5rem] flex items-center justify-center text-white shadow-2xl">
            <CreditCard size={32} />
          </div>
          <div>
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">
              {uiLang === 'zh' ? '订阅中心' : 'Billing Center'}
            </h2>
            <p className="text-sm text-slate-400 font-bold uppercase tracking-widest italic">Scale your cross-border business with AI</p>
          </div>
        </div>

        <div className="bg-white px-8 py-5 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-8">
           <div className="text-right">
             <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{uiLang === 'zh' ? '我的剩余点数' : 'Credits Remaining'}</p>
             <p className="text-3xl font-black text-indigo-600">{(profile?.credits_total || 0) - (profile?.credits_used || 0)}</p>
           </div>
           <div className="w-px h-12 bg-slate-100"></div>
           <div>
             <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{uiLang === 'zh' ? '当前方案' : 'Current Plan'}</p>
             <span className="inline-flex items-center gap-1.5 px-4 py-1.5 bg-slate-900 text-white rounded-full text-[10px] font-black uppercase tracking-widest mt-1">
               <Crown size={12} className="text-amber-400" />
               {profile?.plan_type || 'Free'}
             </span>
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        {PLANS.map(plan => {
          const isCurrent = (profile?.plan_type || 'Free') === plan.id;
          const currencySym = uiLang === 'zh' ? '¥' : '$';
          const price = uiLang === 'zh' ? plan.price_cny : plan.price_usd;
          const features = uiLang === 'zh' ? plan.features_zh : plan.features;
          const isProcessing = processingId === plan.id;

          return (
            <div 
              key={plan.id} 
              className={`bg-white rounded-[3rem] border-4 overflow-hidden flex flex-col group transition-all relative ${
                isCurrent 
                  ? 'border-indigo-600 shadow-2xl scale-105 z-10' 
                  : 'border-slate-100 hover:border-slate-200'
              }`}
            >
              {isCurrent && (
                <div className="absolute top-6 right-6 bg-indigo-600 text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 shadow-lg z-20">
                  <BadgeCheck size={14} /> {uiLang === 'zh' ? '当前订阅中' : 'Active'}
                </div>
              )}

              <div className="p-10 space-y-8 flex-1">
                 <div>
                    <h3 className="text-2xl font-black text-slate-900">{uiLang === 'zh' ? plan.name_zh : plan.name}</h3>
                    <div className="flex items-baseline gap-1 mt-6">
                      <span className="text-5xl font-black text-slate-900 tracking-tighter">{currencySym}{price}</span>
                      <span className="text-sm text-slate-400 font-bold uppercase tracking-widest">/ mo</span>
                    </div>
                    <p className="text-[11px] font-black text-indigo-500 uppercase tracking-[0.2em] mt-6 bg-indigo-50 w-fit px-3 py-1 rounded-lg">
                      {plan.credits.toLocaleString()} {uiLang === 'zh' ? 'AI 积分/月' : 'Credits/mo'}
                    </p>
                 </div>

                 <div className="space-y-4">
                    {features.map((f, i) => (
                      <div key={i} className="flex items-center gap-3">
                        <div className={`w-5 h-5 rounded-full flex items-center justify-center ${isCurrent ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                          <Check size={12} strokeWidth={3} />
                        </div>
                        <span className="text-sm font-bold text-slate-600">{f}</span>
                      </div>
                    ))}
                 </div>
              </div>

              <div className="p-8 bg-slate-50 border-t border-slate-100">
                 {isCurrent ? (
                   <button disabled className="w-full py-5 bg-slate-200 text-slate-500 rounded-3xl font-black text-xs uppercase tracking-[0.2em] shadow-inner">
                     {uiLang === 'zh' ? '您当前的选择' : 'Current Selection'}
                   </button>
                 ) : plan.id === 'Free' ? (
                   <button disabled className="w-full py-5 bg-white border border-slate-200 text-slate-300 rounded-3xl font-black text-xs uppercase tracking-[0.2em]">
                     {uiLang === 'zh' ? '免费永久' : 'Free Tier'}
                   </button>
                 ) : (
                   <div className="space-y-3">
                      {uiLang === 'zh' ? (
                        <button 
                          onClick={() => handlePay(plan, 'alipay')}
                          disabled={!!processingId}
                          className="w-full py-5 bg-blue-600 text-white rounded-3xl font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-3 shadow-xl hover:bg-blue-700 active:scale-95 transition-all disabled:opacity-50"
                        >
                          {isProcessing ? <Loader2 className="animate-spin" size={20} /> : <Wallet size={20} />}
                          支付宝支付升级
                        </button>
                      ) : (
                        <button 
                          onClick={() => handlePay(plan, 'paypal')}
                          disabled={!!processingId}
                          className="w-full py-5 bg-slate-900 text-white rounded-3xl font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-3 shadow-xl hover:bg-slate-800 active:scale-95 transition-all disabled:opacity-50"
                        >
                          {isProcessing ? <Loader2 className="animate-spin" size={20} /> : <img src="https://www.paypalobjects.com/webstatic/mktg/logo/pp_cc_mark_37x23.jpg" className="h-5" />}
                          PayPal Checkout
                        </button>
                      )}
                   </div>
                 )}
              </div>
            </div>
          );
        })}
      </div>

      <div className="p-10 bg-indigo-900 rounded-[3rem] text-white flex flex-col md:flex-row items-center gap-10 relative overflow-hidden group">
         <div className="absolute -right-10 -top-10 w-64 h-64 bg-indigo-500/20 blur-3xl rounded-full"></div>
         <div className="w-20 h-20 bg-white/10 rounded-3xl flex items-center justify-center text-indigo-400 border border-white/5"><Star size={40} /></div>
         <div className="flex-1 space-y-2">
            <h4 className="text-xl font-black tracking-tight">{uiLang === 'zh' ? '为什么升级专业版？' : 'Why Go Pro?'}</h4>
            <p className="text-sm text-indigo-200 font-medium leading-relaxed max-w-2xl">
              {uiLang === 'zh' ? '解锁 1688 深度搜货 API、无限制产品采集及 AI 实验室修图功能。专业版用户平均每日节省 4.5 小时的手动录入时间。' : 'Unlock full 1688 visual sourcing, unlimited scrapes, and AI Media Lab. Pro users save 4.5 hours on average daily.'}
            </p>
         </div>
         <button className="px-10 py-5 bg-white text-indigo-900 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-50 transition-all flex items-center gap-3">
           View Comparison <Star size={16} />
         </button>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Package, LogOut, LayoutDashboard, Settings, Layout, List, Tags, Coins, CreditCard, User, ChevronRight, Crown, Sparkles, Mail, ShieldCheck, RefreshCcw } from 'lucide-react';
import { UILanguage, UserProfile } from '../types';
import { useTranslation } from '../lib/i18n';
import { supabase } from '../lib/supabaseClient';

interface SidebarProps {
  onLogout: () => void;
  onLogoClick: () => void;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  lang: UILanguage;
  userEmail?: string;
  userProfile?: UserProfile | null;
}

export const Sidebar: React.FC<SidebarProps> = ({ onLogout, onLogoClick, activeTab, setActiveTab, lang, userEmail, userProfile }) => {
  const t = useTranslation(lang);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const profileRef = useRef<HTMLDivElement>(null);

  const userName = userEmail ? userEmail.split('@')[0] : 'User';
  const isAdmin = userProfile?.role === 'admin';

  const menuItems = [
    { id: 'dashboard', label: lang === 'zh' ? '概览' : 'Dashboard', icon: <LayoutDashboard size={20} /> },
    { id: 'listings', label: t('listings'), icon: <List size={20} /> },
    { id: 'categories', label: lang === 'zh' ? '分类管理' : 'Categories', icon: <Tags size={20} /> },
    { id: 'pricing', label: lang === 'zh' ? '定价中心' : 'Pricing Center', icon: <Coins size={20} /> },
    { id: 'templates', label: t('templates'), icon: <Layout size={20} /> },
  ];

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) {
        setIsProfileOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className="w-64 bg-slate-900 text-white h-screen flex flex-col fixed left-0 top-0 z-50 shadow-2xl">
      <div className="p-6 border-b border-slate-800 flex items-center justify-between">
        <button onClick={onLogoClick} className="text-xl font-black flex items-center gap-2 hover:opacity-80 transition-opacity">
          <span className="bg-blue-600 px-2 py-0.5 rounded text-sm">ERP</span> AMZBot
        </button>
      </div>

      <nav className="flex-1 p-4 space-y-2 overflow-y-auto custom-scrollbar">
        <p className="px-4 py-2 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">Main Menu</p>
        {menuItems.map((item) => (
          <button
            key={item.id}
            onClick={() => setActiveTab(item.id)}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
              activeTab === item.id 
                ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50 scale-105' 
                : 'text-slate-400 hover:bg-slate-800 hover:text-white'
            }`}
          >
            {item.icon}
            <span className="font-bold text-sm">{item.label}</span>
          </button>
        ))}

        {isAdmin && (
          <div className="pt-6 mt-6 border-t border-slate-800">
            <p className="px-4 py-2 text-[10px] font-black text-amber-500 uppercase tracking-[0.2em]">Management</p>
            <button
              onClick={() => setActiveTab('admin')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                activeTab === 'admin' 
                  ? 'bg-amber-500 text-white shadow-lg shadow-amber-900/50 scale-105' 
