  const [view, setView] = useState<AppView>(AppView.LANDING);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [session, setSession] = useState<any>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [org, setOrg] = useState<Organization | null>(null);
  const [loading, setLoading] = useState(true);
  const [lang, setLang] = useState<UILanguage>('zh');
  const [listings, setListings] = useState<Listing[]>([]);

  const fetchIdentity = useCallback(async (userId: string) => {
    if (!isSupabaseConfigured()) return;

    // 1. 获取用户档案
    let { data: profile } = await supabase.from('user_profiles').select('*').eq('id', userId).maybeSingle();

    if (!profile) {
      // 如果没档案，创建租户管理员档案及新组织
      const newOrgId = crypto.randomUUID();
      const { data: newOrg } = await supabase.from('organizations').insert([{
        id: newOrgId,
        name: `Org_${userId.slice(0, 5)}`,
        owner_id: userId,
        credits_total: 100
      }]).select().single();

      const { data: newProfile } = await supabase.from('user_profiles').insert([{
        id: userId,
        org_id: newOrgId,
        role: 'tenant_admin'
      }]).select().single();

      profile = newProfile;
      setOrg(newOrg);
    } else {
      // 获取组织信息
      if (profile.org_id) {
        const { data: orgData } = await supabase.from('organizations').select('*').eq('id', profile.org_id).maybeSingle();
        setOrg(orgData);
      }
    }

    setUserProfile(profile);
    if (profile?.is_suspended) {
      await supabase.auth.signOut();
      return;
    }
    setView(AppView.DASHBOARD);
  }, []);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session: cur } }) => {
      setSession(cur);
      if (cur) fetchIdentity(cur.user.id);
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, newSession) => {
      setSession(newSession);
      if (newSession) fetchIdentity(newSession.user.id);
      else { setView(AppView.LANDING); setUserProfile(null); setOrg(null); }
    });
    return () => subscription.unsubscribe();
  }, [fetchIdentity]);

  const handleTabChange = (tab: string) => {
    setActiveTab(tab);
    if (tab === 'admin') setView(AppView.ADMIN);
    else if (tab === 'system') setView(AppView.SYSTEM_MGMT);
    else setView(AppView.DASHBOARD);
  };

  const renderContent = () => {
    if (view === AppView.ADMIN && userProfile?.role === 'super_admin') return <AdminDashboard uiLang={lang} />;
    if (view === AppView.SYSTEM_MGMT && userProfile?.role === 'tenant_admin') return <SystemManagement uiLang={lang} orgId={userProfile.org_id!} />;

    switch (activeTab) {
      case 'dashboard': return <Dashboard listings={listings} lang={lang} userProfile={userProfile} org={org} />;
      case 'listings': return <ListingsManager onSelectListing={() => {}} listings={listings} setListings={setListings} lang={lang} refreshListings={() => {}} />;
      case 'billing': return <BillingCenter uiLang={lang} org={org} />;
      default: return <Dashboard listings={listings} lang={lang} userProfile={userProfile} org={org} />;
    }
  };

  if (loading) return <div className="h-screen flex items-center justify-center"><Loader2 className="animate-spin" /></div>;

  return (
    <div className="flex min-h-screen bg-slate-50">
      {userProfile && (
        <Sidebar 
          activeTab={activeTab} 
          setActiveTab={handleTabChange} 
          lang={lang} 
          userProfile={userProfile}
          onLogout={() => supabase.auth.signOut()}
        />
      )}
      <main className={`${userProfile ? 'ml-64' : 'w-full'} flex-1`}>
        {view === AppView.LANDING ? <LandingPage onLogin={() => setView(AppView.AUTH)} uiLang={lang} onLanguageChange={setLang} onLogoClick={() => {}} /> :
         view === AppView.AUTH ? <AuthPage onBack={() => setView(AppView.LANDING)} uiLang={lang} onLogoClick={() => {}} /> :
         renderContent()}
      </main>
    </div>
  );
};

