import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './components/Dashboard';
import { ListingsManager } from './components/ListingsManager';
import { LandingPage } from './components/LandingPage';
import { AuthPage } from './components/AuthPage.tsx';
import { TemplateManager } from './components/TemplateManager';
import { CategoryManager } from './components/CategoryManager';
import { PricingManager } from './components/PricingManager';
import { BillingCenter } from './components/BillingCenter';
import { AdminDashboard } from './components/AdminDashboard';
import { SystemManagement } from './components/SystemManagement';
import { AppView, Listing, UILanguage, UserProfile, Organization } from './types';
import { supabase, isSupabaseConfigured } from './lib/supabaseClient';
import { Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.LANDING);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [session, setSession] = useState<any>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [org, setOrg] = useState<Organization | null>(null);
  const [loading, setLoading] = useState(true);
  const [lang, setLang] = useState<UILanguage>('zh');
  const [listings, setListings] = useState<Listing[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);

  const viewRef = useRef(view);
  useEffect(() => { viewRef.current = view; }, [view]);

  const fetchListings = useCallback(async (orgId: string) => {
    if (!isSupabaseConfigured()) return;
    setIsSyncing(true);
    try {
      const { data } = await supabase.from('listings').select('*').eq('org_id', orgId).order('created_at', { ascending: false });
      if (data) setListings(data);
    } catch (e) {
      console.error("Fetch listings error:", e);
    } finally {
      setIsSyncing(false);
    }
  }, []);

  const fetchIdentity = useCallback(async (userId: string, currentSession: any) => {
    if (!isSupabaseConfigured()) {
      setLoading(false);
      return;
    }

    try {
      let { data: profile, error: profileErr } = await supabase
        .from('user_profiles')
        .select('*')
        .eq('id', userId)
        .maybeSingle();

      if (profileErr) throw profileErr;

      if (!profile) {
        const newOrgId = crypto.randomUUID();
        await supabase.from('organizations').insert([{
          id: newOrgId,
          name: `Org_${userId.slice(0, 5)}`,
          owner_id: userId,
          plan_type: 'Free',
          credits_total: 100,
          credits_used: 0
        }]);

        const { data: newProfile } = await supabase.from('user_profiles').insert([{
          id: userId,
          org_id: newOrgId,
          role: 'tenant_admin',
          email: currentSession?.user?.email,
          plan_type: 'Free',
          credits_total: 100,
          credits_used: 0
        }]).select().single();

        await supabase.from('listings').update({ org_id: newOrgId }).eq('user_id', userId).is('org_id', null);
        profile = newProfile;
      }

      if (profile?.org_id) {
        const { data: orgData } = await supabase.from('organizations').select('*').eq('id', profile.org_id).maybeSingle();
        setOrg(orgData);
        await fetchListings(profile.org_id);
      }

      setUserProfile(profile);

      if (viewRef.current === AppView.LANDING || viewRef.current === AppView.AUTH) {
        setView(AppView.DASHBOARD);
        setActiveTab('dashboard');
      }
    } catch (err) {
      console.error("Identity error:", err);
      setView(AppView.AUTH);
    } finally {
      setLoading(false);
    }
  }, [fetchListings]);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session: cur } }) => {
      setSession(cur);
      if (cur) fetchIdentity(cur.user.id, cur);
      else setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, newSession) => {
      // 深度修复退出逻辑：当事件为 SIGNED_OUT 或新会话不存在时，彻底重置
      if (!newSession) {
        setSession(null);
        setUserProfile(null);
        setOrg(null);
        setListings([]);
        setView(AppView.LANDING);
        setLoading(false);
        return;
      }

      if (newSession?.user?.id === session?.user?.id && event !== 'SIGNED_IN') return;

      setSession(newSession);
      if (newSession) {
        setLoading(true);
        fetchIdentity(newSession.user.id, newSession);
      }
    });

    return () => subscription.unsubscribe();
  }, [fetchIdentity, session?.user?.id]);

  const handleTabChange = (tab: string) => {
    setActiveTab(tab);
    switch(tab) {
      case 'dashboard': setView(AppView.DASHBOARD); break;
      case 'listings': setView(AppView.DASHBOARD); break;
      case 'templates': setView(AppView.TEMPLATES); break;
      case 'categories': setView(AppView.CATEGORIES); break;
      case 'pricing': setView(AppView.PRICING); break;
      case 'billing': setView(AppView.BILLING); break;
      case 'admin': setView(AppView.ADMIN); break;
      case 'system': setView(AppView.SYSTEM_MGMT); break;
      default: setView(AppView.DASHBOARD);
    }
  };

  const renderContent = () => {
    if (view === AppView.ADMIN && (userProfile?.role === 'super_admin' || userProfile?.role === 'admin')) {
      return <AdminDashboard uiLang={lang} />;
    }
    if (view === AppView.SYSTEM_MGMT) {
      return <SystemManagement uiLang={lang} orgId={userProfile?.org_id || ''} orgData={org} onOrgUpdate={setOrg} />;
    }

    switch(view) {
      case AppView.TEMPLATES: return <TemplateManager uiLang={lang} />;
      case AppView.CATEGORIES: return <CategoryManager uiLang={lang} />;
      case AppView.PRICING: return <PricingManager uiLang={lang} />;
      case AppView.BILLING: return <BillingCenter uiLang={lang} />;
      default:
        if (activeTab === 'listings') {
          return <ListingsManager onSelectListing={() => {}} listings={listings} setListings={setListings} lang={lang} refreshListings={() => userProfile?.org_id && fetchListings(userProfile.org_id)} />;
        }
        return <Dashboard listings={listings} lang={lang} userProfile={userProfile} onNavigate={handleTabChange} isSyncing={isSyncing} onRefresh={() => userProfile?.org_id && fetchListings(userProfile.org_id)} />;
    }
  };

  if (loading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-white space-y-6">
        <div className="relative">
          <div className="w-16 h-16 border-4 border-indigo-100 rounded-full animate-pulse"></div>
          <Loader2 className="absolute inset-0 m-auto animate-spin text-indigo-600" size={32} />
        </div>
        <div className="flex flex-col items-center gap-1">
           <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] animate-pulse">Authenticating Session</p>
           <p className="text-[8px] font-bold text-slate-300 uppercase italic">AMZBot Core Engine</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-slate-50">
      {userProfile && session && (
        <Sidebar activeTab={activeTab} setActiveTab={handleTabChange} lang={lang} userProfile={userProfile} session={session} onLogout={() => supabase.auth.signOut()} onLogoClick={() => setView(AppView.LANDING)} />
      )}
      <main className={`${userProfile ? 'ml-64' : 'w-full'} flex-1 h-screen overflow-hidden relative`}>
        <div className="h-full overflow-y-auto custom-scrollbar">
          {view === AppView.LANDING ? <LandingPage onLogin={() => setView(AppView.AUTH)} uiLang={lang} onLanguageChange={setLang} onLogoClick={() => setView(AppView.LANDING)} /> :
           view === AppView.AUTH ? <AuthPage onBack={() => setView(AppView.LANDING)} uiLang={lang} onLogoClick={() => setView(AppView.LANDING)} /> :
           renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  Users, Shield, Building, Plus, Trash2, Mail, Edit3, Loader2, 
  Check, X, Save, ShieldCheck, MapPin, UserCheck, Phone, 
  Settings, Key, RefreshCw, Power
} from 'lucide-react';
import { UILanguage, Organization, UserProfile, Role, RolePermission } from '../types';
import { supabase } from '../lib/supabaseClient';
import { useTranslation } from '../lib/i18n';

interface SystemManagementProps {
  uiLang: UILanguage;
  orgId: string;
  orgData: Organization | null;
  onOrgUpdate: (org: Organization) => void;
}

const MENU_OPTIONS = [
  { id: 'dashboard', label: 'dashboard' },
  { id: 'listings', label: 'listings' },
  { id: 'categories', label: 'categories' },
  { id: 'pricing', label: 'pricing' },
  { id: 'templates', label: 'templateManager' },
  { id: 'system', label: 'systemMgmt' }
];

export const SystemManagement: React.FC<SystemManagementProps> = ({ uiLang, orgId, orgData, onOrgUpdate }) => {
  const t = useTranslation(uiLang);
  const [activeTab, setActiveTab] = useState<'org' | 'roles' | 'users'>('users');
  const [loading, setLoading] = useState(false);
  const [members, setMembers] = useState<UserProfile[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);

  const [showMemberModal, setShowMemberModal] = useState(false);
  const [showRoleModal, setShowRoleModal] = useState(false);
  const [editingRole, setEditingRole] = useState<Role | null>(null);
  const [editingMember, setEditingMember] = useState<UserProfile | null>(null);

  const [orgForm, setOrgForm] = useState({
    name: orgData?.name || '',
    address: orgData?.address || '',
    contact_name: orgData?.contact_name || '',
    contact_phone: orgData?.contact_phone || ''
  });

  useEffect(() => {
    if (activeTab === 'users') fetchMembers();
    if (activeTab === 'roles') fetchRoles();
  }, [activeTab, orgId]);

  const fetchMembers = async () => {
    setLoading(true);
    const { data } = await supabase.from('user_profiles').select('*').eq('org_id', orgId);
    setMembers(data || []);
    setLoading(false);
  };

  const fetchRoles = async () => {
    setLoading(true);
    const { data } = await supabase.from('roles').select('*').eq('org_id', orgId);
    setRoles(data || []);
    setLoading(false);
  };

  const handleSaveOrg = async () => {
    setLoading(true);
    const { error } = await supabase
      .from('organizations')
      .update(orgForm)
      .eq('id', orgId);
    if (!error) {
      onOrgUpdate({ ...orgData!, ...orgForm });
      alert(t('saveSuccess'));
    }
    setLoading(false);
  };

  const handleSaveMember = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingMember) {
      setLoading(true);
      await supabase.from('user_profiles').update({ role: editingMember.role }).eq('id', editingMember.id);
      fetchMembers();
      setShowMemberModal(false);
      setLoading(false);
    }
  };

  const handleToggleStatus = async (user: UserProfile) => {
    setLoading(true);
    const newStatus = !user.is_suspended;
    const { error } = await supabase
      .from('user_profiles')
      .update({ is_suspended: newStatus })
      .eq('id', user.id);

    if (!error) {
      setMembers(members.map(m => m.id === user.id ? { ...m, is_suspended: newStatus } : m));
    }
    setLoading(false);
  };

  const handleResetPassword = async (userId: string) => {
    if (!window.confirm(t('resetWarning'))) return;
    setLoading(true);
    // 注意：客户端 Supabase 不支持直接重置其他用户的密码。此处为 UI 模拟。
    // 在真实生产中需调用 Supabase Edge Functions。
    setTimeout(() => {
      alert(uiLang === 'zh' ? "密码已重置为 000000（模拟成功）。" : "Password reset to 000000 (Simulated).");
      setLoading(false);
    }, 800);
  };

  const handleSaveRole = async () => {
    if (!editingRole) return;
    setLoading(true);
    if (editingRole.id) {
      await supabase.from('roles').update(editingRole).eq('id', editingRole.id);
    } else {
      await supabase.from('roles').insert([{ ...editingRole, id: crypto.randomUUID(), org_id: orgId }]);
    }
    fetchRoles();
    setShowRoleModal(false);
    setLoading(false);
  };

  const updateRolePermission = (menuId: string, action: keyof RolePermission, value: boolean) => {
    if (!editingRole) return;
    const newPerms = [...(editingRole.permissions || [])];
    let perm = newPerms.find(p => p.menu_id === menuId);
    if (!perm) {
      perm = { menu_id: menuId, can_create: false, can_read: true, can_update: false, can_delete: false };
      newPerms.push(perm);
    }
    (perm as any)[action] = value;
    setEditingRole({ ...editingRole, permissions: newPerms });
  };

  return (
    <div className="p-8 max-w-7xl mx-auto space-y-8 animate-in fade-in pb-24">
      <div className="flex flex-col md:flex-row items-center justify-between gap-6">
        <div className="flex items-center gap-5">
          <div className="w-16 h-16 bg-slate-900 rounded-[1.5rem] flex items-center justify-center text-white shadow-2xl">
            <Settings size={32} />
          </div>
          <div>
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">{t('systemMgmt')}</h2>
            <p className="text-sm text-slate-400 font-bold uppercase tracking-widest italic">Global Access Control</p>
          </div>
        </div>
        <div className="flex bg-slate-100 p-1.5 rounded-2xl border border-slate-200">
          <TabButton active={activeTab === 'users'} onClick={() => setActiveTab('users')} icon={<Users size={16}/>} label={t('userMgmt')} />
          <TabButton active={activeTab === 'roles'} onClick={() => setActiveTab('roles')} icon={<Shield size={16}/>} label={t('roleMgmt')} />
          <TabButton active={activeTab === 'org'} onClick={() => setActiveTab('org')} icon={<Building size={16}/>} label={t('orgMgmt')} />
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm min-h-[500px] flex flex-col relative overflow-hidden">
        {loading && (
          <div className="absolute inset-0 bg-white/60 backdrop-blur-[2px] z-50 flex items-center justify-center">
             <Loader2 size={40} className="animate-spin text-indigo-600" />
          </div>
        )}

        {activeTab === 'users' && (
          <div className="p-10 space-y-8">
            <div className="flex justify-between items-center">
               <h3 className="font-black text-slate-800 flex items-center gap-2 uppercase tracking-tight text-sm">
                 <Users className="text-indigo-600" size={18} /> {t('userMgmt')}
               </h3>
               <button onClick={() => { setEditingMember(null); setShowMemberModal(true); }} className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">
                 <Plus size={14}/> {t('addMember')}
               </button>
            </div>
            <div className="overflow-x-auto">
               <table className="w-full text-left">
                  <thead>
                    <tr className="border-b border-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                       <th className="pb-4 px-4">{t('email')}</th>
                       <th className="pb-4 px-4">{t('roleMgmt')}</th>
                       <th className="pb-4 px-4">{t('status')}</th>
                       <th className="pb-4 px-4 text-right">{t('actions')}</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {members.map(m => (
                      <tr key={m.id} className={`group hover:bg-slate-50/50 transition-all ${m.is_suspended ? 'opacity-60 grayscale' : ''}`}>
                        <td className="py-6 px-4">
                          <div className="flex items-center gap-4">
                            <div className="w-10 h-10 rounded-xl bg-slate-100 flex items-center justify-center text-slate-400">
                               <Mail size={16} />
                            </div>
                            <div>
                               <p className="text-sm font-black text-slate-800">{m.email || 'N/A'}</p>
                               <p className="text-[10px] text-slate-400 font-bold uppercase">{m.id.slice(0, 8)}</p>
                            </div>
                          </div>
                        </td>
                        <td className="py-6 px-4">
                           <span className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest ${m.role === 'tenant_admin' ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500'}`}>
                             {m.role}
                           </span>
                        </td>
                        <td className="py-6 px-4">
                           <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest flex items-center gap-1.5 w-fit ${m.is_suspended ? 'bg-red-50 text-red-500' : 'bg-green-50 text-green-600'}`}>
                             <div className={`w-1.5 h-1.5 rounded-full ${m.is_suspended ? 'bg-red-500' : 'bg-green-500'}`}></div>
                             {m.is_suspended ? t('disabled') : t('enabled')}
                           </span>
                        </td>
                        <td className="py-6 px-4 text-right">
                           <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-all">
                              <button 
                                onClick={() => handleResetPassword(m.id)}
                                title={t('resetPassword')} 
                                className="p-2.5 text-slate-400 hover:text-amber-600 hover:bg-amber-50 rounded-xl"
                              >
                                <RefreshCw size={16}/>
                              </button>
                              <button 
                                onClick={() => handleToggleStatus(m)}
                                title={m.is_suspended ? t('activate') : t('suspend')}
                                className={`p-2.5 rounded-xl ${m.is_suspended ? 'text-green-600 hover:bg-green-50' : 'text-slate-400 hover:text-red-500 hover:bg-red-50'}`}
                              >
                                <Power size={16}/>
                              </button>
                              <button onClick={() => { setEditingMember(m); setShowMemberModal(true); }} className="p-2.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl"><Edit3 size={16}/></button>
                           </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
               </table>
            </div>
          </div>
        )}

        {activeTab === 'roles' && (
          <div className="p-10 space-y-8">
            <div className="flex justify-between items-center">
               <h3 className="font-black text-slate-800 flex items-center gap-2 uppercase tracking-tight text-sm">
                 <Shield className="text-indigo-600" size={18} /> {t('roleMgmt')}
               </h3>
               <button onClick={() => { setEditingRole({ id: '', org_id: orgId, name: '', permissions: [], created_at: '' }); setShowRoleModal(true); }} className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl">
                 <Plus size={14}/> {t('addMember')}
               </button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
               {roles.map(role => (
                 <div key={role.id} className="p-8 border border-slate-100 rounded-[2.5rem] bg-slate-50/30 group hover:border-indigo-500 transition-all">
                    <div className="flex justify-between items-start mb-6">
                       <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-indigo-600 shadow-sm group-hover:bg-indigo-600 group-hover:text-white transition-all"><ShieldCheck size={24}/></div>
                       <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
                          <button onClick={() => { setEditingRole(role); setShowRoleModal(true); }} className="p-2 text-slate-400 hover:text-indigo-600"><Edit3 size={16}/></button>
                          <button className="p-2 text-slate-400 hover:text-red-500"><Trash2 size={16}/></button>
                       </div>
                    </div>
                    <h4 className="font-black text-slate-800">{role.name}</h4>
                    <p className="text-xs text-slate-400 mt-2 line-clamp-2">{role.description || 'Enterprise RBAC'}</p>
                 </div>
               ))}
            </div>
          </div>
        )}

        {activeTab === 'org' && (
          <div className="p-10 space-y-12">
            <div className="flex justify-between items-center">
               <h3 className="font-black text-slate-800 flex items-center gap-2 uppercase tracking-tight text-sm">
                 <Building className="text-indigo-600" size={18} /> {t('orgMgmt')}
               </h3>
               <button onClick={handleSaveOrg} className="px-10 py-3.5 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all">
                 <Save size={16}/> {t('save')}
               </button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
               <div className="space-y-6">
                  <OrgField label={t('orgName')} icon={<Building size={14}/>}>
                    <input value={orgForm.name} onChange={e => setOrgForm({...orgForm, name: e.target.value})} className="org-input" />
                  </OrgField>
                  <OrgField label={t('orgAddress')} icon={<MapPin size={14}/>}>
                    <textarea value={orgForm.address} onChange={e => setOrgForm({...orgForm, address: e.target.value})} className="org-input min-h-[100px]" />
                  </OrgField>
               </div>
               <div className="space-y-6">
                  <OrgField label={t('contactName')} icon={<UserCheck size={14}/>}>
                    <input value={orgForm.contact_name} onChange={e => setOrgForm({...orgForm, contact_name: e.target.value})} className="org-input" />
                  </OrgField>
                  <OrgField label={t('contactPhone')} icon={<Phone size={14}/>}>
                    <input value={orgForm.contact_phone} onChange={e => setOrgForm({...orgForm, contact_phone: e.target.value})} className="org-input" />
                  </OrgField>
               </div>
            </div>
          </div>
