                   <EditSection 
                    label="Product Description (HTML)" 
                    icon={<FileText size={14}/>} 
                    value={(currentContent as any).optimized_description || (currentContent as any).description || ''}
                    onChange={v => updateField('optimized_description', v)}
                    limit={2000}
                    isMono
                    className="min-h-[250px] text-xs leading-loose"
                   />

                   {/* Keywords */}
                   <EditSection 
                    label="Search Keywords" 
                    icon={<Hash size={14}/>} 
                    value={(currentContent as any).search_keywords || ''}
                    onChange={v => updateField('search_keywords', v)}
                    limit={250}
                    className="bg-amber-50/20 border-amber-100 focus:border-amber-400 text-sm font-bold"
                   />
                </div>
             </div>

             {/* Sourcing Center */}
             <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm p-10 space-y-8">
                <div className="flex items-center justify-between">
                   <div className="flex items-center gap-3">
                      <div className="w-12 h-12 bg-orange-500 rounded-2xl flex items-center justify-center text-white shadow-xl"><Link2 size={24} /></div>
                      <div>
                        <h3 className="text-xl font-black text-slate-900 tracking-tight">Supply Chain Discovery</h3>
                        <p className="text-xs text-slate-400 font-bold">Manage wholesale sources and manufacturer benchmarks.</p>
                      </div>
                   </div>
                   <div className="flex gap-3">
                      <button onClick={() => setShowSourcingModal(true)} className="flex items-center gap-2 px-6 py-2.5 bg-orange-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-orange-700 transition-all"><Search size={14} /> AI Visual Search</button>
                      <button onClick={() => setShowSourcingForm({show: true, data: null})} className="flex items-center gap-2 px-6 py-2.5 bg-white border border-slate-200 text-slate-600 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-50 transition-all"><Plus size={14} /> Manual Record</button>
                   </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                   {(localListing.sourcing_data || []).map((s, idx) => (
                     <div key={idx} className="group bg-slate-50 border border-slate-100 p-5 rounded-3xl flex items-center gap-5 relative hover:bg-white hover:shadow-2xl hover:border-orange-200 transition-all">
                        <div className="w-16 h-16 bg-white rounded-xl overflow-hidden border border-slate-200 shrink-0">
                           <img src={s.image} className="w-full h-full object-cover" />
                        </div>
                        <div className="flex-1 overflow-hidden">
                           <p className="text-xs font-black text-slate-900 truncate">{s.title}</p>
                           <p className="text-orange-600 font-black text-lg mt-0.5">{s.price}</p>
                           <div className="flex items-center gap-3 mt-2">
                              <a href={s.url} target="_blank" className="inline-flex items-center gap-1.5 text-[9px] font-black text-slate-400 hover:text-blue-600 uppercase tracking-widest transition-colors">Supplier <ExternalLink size={10} /></a>
                              <button onClick={() => setShowSourcingForm({show: true, data: s})} className="text-[9px] font-black text-slate-400 hover:text-indigo-600 uppercase tracking-widest transition-colors">Edit</button>
                           </div>
                        </div>
                        <button onClick={() => { 
                          const next = { ...localListing, sourcing_data: (localListing.sourcing_data || []).filter((_, i) => i !== idx) }; 
                          setLocalListing(next); syncToSupabase(next); 
                        }} className="absolute top-4 right-4 p-1.5 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={14} /></button>
                     </div>
                   ))}
                   {(localListing.sourcing_data || []).length === 0 && (
                     <div className="col-span-2 py-16 bg-slate-50 border-2 border-dashed border-slate-100 rounded-[2.5rem] flex flex-col items-center justify-center opacity-30"><Link2 size={32} className="mb-3" /><p className="text-[10px] font-black uppercase tracking-widest">No sourcing data attached</p></div>
                   )}
                </div>
             </div>
          </div>
        </div>
      </div>

      {showSourcingForm.show && (
        <SourcingFormModal 
          initialData={showSourcingForm.data} 
          onClose={() => setShowSourcingForm({show: false, data: null})} 
          onSave={(res) => {
            const nextData = [...(localListing.sourcing_data || [])];
            const existingIdx = nextData.findIndex(s => s.id === res.id);
            if (existingIdx >= 0) nextData[existingIdx] = res;
            else nextData.push(res);
            const next = { ...localListing, sourcing_data: nextData };
            setLocalListing(next); syncToSupabase(next); setShowSourcingForm({show: false, data: null});
          }} 
        />
      )}

      {showSourcingModal && (
        <SourcingModal 
          productImage={previewImage} 
          onClose={() => setShowSourcingModal(false)} 
          onAddLink={(res) => {
            const next = { ...localListing, sourcing_data: [...(localListing.sourcing_data || []), res] };
            setLocalListing(next); syncToSupabase(next); setShowSourcingModal(false);
          }}
        />
      )}

      {showImageEditor && <ImageEditor imageUrl={previewImage} onClose={() => setShowImageEditor(false)} onSave={(url) => { updateField('main_image', url); setPreviewImage(url); setShowImageEditor(false); }} />}
    </div>
  );
};

const EngineBtn = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${active ? 'bg-white shadow-md text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}>
    {icon} {label}
  </button>
);

const EditSection = ({ label, icon, value, onChange, limit, className = "", isMono = false }: any) => (
  <div className="space-y-3 group">
    <div className="flex justify-between items-center px-1">
      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">{icon} {label}</label>
      <div className={`flex items-center gap-1.5 px-2 py-0.5 rounded-full text-[9px] font-black ${value.length > limit ? 'bg-red-50 text-red-500 animate-pulse' : 'text-slate-300 uppercase'}`}>
        {value.length > limit && <AlertTriangle size={10} />} {value.length} / {limit}
      </div>
    </div>
    <textarea 
      value={value} 
      onChange={(e) => onChange(e.target.value)}
      className={`w-full p-6 bg-slate-50 border rounded-[2rem] outline-none transition-all focus:bg-white ${isMono ? 'font-mono' : 'font-bold'} ${value.length > limit ? 'border-red-500 ring-4 ring-red-50' : 'border-slate-200 focus:border-indigo-500 focus:ring-8 focus:ring-indigo-500/5'} ${className}`} 
    />
  </div>
);

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  X, Eraser, Scissors, PaintBucket, Crop, Save, Undo, 
  Wand2, Loader2, Download, MousePointer2, Maximize, 
  Type, Square, Circle, Minus, Move, Palette, Trash2,
  ZoomIn, ZoomOut, RotateCcw, Box
} from 'lucide-react';
import { editImageWithAI } from '../services/geminiService';

interface ImageEditorProps {
  imageUrl: string;
  onClose: () => void;
  onSave: (newImageUrl: string) => void;
}

type Tool = 'select-fill' | 'brush' | 'ai-erase' | 'crop' | 'rect' | 'circle' | 'line' | 'text' | 'none';

interface SelectionBox {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
}

const CORS_PROXY = 'https://corsproxy.io/?';

export const ImageEditor: React.FC<ImageEditorProps> = ({ imageUrl, onClose, onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [currentTool, setCurrentTool] = useState<Tool>('none');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [strokeColor, setStrokeColor] = useState('#000000');
  const [fillColor, setFillColor] = useState('#ffffff');
  const [brushSize, setBrushSize] = useState(5);
  const [history, setHistory] = useState<string[]>([]);
  const [zoom, setZoom] = useState(1);
  const [isDrawing, setIsDrawing] = useState(false);
  const [selection, setSelection] = useState<SelectionBox | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const initCanvas = async () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d', { willReadFrequently: true }) as CanvasRenderingContext2D | null;
      if (!ctx) return;

      setIsProcessing(true);
      try {
        const proxyUrl = `${CORS_PROXY}${encodeURIComponent(imageUrl)}`;
        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error("Failed to fetch image through proxy");
        const blob = await response.blob();
        const localUrl = URL.createObjectURL(blob);

        const img = new Image();
        img.src = localUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);

          if (containerRef.current) {
            const padding = 120;
            const availableW = containerRef.current.clientWidth - padding;
            const availableH = containerRef.current.clientHeight - padding;
            const scale = Math.min(availableW / img.width, availableH / img.height, 1);
            setZoom(scale || 1);
          }

          saveToHistory();
          setIsProcessing(false);
          URL.revokeObjectURL(localUrl);
        };
      } catch (err) {
        console.warn("Proxy load failed, falling back to direct load:", err);
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.src = imageUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          (ctx as CanvasRenderingContext2D).drawImage(img, 0, 0);
          saveToHistory();
          setIsProcessing(false);
        };
      }
    };
    initCanvas();
  }, [imageUrl]);

  const saveToHistory = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      setHistory(prev => [...prev.slice(-20), canvas.toDataURL('image/png')]);
    }
  };

  const undo = () => {
    if (history.length <= 1) return;
    const newHistory = [...history];
    newHistory.pop(); 
    const last = newHistory[newHistory.length - 1];
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (canvas && ctx && last) {
      const img = new Image();
      img.src = last;
      img.onload = () => {
        canvas.width = img.width;
        canvas.height = img.height;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        setHistory(newHistory);
      };
    }
  };

  const standardize = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const currentData = canvas.toDataURL();
    const tempImg = new Image();
    tempImg.src = currentData;
    tempImg.onload = () => {
      const targetSize = 1600;
      const safeArea = 1500;
      canvas.width = targetSize;
      canvas.height = targetSize;
      const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, targetSize, targetSize);
      const scale = Math.min(safeArea / tempImg.width, safeArea / tempImg.height);
      const drawW = tempImg.width * scale;
      const drawH = tempImg.height * scale;
      const x = (targetSize - drawW) / 2;
      const y = (targetSize - drawH) / 2;
      ctx.drawImage(tempImg, x, y, drawW, drawH);
      saveToHistory();
      if (containerRef.current) {
        setZoom(Math.min((containerRef.current.clientHeight - 120) / 1600, 1));
      }
    };
  };

  const getMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }
    return {
      x: (clientX - rect.left) / zoom,
      y: (clientY - rect.top) / zoom
    };
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    if (currentTool === 'none') return;
    const pos = getMousePos(e);
    setStartPos(pos);
    setIsDrawing(true);
    if (currentTool === 'select-fill' || currentTool === 'crop' || currentTool === 'rect' || currentTool === 'circle' || currentTool === 'line') {
      setSelection({ x1: pos.x, y1: pos.y, x2: pos.x, y2: pos.y });
    }
    if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.beginPath();
        ctx.moveTo(pos.x, pos.y);
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.strokeStyle = currentTool === 'ai-erase' ? 'rgba(255, 0, 0, 0.6)' : strokeColor;
        ctx.lineWidth = brushSize;
      }
    }
  };

  const drawShape = (ctx: CanvasRenderingContext2D, tool: Tool, start: {x: number, y: number}, end: {x: number, y: number}) => {
    ctx.strokeStyle = strokeColor;
    ctx.fillStyle = fillColor;
    ctx.lineWidth = brushSize;
    ctx.lineCap = 'round';

    if (tool === 'rect') {
      const x = Math.min(start.x, end.x);
      const y = Math.min(start.y, end.y);
      const w = Math.abs(start.x - end.x);
      const h = Math.abs(start.y - end.y);
      ctx.beginPath();
      ctx.rect(x, y, w, h);
      ctx.fill();
      ctx.stroke();
    } else if (tool === 'circle') {
      const rx = Math.abs(start.x - end.x);
      const ry = Math.abs(start.y - end.y);
      const r = Math.sqrt(rx*rx + ry*ry);
      ctx.beginPath();
      ctx.arc(start.x, start.y, r, 0, Math.PI * 2);
      ctx.fill();
      ctx.stroke();
    } else if (tool === 'line') {
      ctx.beginPath();
      ctx.moveTo(start.x, start.y);
      ctx.lineTo(end.x, end.y);
      ctx.stroke();
    }
  };

  const handleMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    const pos = getMousePos(e);

    if (['rect', 'circle', 'line'].includes(currentTool)) {
      setSelection(prev => prev ? { ...prev, x2: pos.x, y2: pos.y } : null);
      // For shapes, we need a preview. 
      // Simplest way for this architecture: redraw from history then draw current shape.
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
      if (canvas && ctx && history.length > 0) {
        const lastImg = new Image();
        lastImg.src = history[history.length - 1];
        lastImg.onload = () => {
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(lastImg, 0, 0);
          drawShape(ctx, currentTool, startPos, pos);
        };
      }
    } else if (currentTool === 'select-fill' || currentTool === 'crop') {
      setSelection(prev => prev ? { ...prev, x2: pos.x, y2: pos.y } : null);
    } else if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.lineTo(pos.x, pos.y);
        ctx.stroke();
      }
    }
  };

  const handleEnd = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    setIsDrawing(false);

    if (['rect', 'circle', 'line', 'brush'].includes(currentTool)) {
      saveToHistory();
    }

    if (currentTool === 'text') {
      const pos = getMousePos(e);
      const text = window.prompt("Enter text:");
      if (text) {
        const canvas = canvasRef.current;
        const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
        if (ctx) {
          ctx.font = `bold ${brushSize * 5}px Inter, sans-serif`;
          ctx.fillStyle = fillColor;
          ctx.strokeStyle = strokeColor;
          ctx.lineWidth = Math.max(1, brushSize / 2);
          ctx.fillText(text, pos.x, pos.y);
          ctx.strokeText(text, pos.x, pos.y);
          saveToHistory();
        }
      }
    }
  };

  const handleFill = () => {
    if (currentTool !== 'select-fill' || !selection) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    ctx.fillStyle = fillColor;
    ctx.fillRect(x, y, w, h);
    saveToHistory();
    setSelection(null); 
  };

  const handleCrop = () => {
    if (!selection) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    if (w < 5 || h < 5) return;
    const imageData = ctx.getImageData(x, y, w, h);
    canvas.width = w;
    canvas.height = h;
    ctx.putImageData(imageData, 0, 0);
    saveToHistory();
    setSelection(null);
    setZoom(1);
  };

  const runAIErase = async () => {
    setIsProcessing(true);
    try {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const base64 = canvas.toDataURL('image/jpeg', 0.9).split(',')[1];
      const result = await editImageWithAI(base64, "Please erase the red highlighted areas cleanly.");
      const img = new Image();
      img.src = `data:image/jpeg;base64,${result}`;
      img.onload = () => {
        const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        saveToHistory();
        setIsProcessing(false);
      };
    } catch (e: any) {
      alert("AI Erase failed: " + e.message);
      setIsProcessing(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col font-inter">
      <div className="h-16 bg-slate-900 border-b border-slate-800 px-6 flex items-center justify-between text-white shadow-xl z-20">
        <div className="flex items-center gap-6">
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-all"><X size={20} /></button>
          <div className="h-6 w-px bg-slate-800"></div>
          <h2 className="font-black tracking-tighter text-xl bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent uppercase">AI Media Lab</h2>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex bg-slate-800 p-1 rounded-xl">
            <button onClick={() => setZoom(prev => Math.max(0.05, prev - 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomOut size={16} /></button>
            <span className="px-3 flex items-center text-[10px] font-black text-slate-300 w-16 justify-center">{(zoom * 100).toFixed(0)}%</span>
            <button onClick={() => setZoom(prev => Math.min(5, prev + 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomIn size={16} /></button>
          </div>
          <button onClick={undo} disabled={history.length <= 1} className="p-2.5 bg-slate-800 hover:bg-slate-700 disabled:opacity-30 rounded-xl text-slate-300 transition-all"><Undo size={18} /></button>
          <button onClick={standardize} className="px-5 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-black flex items-center gap-2 border border-slate-700"><Maximize size={16} /> 1600*1600</button>
          <button onClick={() => onSave(canvasRef.current?.toDataURL('image/jpeg', 0.95) || '')} className="px-8 py-2.5 bg-indigo-600 hover:bg-indigo-700 rounded-xl text-xs font-black shadow-lg flex items-center gap-2 transform active:scale-95 transition-all"><Save size={16} /> Save & Apply</button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className="w-24 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-6 z-20 overflow-y-auto no-scrollbar">
          <ToolIcon active={currentTool === 'brush'} onClick={() => { setCurrentTool('brush'); setSelection(null); }} icon={<Palette size={20} />} label="Brush" />
          <ToolIcon active={currentTool === 'ai-erase'} onClick={() => { setCurrentTool('ai-erase'); setSelection(null); }} icon={<Eraser size={20} />} label="AI Erase" />
          <ToolIcon active={currentTool === 'rect'} onClick={() => { setCurrentTool('rect'); setSelection(null); }} icon={<Square size={20} />} label="Rect" />
          <ToolIcon active={currentTool === 'circle'} onClick={() => { setCurrentTool('circle'); setSelection(null); }} icon={<Circle size={20} />} label="Circle" />
          <ToolIcon active={currentTool === 'line'} onClick={() => { setCurrentTool('line'); setSelection(null); }} icon={<Minus size={20} />} label="Line" />
          <ToolIcon active={currentTool === 'text'} onClick={() => { setCurrentTool('text'); setSelection(null); }} icon={<Type size={20} />} label="Text" />
          <ToolIcon active={currentTool === 'select-fill'} onClick={() => { setCurrentTool('select-fill'); setSelection(null); }} icon={<PaintBucket size={20} />} label="Fill" />
          <ToolIcon active={currentTool === 'crop'} onClick={() => { setCurrentTool('crop'); setSelection(null); }} icon={<Scissors size={20} />} label="Crop" />

          <div className="mt-auto flex flex-col gap-4 pb-4">
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Stroke</span>
               <input type="color" value={strokeColor} onChange={(e) => setStrokeColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Fill</span>
               <input type="color" value={fillColor} onChange={(e) => setFillColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
          </div>
        </div>

        <div ref={containerRef} className="flex-1 bg-slate-950 overflow-auto flex items-center justify-center p-20 relative">
          <div className="relative shadow-2xl transition-transform duration-75 origin-center" style={{ transform: `scale(${zoom})` }}>
            <canvas ref={canvasRef} onMouseDown={handleStart} onMouseMove={handleMove} onMouseUp={handleEnd} className="block relative" style={{ cursor: currentTool === 'none' ? 'default' : 'crosshair' }} />
            {selection && (currentTool === 'select-fill' || currentTool === 'crop') && (
               <div className="absolute pointer-events-none border-2 border-white" style={{ left: Math.min(selection.x1, selection.x2), top: Math.min(selection.y1, selection.y2), width: Math.abs(selection.x1 - selection.x2), height: Math.abs(selection.y1 - selection.y2) }}>
                 <div className="absolute inset-0 border-2 border-dashed border-black/50 animate-pulse"></div>
               </div>
            )}
          </div>

          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-8 bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-4 rounded-3xl shadow-2xl z-30 min-w-[500px]">
             <div className="flex flex-col gap-1 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase">Size / Stroke Width</span>
                 <span className="text-[10px] font-black text-blue-400">{brushSize}px</span>
               </div>
               <input type="range" min="1" max="100" value={brushSize} onChange={(e) => setBrushSize(parseInt(e.target.value))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500" />
             </div>

             {currentTool === 'ai-erase' && (
               <button onClick={runAIErase} disabled={isProcessing} className="px-8 py-3 bg-red-600 hover:bg-red-700 text-white rounded-2xl text-xs font-black shadow-xl flex items-center gap-3 transition-all active:scale-95 disabled:opacity-50">
                 {isProcessing ? <Loader2 className="animate-spin" size={16} /> : <Wand2 size={16} />} AI ERASE
               </button>
             )}
             {currentTool === 'select-fill' && (
               <button onClick={handleFill} disabled={!selection} className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">FILL AREA</button>
             )}
             {currentTool === 'crop' && (
               <button onClick={handleCrop} disabled={!selection} className="px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">CONFIRM CROP</button>
             )}
             {['rect', 'circle', 'line', 'text', 'brush', 'none'].includes(currentTool) && currentTool !== 'ai-erase' && (
                <div className="px-10 text-[10px] font-black text-slate-500 uppercase tracking-widest">{currentTool === 'none' ? 'Select a tool' : `${currentTool} tool active`}</div>
             )}
          </div>

          {isProcessing && <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/70 backdrop-blur-md"><Loader2 size={40} className="text-indigo-500 animate-spin" /><p className="mt-8 text-white font-black tracking-[0.3em] text-sm uppercase">AI Processing...</p></div>}
        </div>
      </div>
    </div>
  );
};

const ToolIcon = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1.5 group transition-all shrink-0 ${active ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>
    <div className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${active ? 'bg-indigo-600/10 border border-indigo-500/50 shadow-lg' : 'bg-slate-800/50 hover:bg-slate-800'}`}>
      {icon}
    </div>
    <span className="text-[8px] font-black uppercase tracking-tighter">{label}</span>
  </button>
);

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  X, Eraser, Scissors, PaintBucket, Crop, Save, Undo, 
  Wand2, Loader2, Download, MousePointer2, Maximize, 
  Type, Square, Circle, Minus, Move, Palette, Trash2,
  ZoomIn, ZoomOut, RotateCcw, Box, ArrowUpRight
} from 'lucide-react';
import { editImageWithAI } from '../services/geminiService';

interface ImageEditorProps {
  imageUrl: string;
  onClose: () => void;
  onSave: (newImageUrl: string) => void;
}

type Tool = 'select' | 'select-fill' | 'brush' | 'ai-erase' | 'crop' | 'rect' | 'circle' | 'line' | 'text' | 'none';

interface EditorObject {
  id: string;
  type: 'rect' | 'circle' | 'line' | 'text';
  x: number;
  y: number;
  width: number;
  height: number;
  stroke: string;
  fill: string;
  strokeWidth: number;
  text?: string;
}

interface SelectionBox {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
}

const CORS_PROXY = 'https://corsproxy.io/?';

export const ImageEditor: React.FC<ImageEditorProps> = ({ imageUrl, onClose, onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [currentTool, setCurrentTool] = useState<Tool>('select');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [strokeColor, setStrokeColor] = useState('#000000');
  const [fillColor, setFillColor] = useState('#ffffff');
  const [brushSize, setBrushSize] = useState(5);
  const [history, setHistory] = useState<string[]>([]);
  const [zoom, setZoom] = useState(1);

  // Object system
  const [objects, setObjects] = useState<EditorObject[]>([]);
  const [selectedObjectId, setSelectedObjectId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const [isDrawing, setIsDrawing] = useState(false);
  const [selection, setSelection] = useState<SelectionBox | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const initCanvas = async () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d', { willReadFrequently: true }) as CanvasRenderingContext2D | null;
      if (!ctx) return;

      setIsProcessing(true);
      try {
        const proxyUrl = `${CORS_PROXY}${encodeURIComponent(imageUrl)}`;
        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error("Failed to fetch image through proxy");
        const blob = await response.blob();
        const localUrl = URL.createObjectURL(blob);

        const img = new Image();
        img.src = localUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);

          if (containerRef.current) {
            const padding = 120;
            const availableW = containerRef.current.clientWidth - padding;
            const availableH = containerRef.current.clientHeight - padding;
            const scale = Math.min(availableW / img.width, availableH / img.height, 1);
            setZoom(scale || 1);
          }

          saveToHistory();
          setIsProcessing(false);
          URL.revokeObjectURL(localUrl);
        };
      } catch (err) {
        console.warn("Proxy load failed, falling back to direct load:", err);
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.src = imageUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          (ctx as CanvasRenderingContext2D).drawImage(img, 0, 0);
          saveToHistory();
          setIsProcessing(false);
        };
      }
    };
    initCanvas();
  }, [imageUrl]);

  const saveToHistory = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      setHistory(prev => [...prev.slice(-20), canvas.toDataURL('image/png')]);
    }
  };

  const undo = () => {
    if (history.length <= 1) return;
    const newHistory = [...history];
    newHistory.pop(); 
    const last = newHistory[newHistory.length - 1];
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (canvas && ctx && last) {
      const img = new Image();
      img.src = last;
      img.onload = () => {
        canvas.width = img.width;
        canvas.height = img.height;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        setHistory(newHistory);
        setObjects([]); // Clear active objects on undo as they are baked per step in this simplified model or lost
      };
    }
  };

  const standardize = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const currentData = canvas.toDataURL();
    const tempImg = new Image();
    tempImg.src = currentData;
    tempImg.onload = () => {
      const targetSize = 1600;
      const safeArea = 1500;
      canvas.width = targetSize;
      canvas.height = targetSize;
      const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, targetSize, targetSize);
      const scale = Math.min(safeArea / tempImg.width, safeArea / tempImg.height);
      const drawW = tempImg.width * scale;
      const drawH = tempImg.height * scale;
      const x = (targetSize - drawW) / 2;
      const y = (targetSize - drawH) / 2;
      ctx.drawImage(tempImg, x, y, drawW, drawH);
      saveToHistory();
      if (containerRef.current) {
        setZoom(Math.min((containerRef.current.clientHeight - 120) / 1600, 1));
      }
    };
  };

  const getMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }
    return {
      x: (clientX - rect.left) / zoom,
      y: (clientY - rect.top) / zoom
    };
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);
    setStartPos(pos);

    if (currentTool === 'select') {
      // Check for handles first
      if (selectedObjectId) {
        const obj = objects.find(o => o.id === selectedObjectId);
        if (obj) {
          const handleSize = 10 / zoom;
          const isOverResizeHandle = 
            pos.x >= obj.x + obj.width - handleSize && 
            pos.x <= obj.x + obj.width + handleSize && 
            pos.y >= obj.y + obj.height - handleSize && 
            pos.y <= obj.y + obj.height + handleSize;

          if (isOverResizeHandle) {
            setIsResizing(true);
            return;
          }

          const isOverBody = 
            pos.x >= obj.x && pos.x <= obj.x + obj.width &&
            pos.y >= obj.y && pos.y <= obj.y + obj.height;

          if (isOverBody) {
            setIsDragging(true);
            setDragOffset({ x: pos.x - obj.x, y: pos.y - obj.y });
            return;
          }
        }
      }

      // Check hit test for all objects
      const hit = objects.slice().reverse().find(obj => 
        pos.x >= obj.x && pos.x <= obj.x + obj.width &&
        pos.y >= obj.y && pos.y <= obj.y + obj.height
      );

      if (hit) {
        setSelectedObjectId(hit.id);
        setIsDragging(true);
        setDragOffset({ x: pos.x - hit.x, y: pos.y - hit.y });
      } else {
        setSelectedObjectId(null);
      }
      return;
    }

    setIsDrawing(true);
    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection({ x1: pos.x, y1: pos.y, x2: pos.x, y2: pos.y });
    }

    if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.beginPath();
        ctx.moveTo(pos.x, pos.y);
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.strokeStyle = currentTool === 'ai-erase' ? 'rgba(255, 0, 0, 0.6)' : strokeColor;
        ctx.lineWidth = brushSize;
      }
    }
  };

  const handleMove = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);

    if (currentTool === 'select' && selectedObjectId) {
      if (isDragging) {
        setObjects(prev => prev.map(obj => 
          obj.id === selectedObjectId 
            ? { ...obj, x: pos.x - dragOffset.x, y: pos.y - dragOffset.y }
            : obj
        ));
      } else if (isResizing) {
        setObjects(prev => prev.map(obj => 
          obj.id === selectedObjectId 
            ? { ...obj, width: Math.max(10, pos.x - obj.x), height: Math.max(10, pos.y - obj.y) }
            : obj
        ));
      }
      return;
    }

    if (!isDrawing) return;

    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection(prev => prev ? { ...prev, x2: pos.x, y2: pos.y } : null);
    } else if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.lineTo(pos.x, pos.y);
        ctx.stroke();
      }
    }
  };

  const handleEnd = (e: React.MouseEvent | React.TouchEvent) => {
    if (currentTool === 'select') {
      setIsDragging(false);
      setIsResizing(false);
      return;
    }

    if (!isDrawing) return;
    setIsDrawing(false);

    const pos = getMousePos(e);

    if (['rect', 'circle', 'line'].includes(currentTool)) {
      const newObj: EditorObject = {
        id: crypto.randomUUID(),
        type: currentTool as any,
        x: Math.min(startPos.x, pos.x),
        y: Math.min(startPos.y, pos.y),
        width: Math.abs(startPos.x - pos.x),
        height: Math.abs(startPos.y - pos.y),
        stroke: strokeColor,
        fill: fillColor,
        strokeWidth: brushSize
      };
      setObjects(prev => [...prev, newObj]);
      setSelectedObjectId(newObj.id);
      setCurrentTool('select');
      setSelection(null);
    } else if (currentTool === 'text') {
      const text = window.prompt("Enter text:");
      if (text) {
        const newObj: EditorObject = {
          id: crypto.randomUUID(),
          type: 'text',
          x: pos.x,
          y: pos.y,
          width: text.length * brushSize * 3, // Approximation for selection box
          height: brushSize * 6,
          stroke: strokeColor,
          fill: fillColor,
          strokeWidth: brushSize,
          text: text
        };
        setObjects(prev => [...prev, newObj]);
        setSelectedObjectId(newObj.id);
        setCurrentTool('select');
      }
    } else if (currentTool === 'brush') {
      saveToHistory();
    }
  };

  const handleFill = () => {
    if (currentTool !== 'select-fill' || !selection) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    ctx.fillStyle = fillColor;
    ctx.fillRect(x, y, w, h);
    saveToHistory();
    setSelection(null); 
  };

  const handleCrop = () => {
    if (!selection) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    if (w < 5 || h < 5) return;
    const imageData = ctx.getImageData(x, y, w, h);
    canvas.width = w;
    canvas.height = h;
    ctx.putImageData(imageData, 0, 0);
    saveToHistory();
    setSelection(null);
    setZoom(1);
  };

  const runAIErase = async () => {
    setIsProcessing(true);
    try {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const base64 = canvas.toDataURL('image/jpeg', 0.9).split(',')[1];
      const result = await editImageWithAI(base64, "Please erase the red highlighted areas cleanly.");
      const img = new Image();
      img.src = `data:image/jpeg;base64,${result}`;
      img.onload = () => {
        const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        saveToHistory();
        setIsProcessing(false);
      };
    } catch (e: any) {
      alert("AI Erase failed: " + e.message);
      setIsProcessing(false);
    }
  };

  const handleFinalSave = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Draw all objects onto the canvas permanently
    objects.forEach(obj => {
      ctx.strokeStyle = obj.stroke;
      ctx.fillStyle = obj.fill;
      ctx.lineWidth = obj.strokeWidth;
      ctx.lineCap = 'round';

      if (obj.type === 'rect') {
        ctx.beginPath();
        ctx.rect(obj.x, obj.y, obj.width, obj.height);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'circle') {
        const r = Math.sqrt(obj.width * obj.width + obj.height * obj.height) / 2;
        ctx.beginPath();
        ctx.arc(obj.x + obj.width/2, obj.y + obj.height/2, r, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'line') {
        ctx.beginPath();
        ctx.moveTo(obj.x, obj.y);
        ctx.lineTo(obj.x + obj.width, obj.y + obj.height);
        ctx.stroke();
      } else if (obj.type === 'text' && obj.text) {
        ctx.font = `bold ${obj.strokeWidth * 6}px Inter, sans-serif`;
        ctx.fillText(obj.text, obj.x, obj.y);
        ctx.strokeText(obj.text, obj.x, obj.y);
      }
    });

    onSave(canvas.toDataURL('image/jpeg', 0.95));
  };

  // Keyboard support for deleting objects
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedObjectId) {
        setObjects(prev => prev.filter(o => o.id !== selectedObjectId));
        setSelectedObjectId(null);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedObjectId]);

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col font-inter">
      <div className="h-16 bg-slate-900 border-b border-slate-800 px-6 flex items-center justify-between text-white shadow-xl z-20">
        <div className="flex items-center gap-6">
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-all"><X size={20} /></button>
          <div className="h-6 w-px bg-slate-800"></div>
          <h2 className="font-black tracking-tighter text-xl bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent uppercase">AI Media Lab</h2>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex bg-slate-800 p-1 rounded-xl">
            <button onClick={() => setZoom(prev => Math.max(0.05, prev - 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomOut size={16} /></button>
            <span className="px-3 flex items-center text-[10px] font-black text-slate-300 w-16 justify-center">{(zoom * 100).toFixed(0)}%</span>
            <button onClick={() => setZoom(prev => Math.min(5, prev + 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomIn size={16} /></button>
          </div>
          <button onClick={undo} disabled={history.length <= 1} className="p-2.5 bg-slate-800 hover:bg-slate-700 disabled:opacity-30 rounded-xl text-slate-300 transition-all"><Undo size={18} /></button>
          <button onClick={standardize} className="px-5 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-black flex items-center gap-2 border border-slate-700"><Maximize size={16} /> 1600*1600</button>
          <button onClick={handleFinalSave} className="px-8 py-2.5 bg-indigo-600 hover:bg-indigo-700 rounded-xl text-xs font-black shadow-lg flex items-center gap-2 transform active:scale-95 transition-all"><Save size={16} /> Save & Apply</button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className="w-24 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-6 z-20 overflow-y-auto no-scrollbar">
          <ToolIcon active={currentTool === 'select'} onClick={() => { setCurrentTool('select'); }} icon={<MousePointer2 size={20} />} label="Select" />
          <ToolIcon active={currentTool === 'brush'} onClick={() => { setCurrentTool('brush'); setSelectedObjectId(null); }} icon={<Palette size={20} />} label="Brush" />
          <ToolIcon active={currentTool === 'ai-erase'} onClick={() => { setCurrentTool('ai-erase'); setSelectedObjectId(null); }} icon={<Eraser size={20} />} label="AI Erase" />
          <ToolIcon active={currentTool === 'rect'} onClick={() => { setCurrentTool('rect'); setSelectedObjectId(null); }} icon={<Square size={20} />} label="Rect" />
          <ToolIcon active={currentTool === 'circle'} onClick={() => { setCurrentTool('circle'); setSelectedObjectId(null); }} icon={<Circle size={20} />} label="Circle" />
          <ToolIcon active={currentTool === 'line'} onClick={() => { setCurrentTool('line'); setSelectedObjectId(null); }} icon={<Minus size={20} />} label="Line" />
          <ToolIcon active={currentTool === 'text'} onClick={() => { setCurrentTool('text'); setSelectedObjectId(null); }} icon={<Type size={20} />} label="Text" />
          <ToolIcon active={currentTool === 'select-fill'} onClick={() => { setCurrentTool('select-fill'); setSelectedObjectId(null); }} icon={<PaintBucket size={20} />} label="Fill" />
          <ToolIcon active={currentTool === 'crop'} onClick={() => { setCurrentTool('crop'); setSelectedObjectId(null); }} icon={<Scissors size={20} />} label="Crop" />

          <div className="mt-auto flex flex-col gap-4 pb-4">
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Stroke</span>
               <input type="color" value={strokeColor} onChange={(e) => setStrokeColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Fill</span>
               <input type="color" value={fillColor} onChange={(e) => setFillColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
          </div>
        </div>

        <div ref={containerRef} className="flex-1 bg-slate-950 overflow-auto flex items-center justify-center p-20 relative">
          <div className="relative shadow-2xl transition-transform duration-75 origin-center" style={{ transform: `scale(${zoom})` }}>
            <canvas ref={canvasRef} onMouseDown={handleStart} onMouseMove={handleMove} onMouseUp={handleEnd} className="block relative" style={{ cursor: currentTool === 'none' ? 'default' : currentTool === 'select' ? 'default' : 'crosshair' }} />

            {/* Object Overlay */}
            <svg 
              className="absolute inset-0 pointer-events-none w-full h-full"
              viewBox={`0 0 ${canvasRef.current?.width || 0} ${canvasRef.current?.height || 0}`}
            >
              {objects.map(obj => (
                <g key={obj.id} className={selectedObjectId === obj.id ? 'opacity-100' : 'opacity-80'}>
                  {obj.type === 'rect' && <rect x={obj.x} y={obj.y} width={obj.width} height={obj.height} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'circle' && <ellipse cx={obj.x + obj.width/2} cy={obj.y + obj.height/2} rx={obj.width/2} ry={obj.height/2} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'line' && <line x1={obj.x} y1={obj.y} x2={obj.x + obj.width} y2={obj.y + obj.height} stroke={obj.stroke} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'text' && (
                    <text 
                      x={obj.x} 
                      y={obj.y} 
                      fill={obj.fill} 
                      stroke={obj.stroke} 
                      strokeWidth={obj.strokeWidth/4} 
                      style={{ font: `bold ${obj.strokeWidth * 6}px Inter, sans-serif` }}
                    >
                      {obj.text}
                    </text>
                  )}
                  {selectedObjectId === obj.id && (
                    <>
                      <rect 
                        x={obj.x} y={obj.y} width={obj.width} height={obj.height} 
                        fill="none" stroke="#6366f1" strokeWidth={2 / zoom} strokeDasharray="4"
                      />
                      {/* Resize handle */}
                      <circle 
                        cx={obj.x + obj.width} cy={obj.y + obj.height} r={6 / zoom} 
                        fill="#6366f1" className="cursor-nwse-resize" 
                      />
                    </>
                  )}
                </g>
              ))}
            </svg>

            {selection && (['select-fill', 'crop'].includes(currentTool)) && (
               <div className="absolute pointer-events-none border-2 border-white" style={{ left: Math.min(selection.x1, selection.x2), top: Math.min(selection.y1, selection.y2), width: Math.abs(selection.x1 - selection.x2), height: Math.abs(selection.y1 - selection.y2) }}>
                 <div className="absolute inset-0 border-2 border-dashed border-black/50 animate-pulse"></div>
               </div>
            )}
          </div>

          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-8 bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-4 rounded-3xl shadow-2xl z-30 min-w-[500px]">
             <div className="flex flex-col gap-1 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase">Size / Stroke Width</span>
                 <span className="text-[10px] font-black text-blue-400">{brushSize}px</span>
               </div>
               <input type="range" min="1" max="100" value={brushSize} onChange={(e) => setBrushSize(parseInt(e.target.value))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500" />
             </div>

             {currentTool === 'ai-erase' && (
               <button onClick={runAIErase} disabled={isProcessing} className="px-8 py-3 bg-red-600 hover:bg-red-700 text-white rounded-2xl text-xs font-black shadow-xl flex items-center gap-3 transition-all active:scale-95 disabled:opacity-50">
                 {isProcessing ? <Loader2 className="animate-spin" size={16} /> : <Wand2 size={16} />} AI ERASE
               </button>
             )}
             {currentTool === 'select-fill' && (
               <button onClick={handleFill} disabled={!selection} className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">FILL AREA</button>
             )}
             {currentTool === 'crop' && (
               <button onClick={handleCrop} disabled={!selection} className="px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">CONFIRM CROP</button>
             )}
             {['select', 'rect', 'circle', 'line', 'text', 'brush', 'none'].includes(currentTool) && currentTool !== 'ai-erase' && (
                <div className="px-10 text-[10px] font-black text-slate-500 uppercase tracking-widest">
                  {currentTool === 'select' ? (selectedObjectId ? 'Object Selected (Drag corners to resize)' : 'Select an object') : `${currentTool} tool active`}
                </div>
             )}
          </div>

          {isProcessing && <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/70 backdrop-blur-md"><Loader2 size={40} className="text-indigo-500 animate-spin" /><p className="mt-8 text-white font-black tracking-[0.3em] text-sm uppercase">AI Processing...</p></div>}
        </div>
      </div>
    </div>
  );
};

const ToolIcon = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1.5 group transition-all shrink-0 ${active ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>
    <div className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${active ? 'bg-indigo-600/10 border border-indigo-500/50 shadow-lg' : 'bg-slate-800/50 hover:bg-slate-800'}`}>
      {icon}
    </div>
    <span className="text-[8px] font-black uppercase tracking-tighter">{label}</span>
  </button>
);

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  X, Eraser, Scissors, PaintBucket, Crop, Save, Undo, 
  Wand2, Loader2, Download, MousePointer2, Maximize, 
  Type, Square, Circle, Minus, Move, Palette, Trash2,
  ZoomIn, ZoomOut, RotateCcw, Box, ArrowUpRight, RefreshCw
} from 'lucide-react';
import { editImageWithAI } from '../services/geminiService';

interface ImageEditorProps {
  imageUrl: string;
  onClose: () => void;
  onSave: (newImageUrl: string) => void;
}

type Tool = 'select' | 'select-fill' | 'brush' | 'ai-erase' | 'crop' | 'rect' | 'circle' | 'line' | 'text' | 'none';

interface EditorObject {
  id: string;
  type: 'rect' | 'circle' | 'line' | 'text';
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number; // In radians
  stroke: string;
  fill: string;
  strokeWidth: number;
  text?: string;
}

interface EditorState {
  canvasData: string;
  objects: EditorObject[];
}

interface SelectionBox {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
}

const CORS_PROXY = 'https://corsproxy.io/?';

export const ImageEditor: React.FC<ImageEditorProps> = ({ imageUrl, onClose, onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [currentTool, setCurrentTool] = useState<Tool>('select');
  const [isProcessing, setIsProcessing] = useState(false);
  const [strokeColor, setStrokeColor] = useState('#000000');
  const [fillColor, setFillColor] = useState('#ffffff');
  const [brushSize, setBrushSize] = useState(5);
  const [zoom, setZoom] = useState(1);

  // Object system
  const [objects, setObjects] = useState<EditorObject[]>([]);
  const [selectedObjectId, setSelectedObjectId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [isRotating, setIsRotating] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const [isDrawing, setIsDrawing] = useState(false);
  const [selection, setSelection] = useState<SelectionBox | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });

  // Unified History System
  const [history, setHistory] = useState<EditorState[]>([]);

  const saveToHistory = useCallback((currentObjects?: EditorObject[]) => {
    const canvas = canvasRef.current;
    if (canvas) {
      const newState: EditorState = {
        canvasData: canvas.toDataURL('image/png'),
        objects: currentObjects ? [...currentObjects] : [...objects]
      };
      setHistory(prev => [...prev.slice(-30), newState]);
    }
  }, [objects]);

  useEffect(() => {
    const initCanvas = async () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d', { willReadFrequently: true }) as CanvasRenderingContext2D | null;
      if (!ctx) return;

      setIsProcessing(true);
      try {
        const proxyUrl = `${CORS_PROXY}${encodeURIComponent(imageUrl)}`;
        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error("Failed to fetch image through proxy");
        const blob = await response.blob();
        const localUrl = URL.createObjectURL(blob);

        const img = new Image();
        img.src = localUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);

          if (containerRef.current) {
            const padding = 120;
            const availableW = containerRef.current.clientWidth - padding;
            const availableH = containerRef.current.clientHeight - padding;
            const scale = Math.min(availableW / img.width, availableH / img.height, 1);
            setZoom(scale || 1);
          }

          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
          URL.revokeObjectURL(localUrl);
        };
      } catch (err) {
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.src = imageUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          (ctx as CanvasRenderingContext2D).drawImage(img, 0, 0);
          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
        };
      }
    };
    initCanvas();
  }, [imageUrl]);

  const undo = () => {
    if (history.length <= 1) return;
    const newHistory = [...history];
    newHistory.pop(); 
    const prevState = newHistory[newHistory.length - 1];

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (canvas && ctx && prevState) {
      const img = new Image();
      img.src = prevState.canvasData;
      img.onload = () => {
        canvas.width = img.width;
        canvas.height = img.height;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        setObjects(prevState.objects);
        setHistory(newHistory);
      };
    }
  };

  const standardize = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const currentData = canvas.toDataURL();
    const tempImg = new Image();
    tempImg.src = currentData;
    tempImg.onload = () => {
      const targetSize = 1600;
      const safeArea = 1500;
      canvas.width = targetSize;
      canvas.height = targetSize;
      const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, targetSize, targetSize);
      const scale = Math.min(safeArea / tempImg.width, safeArea / tempImg.height);
      const drawW = tempImg.width * scale;
      const drawH = tempImg.height * scale;
      const x = (targetSize - drawW) / 2;
      const y = (targetSize - drawH) / 2;
      ctx.drawImage(tempImg, x, y, drawW, drawH);
      saveToHistory();
      if (containerRef.current) {
        setZoom(Math.min((containerRef.current.clientHeight - 120) / 1600, 1));
      }
    };
  };

  const getMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }
    return {
      x: (clientX - rect.left) / zoom,
      y: (clientY - rect.top) / zoom
    };
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);
    setStartPos(pos);

    if (currentTool === 'select') {
      if (selectedObjectId) {
        const obj = objects.find(o => o.id === selectedObjectId);
        if (obj) {
          const handleSize = 12 / zoom;
          const rotateHandleY = obj.y - 30 / zoom;
          const centerX = obj.x + obj.width / 2;

          // Basic hit test for rotation handle
          const distToRotate = Math.sqrt(Math.pow(pos.x - centerX, 2) + Math.pow(pos.y - rotateHandleY, 2));
          if (distToRotate < handleSize) {
            setIsRotating(true);
            return;
          }

          const isOverResizeHandle = 
            pos.x >= obj.x + obj.width - handleSize && 
            pos.x <= obj.x + obj.width + handleSize && 
            pos.y >= obj.y + obj.height - handleSize && 
            pos.y <= obj.y + obj.height + handleSize;

          if (isOverResizeHandle) {
            setIsResizing(true);
            return;
          }

          const isOverBody = 
            pos.x >= obj.x && pos.x <= obj.x + obj.width &&
            pos.y >= obj.y && pos.y <= obj.y + obj.height;

          if (isOverBody) {
            setIsDragging(true);
            setDragOffset({ x: pos.x - obj.x, y: pos.y - obj.y });
            return;
          }
        }
      }

      const hit = objects.slice().reverse().find(obj => 
        pos.x >= obj.x && pos.x <= obj.x + obj.width &&
        pos.y >= obj.y && pos.y <= obj.y + obj.height
      );

      if (hit) {
        setSelectedObjectId(hit.id);
        setIsDragging(true);
        setDragOffset({ x: pos.x - hit.x, y: pos.y - hit.y });
      } else {
        setSelectedObjectId(null);
      }
      return;
    }

    setIsDrawing(true);
    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection({ x1: pos.x, y1: pos.y, x2: pos.x, y2: pos.y });
    }

    if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.beginPath();
        ctx.moveTo(pos.x, pos.y);
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.strokeStyle = currentTool === 'ai-erase' ? 'rgba(255, 0, 0, 0.6)' : strokeColor;
        ctx.lineWidth = brushSize;
      }
    }
  };

  const handleMove = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);

    if (currentTool === 'select' && selectedObjectId) {
      const obj = objects.find(o => o.id === selectedObjectId);
      if (!obj) return;

      if (isDragging) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, x: pos.x - dragOffset.x, y: pos.y - dragOffset.y }
            : o
        ));
      } else if (isResizing) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, width: Math.max(10, pos.x - o.x), height: Math.max(10, pos.y - o.y) }
            : o
        ));
      } else if (isRotating) {
        const centerX = obj.x + obj.width / 2;
        const centerY = obj.y + obj.height / 2;
        const angle = Math.atan2(pos.y - centerY, pos.x - centerX) + Math.PI / 2;
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId ? { ...o, rotation: angle } : o
        ));
      }
      return;
    }

    if (!isDrawing) return;

    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection(prev => prev ? { ...prev, x2: pos.x, y2: pos.y } : null);
    } else if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.lineTo(pos.x, pos.y);
        ctx.stroke();
      }
    }
  };

  const handleEnd = (e: React.MouseEvent | React.TouchEvent) => {
    if (currentTool === 'select') {
      if (isDragging || isResizing || isRotating) {
        saveToHistory(objects);
      }
      setIsDragging(false);
      setIsResizing(false);
      setIsRotating(false);
      return;
    }

    if (!isDrawing) return;
    setIsDrawing(false);

    const pos = getMousePos(e);

    if (['rect', 'circle', 'line'].includes(currentTool)) {
      const newObj: EditorObject = {
        id: crypto.randomUUID(),
        type: currentTool as any,
        x: Math.min(startPos.x, pos.x),
        y: Math.min(startPos.y, pos.y),
        width: Math.abs(startPos.x - pos.x),
        height: Math.abs(startPos.y - pos.y),
        rotation: 0,
        stroke: strokeColor,
        fill: fillColor,
        strokeWidth: brushSize
      };
      const nextObjects = [...objects, newObj];
      setObjects(nextObjects);
      setSelectedObjectId(newObj.id);
      setCurrentTool('select');
      setSelection(null);
      saveToHistory(nextObjects);
    } else if (currentTool === 'text') {
      const text = window.prompt(uiLang === 'zh' ? "输入文字:" : "Enter text:");
      if (text) {
        const newObj: EditorObject = {
          id: crypto.randomUUID(),
          type: 'text',
          x: pos.x,
          y: pos.y,
          width: text.length * brushSize * 3,
          height: brushSize * 6,
          rotation: 0,
          stroke: strokeColor,
          fill: fillColor,
          strokeWidth: brushSize,
          text: text
        };
        const nextObjects = [...objects, newObj];
        setObjects(nextObjects);
        setSelectedObjectId(newObj.id);
        setCurrentTool('select');
        saveToHistory(nextObjects);
      }
    } else if (currentTool === 'brush') {
      saveToHistory();
    }
  };

  const handleFill = () => {
    if (currentTool !== 'select-fill' || !selection) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    ctx.fillStyle = fillColor;
    ctx.fillRect(x, y, w, h);
    saveToHistory();
    setSelection(null); 
  };

  const handleCrop = () => {
    if (!selection) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    if (w < 5 || h < 5) return;
    const imageData = ctx.getImageData(x, y, w, h);
    canvas.width = w;
    canvas.height = h;
    ctx.putImageData(imageData, 0, 0);
    saveToHistory();
    setSelection(null);
    setZoom(1);
  };

  const runAIErase = async () => {
    setIsProcessing(true);
    try {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const base64 = canvas.toDataURL('image/jpeg', 0.9).split(',')[1];
      const result = await editImageWithAI(base64, "Please erase the red highlighted areas cleanly.");
      const img = new Image();
      img.src = `data:image/jpeg;base64,${result}`;
      img.onload = () => {
        const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        saveToHistory();
        setIsProcessing(false);
      };
    } catch (e: any) {
      alert("AI Erase failed: " + e.message);
      setIsProcessing(false);
    }
  };

  const handleFinalSave = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    objects.forEach(obj => {
      ctx.save();
      const cx = obj.x + obj.width / 2;
      const cy = obj.y + obj.height / 2;

      ctx.translate(cx, cy);
      ctx.rotate(obj.rotation);
      ctx.translate(-cx, -cy);

      ctx.strokeStyle = obj.stroke;
      ctx.fillStyle = obj.fill;
      ctx.lineWidth = obj.strokeWidth;
      ctx.lineCap = 'round';

      if (obj.type === 'rect') {
        ctx.beginPath();
        ctx.rect(obj.x, obj.y, obj.width, obj.height);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'circle') {
        const r = Math.sqrt(obj.width * obj.width + obj.height * obj.height) / 2;
        ctx.beginPath();
        ctx.arc(obj.x + obj.width/2, obj.y + obj.height/2, r, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'line') {
        ctx.beginPath();
        ctx.moveTo(obj.x, obj.y);
        ctx.lineTo(obj.x + obj.width, obj.y + obj.height);
        ctx.stroke();
      } else if (obj.type === 'text' && obj.text) {
        ctx.font = `bold ${obj.strokeWidth * 6}px Inter, sans-serif`;
        ctx.fillText(obj.text, obj.x, obj.y);
        ctx.strokeText(obj.text, obj.x, obj.y);
      }
      ctx.restore();
    });

    onSave(canvas.toDataURL('image/jpeg', 0.95));
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedObjectId) {
        const nextObjects = objects.filter(o => o.id !== selectedObjectId);
        setObjects(nextObjects);
        setSelectedObjectId(null);
        saveToHistory(nextObjects);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedObjectId, objects, saveToHistory]);

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col font-inter">
      <div className="h-16 bg-slate-900 border-b border-slate-800 px-6 flex items-center justify-between text-white shadow-xl z-20">
        <div className="flex items-center gap-6">
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-all"><X size={20} /></button>
          <div className="h-6 w-px bg-slate-800"></div>
          <h2 className="font-black tracking-tighter text-xl bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent uppercase">AI Media Lab</h2>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex bg-slate-800 p-1 rounded-xl">
            <button onClick={() => setZoom(prev => Math.max(0.05, prev - 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomOut size={16} /></button>
            <span className="px-3 flex items-center text-[10px] font-black text-slate-300 w-16 justify-center">{(zoom * 100).toFixed(0)}%</span>
            <button onClick={() => setZoom(prev => Math.min(5, prev + 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomIn size={16} /></button>
          </div>
          <button onClick={undo} disabled={history.length <= 1} className="p-2.5 bg-slate-800 hover:bg-slate-700 disabled:opacity-30 rounded-xl text-slate-300 transition-all"><Undo size={18} /></button>
          <button onClick={standardize} className="px-5 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-black flex items-center gap-2 border border-slate-700"><Maximize size={16} /> 1600*1600</button>
          <button onClick={handleFinalSave} className="px-8 py-2.5 bg-indigo-600 hover:bg-indigo-700 rounded-xl text-xs font-black shadow-lg flex items-center gap-2 transform active:scale-95 transition-all"><Save size={16} /> Save & Apply</button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className="w-24 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-6 z-20 overflow-y-auto no-scrollbar">
          <ToolIcon active={currentTool === 'select'} onClick={() => { setCurrentTool('select'); }} icon={<MousePointer2 size={20} />} label="Select" />
          <ToolIcon active={currentTool === 'brush'} onClick={() => { setCurrentTool('brush'); setSelectedObjectId(null); }} icon={<Palette size={20} />} label="Brush" />
          <ToolIcon active={currentTool === 'ai-erase'} onClick={() => { setCurrentTool('ai-erase'); setSelectedObjectId(null); }} icon={<Eraser size={20} />} label="AI Erase" />
          <ToolIcon active={currentTool === 'rect'} onClick={() => { setCurrentTool('rect'); setSelectedObjectId(null); }} icon={<Square size={20} />} label="Rect" />
          <ToolIcon active={currentTool === 'circle'} onClick={() => { setCurrentTool('circle'); setSelectedObjectId(null); }} icon={<Circle size={20} />} label="Circle" />
          <ToolIcon active={currentTool === 'line'} onClick={() => { setCurrentTool('line'); setSelectedObjectId(null); }} icon={<Minus size={20} />} label="Line" />
          <ToolIcon active={currentTool === 'text'} onClick={() => { setCurrentTool('text'); setSelectedObjectId(null); }} icon={<Type size={20} />} label="Text" />
          <ToolIcon active={currentTool === 'select-fill'} onClick={() => { setCurrentTool('select-fill'); setSelectedObjectId(null); }} icon={<PaintBucket size={20} />} label="Fill" />
          <ToolIcon active={currentTool === 'crop'} onClick={() => { setCurrentTool('crop'); setSelectedObjectId(null); }} icon={<Scissors size={20} />} label="Crop" />

          <div className="mt-auto flex flex-col gap-4 pb-4">
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Stroke</span>
               <input type="color" value={strokeColor} onChange={(e) => setStrokeColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Fill</span>
               <input type="color" value={fillColor} onChange={(e) => setFillColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
          </div>
        </div>

        <div ref={containerRef} className="flex-1 bg-slate-950 overflow-auto flex items-center justify-center p-20 relative">
          <div className="relative shadow-2xl transition-transform duration-75 origin-center" style={{ transform: `scale(${zoom})` }}>
            <canvas ref={canvasRef} onMouseDown={handleStart} onMouseMove={handleMove} onMouseUp={handleEnd} className="block relative" style={{ cursor: currentTool === 'none' ? 'default' : currentTool === 'select' ? 'default' : 'crosshair' }} />

            <svg 
              className="absolute inset-0 pointer-events-none w-full h-full"
              viewBox={`0 0 ${canvasRef.current?.width || 0} ${canvasRef.current?.height || 0}`}
            >
              {objects.map(obj => (
                <g 
                  key={obj.id} 
                  className={selectedObjectId === obj.id ? 'opacity-100' : 'opacity-80'}
                  transform={`rotate(${(obj.rotation * 180) / Math.PI} ${obj.x + obj.width / 2} ${obj.y + obj.height / 2})`}
                >
                  {obj.type === 'rect' && <rect x={obj.x} y={obj.y} width={obj.width} height={obj.height} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'circle' && <ellipse cx={obj.x + obj.width/2} cy={obj.y + obj.height/2} rx={obj.width/2} ry={obj.height/2} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'line' && <line x1={obj.x} y1={obj.y} x2={obj.x + obj.width} y2={obj.y + obj.height} stroke={obj.stroke} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'text' && (
                    <text 
                      x={obj.x} 
                      y={obj.y + obj.height/2} 
                      fill={obj.fill} 
                      stroke={obj.stroke} 
                      strokeWidth={obj.strokeWidth/4} 
                      style={{ font: `bold ${obj.strokeWidth * 6}px Inter, sans-serif` }}
                    >
                      {obj.text}
                    </text>
                  )}
                  {selectedObjectId === obj.id && (
                    <>
                      <rect 
                        x={obj.x} y={obj.y} width={obj.width} height={obj.height} 
                        fill="none" stroke="#6366f1" strokeWidth={2 / zoom} strokeDasharray="4"
                      />
                      {/* Resize handle */}
                      <circle 
                        cx={obj.x + obj.width} cy={obj.y + obj.height} r={6 / zoom} 
                        fill="#6366f1" className="cursor-nwse-resize pointer-events-auto" 
                      />
                      {/* Rotation handle */}
                      <line x1={obj.x + obj.width/2} y1={obj.y} x2={obj.x + obj.width/2} y2={obj.y - 30/zoom} stroke="#6366f1" strokeWidth={2/zoom} />
                      <circle 
                        cx={obj.x + obj.width/2} cy={obj.y - 30/zoom} r={8 / zoom} 
                        fill="#6366f1" className="cursor-pointer pointer-events-auto"
                      >
                         <title>Rotate</title>
                      </circle>
                    </>
                  )}
                </g>
              ))}
            </svg>

            {selection && (['select-fill', 'crop'].includes(currentTool)) && (
               <div className="absolute pointer-events-none border-2 border-white" style={{ left: Math.min(selection.x1, selection.x2), top: Math.min(selection.y1, selection.y2), width: Math.abs(selection.x1 - selection.x2), height: Math.abs(selection.y1 - selection.y2) }}>
                 <div className="absolute inset-0 border-2 border-dashed border-black/50 animate-pulse"></div>
               </div>
            )}
          </div>

          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-8 bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-4 rounded-3xl shadow-2xl z-30 min-w-[500px]">
             <div className="flex flex-col gap-1 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase">Size / Stroke Width</span>
                 <span className="text-[10px] font-black text-blue-400">{brushSize}px</span>
               </div>
               <input type="range" min="1" max="100" value={brushSize} onChange={(e) => setBrushSize(parseInt(e.target.value))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500" />
             </div>

             {currentTool === 'ai-erase' && (
               <button onClick={runAIErase} disabled={isProcessing} className="px-8 py-3 bg-red-600 hover:bg-red-700 text-white rounded-2xl text-xs font-black shadow-xl flex items-center gap-3 transition-all active:scale-95 disabled:opacity-50">
                 {isProcessing ? <Loader2 className="animate-spin" size={16} /> : <Wand2 size={16} />} AI ERASE
               </button>
             )}
             {currentTool === 'select-fill' && (
               <button onClick={handleFill} disabled={!selection} className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">FILL AREA</button>
             )}
             {currentTool === 'crop' && (
               <button onClick={handleCrop} disabled={!selection} className="px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">CONFIRM CROP</button>
             )}
             {['select', 'rect', 'circle', 'line', 'text', 'brush', 'none'].includes(currentTool) && currentTool !== 'ai-erase' && (
                <div className="px-10 text-[10px] font-black text-slate-500 uppercase tracking-widest">
                  {currentTool === 'select' ? (selectedObjectId ? 'Object Selected (Drag top circle to rotate)' : 'Select an object') : `${currentTool} tool active`}
                </div>
             )}
          </div>

          {isProcessing && <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/70 backdrop-blur-md"><Loader2 size={40} className="text-indigo-500 animate-spin" /><p className="mt-8 text-white font-black tracking-[0.3em] text-sm uppercase">AI Processing...</p></div>}
        </div>
      </div>
    </div>
  );
};

const ToolIcon = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1.5 group transition-all shrink-0 ${active ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>
    <div className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${active ? 'bg-indigo-600/10 border border-indigo-500/50 shadow-lg' : 'bg-slate-800/50 hover:bg-slate-800'}`}>
      {icon}
    </div>
    <span className="text-[8px] font-black uppercase tracking-tighter">{label}</span>
  </button>
);

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  X, Eraser, Scissors, PaintBucket, Crop, Save, Undo, 
  Wand2, Loader2, Download, MousePointer2, Maximize, 
  Type, Square, Circle, Minus, Move, Palette, Trash2,
  ZoomIn, ZoomOut, RotateCcw, Box, ArrowUpRight, RefreshCw
} from 'lucide-react';
import { editImageWithAI } from '../services/geminiService';
// Import UILanguage to fix type missing
import { UILanguage } from '../types';

interface ImageEditorProps {
  imageUrl: string;
  onClose: () => void;
  onSave: (newImageUrl: string) => void;
  // Add uiLang prop to interface
  uiLang: UILanguage;
}

type Tool = 'select' | 'select-fill' | 'brush' | 'ai-erase' | 'crop' | 'rect' | 'circle' | 'line' | 'text' | 'none';

interface EditorObject {
  id: string;
  type: 'rect' | 'circle' | 'line' | 'text';
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number; // In radians
  stroke: string;
  fill: string;
  strokeWidth: number;
  text?: string;
}

interface EditorState {
  canvasData: string;
  objects: EditorObject[];
}

interface SelectionBox {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
}

const CORS_PROXY = 'https://corsproxy.io/?';

// Destructure uiLang from props
export const ImageEditor: React.FC<ImageEditorProps> = ({ imageUrl, onClose, onSave, uiLang }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [currentTool, setCurrentTool] = useState<Tool>('select');
  const [isProcessing, setIsProcessing] = useState(false);
  const [strokeColor, setStrokeColor] = useState('#000000');
  const [fillColor, setFillColor] = useState('#ffffff');
  const [brushSize, setBrushSize] = useState(5);
  const [zoom, setZoom] = useState(1);

  // Object system
  const [objects, setObjects] = useState<EditorObject[]>([]);
  const [selectedObjectId, setSelectedObjectId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [isRotating, setIsRotating] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const [isDrawing, setIsDrawing] = useState(false);
  const [selection, setSelection] = useState<SelectionBox | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });

  // Unified History System
  const [history, setHistory] = useState<EditorState[]>([]);

  const saveToHistory = useCallback((currentObjects?: EditorObject[]) => {
    const canvas = canvasRef.current;
    if (canvas) {
      const newState: EditorState = {
        canvasData: canvas.toDataURL('image/png'),
        objects: currentObjects ? [...currentObjects] : [...objects]
      };
      setHistory(prev => [...prev.slice(-30), newState]);
    }
  }, [objects]);

  useEffect(() => {
    const initCanvas = async () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d', { willReadFrequently: true }) as CanvasRenderingContext2D | null;
      if (!ctx) return;

      setIsProcessing(true);
      try {
        const proxyUrl = `${CORS_PROXY}${encodeURIComponent(imageUrl)}`;
        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error("Failed to fetch image through proxy");
        const blob = await response.blob();
        const localUrl = URL.createObjectURL(blob);

        const img = new Image();
        img.src = localUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);

          if (containerRef.current) {
            const padding = 120;
            const availableW = containerRef.current.clientWidth - padding;
            const availableH = containerRef.current.clientHeight - padding;
            const scale = Math.min(availableW / img.width, availableH / img.height, 1);
            setZoom(scale || 1);
          }

          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
          URL.revokeObjectURL(localUrl);
        };
      } catch (err) {
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.src = imageUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          (ctx as CanvasRenderingContext2D).drawImage(img, 0, 0);
          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
        };
      }
    };
    initCanvas();
  }, [imageUrl]);

  const undo = () => {
    if (history.length <= 1) return;
    const newHistory = [...history];
    newHistory.pop(); 
    const prevState = newHistory[newHistory.length - 1];

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (canvas && ctx && prevState) {
      const img = new Image();
      img.src = prevState.canvasData;
      img.onload = () => {
        canvas.width = img.width;
        canvas.height = img.height;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        setObjects(prevState.objects);
        setHistory(newHistory);
      };
    }
  };

  const standardize = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const currentData = canvas.toDataURL();
    const tempImg = new Image();
    tempImg.src = currentData;
    tempImg.onload = () => {
      const targetSize = 1600;
      const safeArea = 1500;
      canvas.width = targetSize;
      canvas.height = targetSize;
      const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, targetSize, targetSize);
      const scale = Math.min(safeArea / tempImg.width, safeArea / tempImg.height);
      const drawW = tempImg.width * scale;
      const drawH = tempImg.height * scale;
      const x = (targetSize - drawW) / 2;
      const y = (targetSize - drawH) / 2;
      ctx.drawImage(tempImg, x, y, drawW, drawH);
      saveToHistory();
      if (containerRef.current) {
        setZoom(Math.min((containerRef.current.clientHeight - 120) / 1600, 1));
      }
    };
  };

  const getMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }
    return {
      x: (clientX - rect.left) / zoom,
      y: (clientY - rect.top) / zoom
    };
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);
    setStartPos(pos);

    if (currentTool === 'select') {
      if (selectedObjectId) {
        const obj = objects.find(o => o.id === selectedObjectId);
        if (obj) {
          const handleSize = 12 / zoom;
          const rotateHandleY = obj.y - 30 / zoom;
          const centerX = obj.x + obj.width / 2;

          // Basic hit test for rotation handle
          const distToRotate = Math.sqrt(Math.pow(pos.x - centerX, 2) + Math.pow(pos.y - rotateHandleY, 2));
          if (distToRotate < handleSize) {
            setIsRotating(true);
            return;
          }

          const isOverResizeHandle = 
            pos.x >= obj.x + obj.width - handleSize && 
            pos.x <= obj.x + obj.width + handleSize && 
            pos.y >= obj.y + obj.height - handleSize && 
            pos.y <= obj.y + obj.height + handleSize;

          if (isOverResizeHandle) {
            setIsResizing(true);
            return;
          }

          const isOverBody = 
            pos.x >= obj.x && pos.x <= obj.x + obj.width &&
            pos.y >= obj.y && pos.y <= obj.y + obj.height;

          if (isOverBody) {
            setIsDragging(true);
            setDragOffset({ x: pos.x - obj.x, y: pos.y - obj.y });
            return;
          }
        }
      }

      const hit = objects.slice().reverse().find(obj => 
        pos.x >= obj.x && pos.x <= obj.x + obj.width &&
        pos.y >= obj.y && pos.y <= obj.y + obj.height
      );

      if (hit) {
        setSelectedObjectId(hit.id);
        setIsDragging(true);
        setDragOffset({ x: pos.x - hit.x, y: pos.y - hit.y });
      } else {
        setSelectedObjectId(null);
      }
      return;
    }

    setIsDrawing(true);
    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection({ x1: pos.x, y1: pos.y, x2: pos.x, y2: pos.y });
    }

    if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.beginPath();
        ctx.moveTo(pos.x, pos.y);
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.strokeStyle = currentTool === 'ai-erase' ? 'rgba(255, 0, 0, 0.6)' : strokeColor;
        ctx.lineWidth = brushSize;
      }
    }
  };

  const handleMove = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);

    if (currentTool === 'select' && selectedObjectId) {
      const obj = objects.find(o => o.id === selectedObjectId);
      if (!obj) return;

      if (isDragging) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, x: pos.x - dragOffset.x, y: pos.y - dragOffset.y }
            : o
        ));
      } else if (isResizing) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, width: Math.max(10, pos.x - o.x), height: Math.max(10, pos.y - o.y) }
            : o
        ));
      } else if (isRotating) {
        const centerX = obj.x + obj.width / 2;
        const centerY = obj.y + obj.height / 2;
        const angle = Math.atan2(pos.y - centerY, pos.x - centerX) + Math.PI / 2;
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId ? { ...o, rotation: angle } : o
        ));
      }
      return;
    }

    if (!isDrawing) return;

    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection(prev => prev ? { ...prev, x2: pos.x, y2: pos.y } : null);
    } else if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.lineTo(pos.x, pos.y);
        ctx.stroke();
      }
    }
  };

  const handleEnd = (e: React.MouseEvent | React.TouchEvent) => {
    if (currentTool === 'select') {
      if (isDragging || isResizing || isRotating) {
        saveToHistory(objects);
      }
      setIsDragging(false);
      setIsResizing(false);
      setIsRotating(false);
      return;
    }

    if (!isDrawing) return;
    setIsDrawing(false);

    const pos = getMousePos(e);

    if (['rect', 'circle', 'line'].includes(currentTool)) {
      const newObj: EditorObject = {
        id: crypto.randomUUID(),
        type: currentTool as any,
        x: Math.min(startPos.x, pos.x),
        y: Math.min(startPos.y, pos.y),
        width: Math.abs(startPos.x - pos.x),
        height: Math.abs(startPos.y - pos.y),
        rotation: 0,
        stroke: strokeColor,
        fill: fillColor,
        strokeWidth: brushSize
      };
      const nextObjects = [...objects, newObj];
      setObjects(nextObjects);
      setSelectedObjectId(newObj.id);
      setCurrentTool('select');
      setSelection(null);
      saveToHistory(nextObjects);
    } else if (currentTool === 'text') {
      const text = window.prompt(uiLang === 'zh' ? "输入文字:" : "Enter text:");
      if (text) {
        const newObj: EditorObject = {
          id: crypto.randomUUID(),
          type: 'text',
          x: pos.x,
          y: pos.y,
          width: text.length * brushSize * 3,
          height: brushSize * 6,
          rotation: 0,
          stroke: strokeColor,
          fill: fillColor,
          strokeWidth: brushSize,
          text: text
        };
        const nextObjects = [...objects, newObj];
        setObjects(nextObjects);
        setSelectedObjectId(newObj.id);
        setCurrentTool('select');
        saveToHistory(nextObjects);
      }
    } else if (currentTool === 'brush') {
      saveToHistory();
    }
  };

  const handleFill = () => {
    if (currentTool !== 'select-fill' || !selection) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    ctx.fillStyle = fillColor;
    ctx.fillRect(x, y, w, h);
    saveToHistory();
    setSelection(null); 
  };

  const handleCrop = () => {
    if (!selection) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    if (w < 5 || h < 5) return;
    const imageData = ctx.getImageData(x, y, w, h);
    canvas.width = w;
    canvas.height = h;
    ctx.putImageData(imageData, 0, 0);
    saveToHistory();
    setSelection(null);
    setZoom(1);
  };

  const runAIErase = async () => {
    setIsProcessing(true);
    try {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const base64 = canvas.toDataURL('image/jpeg', 0.9).split(',')[1];
      const result = await editImageWithAI(base64, "Please erase the red highlighted areas cleanly.");
      const img = new Image();
      img.src = `data:image/jpeg;base64,${result}`;
      img.onload = () => {
        const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        saveToHistory();
        setIsProcessing(false);
      };
    } catch (e: any) {
      alert("AI Erase failed: " + e.message);
      setIsProcessing(false);
    }
  };

  const handleFinalSave = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    objects.forEach(obj => {
      ctx.save();
      const cx = obj.x + obj.width / 2;
      const cy = obj.y + obj.height / 2;

      ctx.translate(cx, cy);
      ctx.rotate(obj.rotation);
      ctx.translate(-cx, -cy);

      ctx.strokeStyle = obj.stroke;
      ctx.fillStyle = obj.fill;
      ctx.lineWidth = obj.strokeWidth;
      ctx.lineCap = 'round';

      if (obj.type === 'rect') {
        ctx.beginPath();
        ctx.rect(obj.x, obj.y, obj.width, obj.height);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'circle') {
        const r = Math.sqrt(obj.width * obj.width + obj.height * obj.height) / 2;
        ctx.beginPath();
        ctx.arc(obj.x + obj.width/2, obj.y + obj.height/2, r, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'line') {
        ctx.beginPath();
        ctx.moveTo(obj.x, obj.y);
        ctx.lineTo(obj.x + obj.width, obj.y + obj.height);
        ctx.stroke();
      } else if (obj.type === 'text' && obj.text) {
        ctx.font = `bold ${obj.strokeWidth * 6}px Inter, sans-serif`;
        ctx.fillText(obj.text, obj.x, obj.y);
        ctx.strokeText(obj.text, obj.x, obj.y);
      }
      ctx.restore();
    });

    onSave(canvas.toDataURL('image/jpeg', 0.95));
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedObjectId) {
        const nextObjects = objects.filter(o => o.id !== selectedObjectId);
        setObjects(nextObjects);
        setSelectedObjectId(null);
        saveToHistory(nextObjects);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedObjectId, objects, saveToHistory]);

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col font-inter">
      <div className="h-16 bg-slate-900 border-b border-slate-800 px-6 flex items-center justify-between text-white shadow-xl z-20">
        <div className="flex items-center gap-6">
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-all"><X size={20} /></button>
          <div className="h-6 w-px bg-slate-800"></div>
          <h2 className="font-black tracking-tighter text-xl bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent uppercase">AI Media Lab</h2>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex bg-slate-800 p-1 rounded-xl">
            <button onClick={() => setZoom(prev => Math.max(0.05, prev - 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomOut size={16} /></button>
            <span className="px-3 flex items-center text-[10px] font-black text-slate-300 w-16 justify-center">{(zoom * 100).toFixed(0)}%</span>
            <button onClick={() => setZoom(prev => Math.min(5, prev + 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomIn size={16} /></button>
          </div>
          <button onClick={undo} disabled={history.length <= 1} className="p-2.5 bg-slate-800 hover:bg-slate-700 disabled:opacity-30 rounded-xl text-slate-300 transition-all"><Undo size={18} /></button>
          <button onClick={standardize} className="px-5 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-black flex items-center gap-2 border border-slate-700"><Maximize size={16} /> 1600*1600</button>
          <button onClick={handleFinalSave} className="px-8 py-2.5 bg-indigo-600 hover:bg-indigo-700 rounded-xl text-xs font-black shadow-lg flex items-center gap-2 transform active:scale-95 transition-all"><Save size={16} /> Save & Apply</button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className="w-24 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-6 z-20 overflow-y-auto no-scrollbar">
          <ToolIcon active={currentTool === 'select'} onClick={() => { setCurrentTool('select'); }} icon={<MousePointer2 size={20} />} label="Select" />
          <ToolIcon active={currentTool === 'brush'} onClick={() => { setCurrentTool('brush'); setSelectedObjectId(null); }} icon={<Palette size={20} />} label="Brush" />
          <ToolIcon active={currentTool === 'ai-erase'} onClick={() => { setCurrentTool('ai-erase'); setSelectedObjectId(null); }} icon={<Eraser size={20} />} label="AI Erase" />
          <ToolIcon active={currentTool === 'rect'} onClick={() => { setCurrentTool('rect'); setSelectedObjectId(null); }} icon={<Square size={20} />} label="Rect" />
          <ToolIcon active={currentTool === 'circle'} onClick={() => { setCurrentTool('circle'); setSelectedObjectId(null); }} icon={<Circle size={20} />} label="Circle" />
          <ToolIcon active={currentTool === 'line'} onClick={() => { setCurrentTool('line'); setSelectedObjectId(null); }} icon={<Minus size={20} />} label="Line" />
          <ToolIcon active={currentTool === 'text'} onClick={() => { setCurrentTool('text'); setSelectedObjectId(null); }} icon={<Type size={20} />} label="Text" />
          <ToolIcon active={currentTool === 'select-fill'} onClick={() => { setCurrentTool('select-fill'); setSelectedObjectId(null); }} icon={<PaintBucket size={20} />} label="Fill" />
          <ToolIcon active={currentTool === 'crop'} onClick={() => { setCurrentTool('crop'); setSelectedObjectId(null); }} icon={<Scissors size={20} />} label="Crop" />

          <div className="mt-auto flex flex-col gap-4 pb-4">
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Stroke</span>
               <input type="color" value={strokeColor} onChange={(e) => setStrokeColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Fill</span>
               <input type="color" value={fillColor} onChange={(e) => setFillColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
          </div>
        </div>

        <div ref={containerRef} className="flex-1 bg-slate-950 overflow-auto flex items-center justify-center p-20 relative">
          <div className="relative shadow-2xl transition-transform duration-75 origin-center" style={{ transform: `scale(${zoom})` }}>
            <canvas ref={canvasRef} onMouseDown={handleStart} onMouseMove={handleMove} onMouseUp={handleEnd} className="block relative" style={{ cursor: currentTool === 'none' ? 'default' : currentTool === 'select' ? 'default' : 'crosshair' }} />

            <svg 
              className="absolute inset-0 pointer-events-none w-full h-full"
              viewBox={`0 0 ${canvasRef.current?.width || 0} ${canvasRef.current?.height || 0}`}
            >
              {objects.map(obj => (
                <g 
                  key={obj.id} 
                  className={selectedObjectId === obj.id ? 'opacity-100' : 'opacity-80'}
                  transform={`rotate(${(obj.rotation * 180) / Math.PI} ${obj.x + obj.width / 2} ${obj.y + obj.height / 2})`}
                >
                  {obj.type === 'rect' && <rect x={obj.x} y={obj.y} width={obj.width} height={obj.height} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'circle' && <ellipse cx={obj.x + obj.width/2} cy={obj.y + obj.height/2} rx={obj.width/2} ry={obj.height/2} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'line' && <line x1={obj.x} y1={obj.y} x2={obj.x + obj.width} y2={obj.y + obj.height} stroke={obj.stroke} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'text' && (
                    <text 
                      x={obj.x} 
                      y={obj.y + obj.height/2} 
                      fill={obj.fill} 
                      stroke={obj.stroke} 
                      strokeWidth={obj.strokeWidth/4} 
                      style={{ font: `bold ${obj.strokeWidth * 6}px Inter, sans-serif` }}
                    >
                      {obj.text}
                    </text>
                  )}
                  {selectedObjectId === obj.id && (
                    <>
                      <rect 
                        x={obj.x} y={obj.y} width={obj.width} height={obj.height} 
                        fill="none" stroke="#6366f1" strokeWidth={2 / zoom} strokeDasharray="4"
                      />
                      {/* Resize handle */}
                      <circle 
                        cx={obj.x + obj.width} cy={obj.y + obj.height} r={6 / zoom} 
                        fill="#6366f1" className="cursor-nwse-resize pointer-events-auto" 
                      />
                      {/* Rotation handle */}
                      <line x1={obj.x + obj.width/2} y1={obj.y} x2={obj.x + obj.width/2} y2={obj.y - 30/zoom} stroke="#6366f1" strokeWidth={2/zoom} />
                      <circle 
                        cx={obj.x + obj.width/2} cy={obj.y - 30/zoom} r={8 / zoom} 
                        fill="#6366f1" className="cursor-pointer pointer-events-auto"
                      >
                         <title>Rotate</title>
                      </circle>
                    </>
                  )}
                </g>
              ))}
            </svg>

            {selection && (['select-fill', 'crop'].includes(currentTool)) && (
               <div className="absolute pointer-events-none border-2 border-white" style={{ left: Math.min(selection.x1, selection.x2), top: Math.min(selection.y1, selection.y2), width: Math.abs(selection.x1 - selection.x2), height: Math.abs(selection.y1 - selection.y2) }}>
                 <div className="absolute inset-0 border-2 border-dashed border-black/50 animate-pulse"></div>
               </div>
            )}
          </div>

          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-8 bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-4 rounded-3xl shadow-2xl z-30 min-w-[500px]">
             <div className="flex flex-col gap-1 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase">Size / Stroke Width</span>
                 <span className="text-[10px] font-black text-blue-400">{brushSize}px</span>
               </div>
               <input type="range" min="1" max="100" value={brushSize} onChange={(e) => setBrushSize(parseInt(e.target.value))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500" />
             </div>

             {currentTool === 'ai-erase' && (
               <button onClick={runAIErase} disabled={isProcessing} className="px-8 py-3 bg-red-600 hover:bg-red-700 text-white rounded-2xl text-xs font-black shadow-xl flex items-center gap-3 transition-all active:scale-95 disabled:opacity-50">
                 {isProcessing ? <Loader2 className="animate-spin" size={16} /> : <Wand2 size={16} />} AI ERASE
               </button>
             )}
             {currentTool === 'select-fill' && (
               <button onClick={handleFill} disabled={!selection} className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">FILL AREA</button>
             )}
             {currentTool === 'crop' && (
               <button onClick={handleCrop} disabled={!selection} className="px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">CONFIRM CROP</button>
             )}
             {['select', 'rect', 'circle', 'line', 'text', 'brush', 'none'].includes(currentTool) && currentTool !== 'ai-erase' && (
                <div className="px-10 text-[10px] font-black text-slate-500 uppercase tracking-widest">
                  {currentTool === 'select' ? (selectedObjectId ? 'Object Selected (Drag top circle to rotate)' : 'Select an object') : `${currentTool} tool active`}
                </div>
             )}
          </div>

          {isProcessing && <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/70 backdrop-blur-md"><Loader2 size={40} className="text-indigo-500 animate-spin" /><p className="mt-8 text-white font-black tracking-[0.3em] text-sm uppercase">AI Processing...</p></div>}
        </div>
      </div>
    </div>
  );
};

const ToolIcon = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1.5 group transition-all shrink-0 ${active ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>
    <div className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${active ? 'bg-indigo-600/10 border border-indigo-500/50 shadow-lg' : 'bg-slate-800/50 hover:bg-slate-800'}`}>
      {icon}
    </div>
    <span className="text-[8px] font-black uppercase tracking-tighter">{label}</span>
  </button>
);

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { 
  ArrowLeft, Sparkles, Image as ImageIcon, Edit2, Trash2, Plus, X,
  Globe, Languages, Loader2, DollarSign, Truck, Save, ChevronRight,
  Zap, Check, Weight, Ruler, ListFilter, FileText, Wand2, Search, 
  ExternalLink, Link2, Star, Maximize2, Hash, Cpu, Brain, AlertTriangle, Upload, Box
} from 'lucide-react';
import { Listing, OptimizedData, CleanedData, UILanguage, ExchangeRate, SourcingRecord } from '../types';
import { optimizeListingWithAI, translateListingWithAI } from '../services/geminiService';
import { optimizeListingWithOpenAI, translateListingWithOpenAI } from '../services/openaiService';
import { optimizeListingWithDeepSeek, translateListingWithDeepSeek } from '../services/deepseekService';
import { ImageEditor } from './ImageEditor';
import { SourcingModal } from './SourcingModal';
import { SourcingFormModal } from './SourcingFormModal';
import { supabase, isSupabaseConfigured } from '../lib/supabaseClient';
import { useTranslation } from '../lib/i18n';
import { AMAZON_MARKETPLACES } from '../lib/marketplaces';

interface ListingDetailProps {
  listing: Listing;
  onBack: () => void;
  onUpdate: (updatedListing: Listing) => void;
  onNext: () => void;
  uiLang: UILanguage;
}

type AIEngine = 'gemini' | 'openai' | 'deepseek';

const IMAGE_HOST_DOMAIN = 'https://img.hmstu.eu.org';
const CORS_PROXY = 'https://corsproxy.io/?';

export const ListingDetail: React.FC<ListingDetailProps> = ({ listing, onBack, onUpdate, onNext, uiLang }) => {
  const t = useTranslation(uiLang);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [activeMarket, setActiveMarket] = useState('US');

  // Persistent AI Engine Selection
  const [engine, setEngine] = useState<AIEngine>(() => {
    const saved = localStorage.getItem('amzbot_preferred_engine');
    return (saved as AIEngine) || 'gemini';
  });

  useEffect(() => {
    localStorage.setItem('amzbot_preferred_engine', engine);
  }, [engine]);

  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isTranslating, setIsTranslating] = useState(false);
  const [isBatchTranslating, setIsBatchTranslating] = useState(false);
  const [isStandardizing, setIsStandardizing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [lastSaved, setLastSaved] = useState<string | null>(null);

  const [showImageEditor, setShowImageEditor] = useState(false);
  const [showSourcingModal, setShowSourcingModal] = useState(false);
  const [showSourcingForm, setShowSourcingForm] = useState<{show: boolean, data: SourcingRecord | null}>({show: false, data: null});

  const [localListing, setLocalListing] = useState<Listing>(listing);
  const [previewImage, setPreviewImage] = useState<string>(listing.cleaned?.main_image || '');
  const [exchangeRates, setExchangeRates] = useState<ExchangeRate[]>([]);

  useEffect(() => {
    setLocalListing(listing);
    setPreviewImage(listing.cleaned?.main_image || '');
    setActiveMarket('US');
    fetchPricingData();
  }, [listing]);

  const fetchPricingData = async () => {
    if (!isSupabaseConfigured()) return;
    const { data } = await supabase.from('exchange_rates').select('*');
    if (data) setExchangeRates(data);
  };

  const syncToSupabase = async (targetListing: Listing) => {
    if (!isSupabaseConfigured()) return;
    setIsSaving(true);
    try {
      const { error } = await supabase.from('listings').update({
        cleaned: targetListing.cleaned,
        optimized: targetListing.optimized || null,
        translations: targetListing.translations || null,
        status: targetListing.status,
        sourcing_data: targetListing.sourcing_data || [],
        updated_at: new Date().toISOString()
      }).eq('id', targetListing.id);
      if (error) throw error;
      onUpdate({ ...targetListing, updated_at: new Date().toISOString() });
      setLastSaved(new Date().toLocaleTimeString());
    } catch (e: any) { console.error("Save failed:", e); } 
    finally { setIsSaving(false); }
  };

  // Image Utilities
  const processImageStandardization = async (url: string): Promise<string> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = `${CORS_PROXY}${encodeURIComponent(url)}`;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 1600;
        canvas.height = 1600;
        const ctx = canvas.getContext('2d');
        if (!ctx) return reject("Canvas failure");

        // Background White
        ctx.fillStyle = "#FFFFFF";
        ctx.fillRect(0, 0, 1600, 1600);

        // Calculate scaling for 1500x1500 box
        const scale = Math.min(1500 / img.width, 1500 / img.height);
        const w = img.width * scale;
        const h = img.height * scale;
        const x = (1600 - w) / 2;
        const y = (1600 - h) / 2;

        ctx.drawImage(img, x, y, w, h);
        resolve(canvas.toDataURL('image/jpeg', 0.9));
      };
      img.onerror = () => reject("Image load error");
    });
  };

  const handleBatchStandardize = async () => {
    setIsStandardizing(true);
    try {
      const nextListing = { ...localListing };
      const allImgs = [nextListing.cleaned.main_image, ...(nextListing.cleaned.other_images || [])].filter(Boolean) as string[];
      const processed: string[] = [];

      for (const url of allImgs) {
        const newUrl = await processImageStandardization(url);
        processed.push(newUrl);
      }

      nextListing.cleaned.main_image = processed[0];
      nextListing.cleaned.other_images = processed.slice(1);

      setLocalListing(nextListing);
      setPreviewImage(processed[0]);
      await syncToSupabase(nextListing);
    } catch (e) {
      alert("Standardize failed: " + e);
    } finally {
      setIsStandardizing(false);
    }
  };

  const handleAddImage = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsSaving(true);
    try {
      const formDataBody = new FormData();
      formDataBody.append('file', file);
      const response = await fetch(`${CORS_PROXY}${encodeURIComponent(IMAGE_HOST_DOMAIN + '/upload')}`, { method: 'POST', body: formDataBody });
      const data = await response.json();
      const url = Array.isArray(data) && data[0]?.src ? `${IMAGE_HOST_DOMAIN}${data[0].src}` : data.url;

      const nextListing = { ...localListing };
      nextListing.cleaned.other_images = [...(nextListing.cleaned.other_images || []), url];
      setLocalListing(nextListing);
      await syncToSupabase(nextListing);
    } catch (err) {
      alert("Upload failed");
    } finally {
      setIsSaving(false);
    }
  };

  const setAsMainImage = async (url: string) => {
    const nextListing = { ...localListing };
    const currentMain = nextListing.cleaned.main_image;
    const others = (nextListing.cleaned.other_images || []).filter(u => u !== url);

    nextListing.cleaned.main_image = url;
    if (currentMain) others.push(currentMain);
    nextListing.cleaned.other_images = others;

    setLocalListing(nextListing);
    setPreviewImage(url);
    await syncToSupabase(nextListing);
  };

  const deleteImage = async (url: string) => {
    const nextListing = { ...localListing };
    if (nextListing.cleaned.main_image === url) {
      const firstOther = nextListing.cleaned.other_images?.[0];
      nextListing.cleaned.main_image = firstOther || '';
      nextListing.cleaned.other_images = nextListing.cleaned.other_images?.slice(1) || [];
      setPreviewImage(nextListing.cleaned.main_image);
    } else {
      nextListing.cleaned.other_images = nextListing.cleaned.other_images?.filter(u => u !== url) || [];
    }
    setLocalListing(nextListing);
    await syncToSupabase(nextListing);
  };

  const handleOptimize = async () => {
    setIsOptimizing(true);
    try {
      let opt: OptimizedData;
      if (engine === 'openai') opt = await optimizeListingWithOpenAI(localListing.cleaned!);
      else if (engine === 'deepseek') opt = await optimizeListingWithDeepSeek(localListing.cleaned!);
      else opt = await optimizeListingWithAI(localListing.cleaned!);

      const updated: Listing = { ...localListing, status: 'optimized', optimized: opt };
      setLocalListing(updated);
      await syncToSupabase(updated);
    } catch (e: any) { alert(`AI Optimization (${engine}) failed: ` + e.message); } 
    finally { setIsOptimizing(false); }
  };

  const performTranslate = async (mkt: string): Promise<OptimizedData | null> => {
    const sourceData = localListing.optimized || {
        optimized_title: localListing.cleaned.title,
        optimized_features: localListing.cleaned.features || [],
        optimized_description: localListing.cleaned.description || '',
        search_keywords: localListing.cleaned.search_keywords || ''
    } as OptimizedData;

    try {
      let trans: Partial<OptimizedData>;
      if (engine === 'openai') trans = await translateListingWithOpenAI(sourceData, mkt);
      else if (engine === 'deepseek') trans = await translateListingWithDeepSeek(sourceData, mkt);
      else trans = await translateListingWithAI(sourceData, mkt);

      const rate = exchangeRates.find(r => r.marketplace === mkt)?.rate || 1;
      const isMetric = ['DE','FR','IT','ES','JP','NL','PL','SE'].includes(mkt);

      const nextTrans: OptimizedData = {
        ...trans,
        optimized_price: parseFloat(((localListing.cleaned.price || 0) * rate).toFixed(2)),
        optimized_shipping: parseFloat(((localListing.cleaned.shipping || 0) * rate).toFixed(2)),
        optimized_weight_value: isMetric ? (parseFloat(localListing.cleaned.item_weight_value || '0') * 0.45359).toFixed(2) : localListing.cleaned.item_weight_value,
        optimized_weight_unit: isMetric ? 'kg' : 'lb',
        optimized_length: isMetric ? (parseFloat(localListing.cleaned.item_length || '0') * 2.54).toFixed(2) : localListing.cleaned.item_length,
        optimized_width: isMetric ? (parseFloat(localListing.cleaned.item_width || '0') * 2.54).toFixed(2) : localListing.cleaned.item_width,
        optimized_height: isMetric ? (parseFloat(localListing.cleaned.item_height || '0') * 2.54).toFixed(2) : localListing.cleaned.item_height,
        optimized_size_unit: isMetric ? 'cm' : 'in',
      } as OptimizedData;

      return nextTrans;
    } catch (e) { return null; }
  };

  const handleBatchTranslate = async () => {
    setIsBatchTranslating(true);
    const nextListing = { ...localListing };
    const currentTranslations = { ...(nextListing.translations || {}) };
    for (const mkt of AMAZON_MARKETPLACES) {
      if (mkt.code === 'US') continue;
      const res = await performTranslate(mkt.code);
      if (res) currentTranslations[mkt.code] = res;
    }
    nextListing.translations = currentTranslations;
    setLocalListing(nextListing);
    await syncToSupabase(nextListing);
    setIsBatchTranslating(false);
  };

  const updateField = (field: string, value: any) => {
    const nextListing = { ...localListing };
    if (activeMarket === 'US') {
      if (nextListing.optimized && nextListing.status === 'optimized') {
        nextListing.optimized = { ...nextListing.optimized, [field]: value };
      } else {
        nextListing.cleaned = { ...nextListing.cleaned, [field]: value };
      }
    } else {
      const currentTranslations = { ...(nextListing.translations || {}) };
      const currentTrans = currentTranslations[activeMarket] || { optimized_title: '', optimized_features: [], optimized_description: '', search_keywords: '' } as OptimizedData;
      currentTranslations[activeMarket] = { ...currentTrans, [field]: value };
      nextListing.translations = currentTranslations;
    }
    setLocalListing(nextListing);
  };

  const currentContent = useMemo(() => {
    if (activeMarket !== 'US') {
      return localListing.translations?.[activeMarket] || { 
        optimized_title: '', optimized_features: [], optimized_description: '', search_keywords: '' 
      } as OptimizedData;
    }
    return localListing.optimized || localListing.cleaned;
  }, [localListing, activeMarket]);

  const allImages = [localListing.cleaned.main_image, ...(localListing.cleaned.other_images || [])].filter(Boolean) as string[];

  return (
    <div className="flex flex-col h-screen bg-slate-50 font-inter overflow-hidden">
      {/* Top Toolbar */}
      <header className="flex-shrink-0 bg-white border-b border-slate-200 px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="group flex items-center text-slate-500 hover:text-slate-900 font-black text-xs uppercase tracking-widest transition-all">
            <ArrowLeft size={18} className="mr-2 group-hover:-translate-x-1 transition-transform" /> {t('back')}
          </button> 
          <div className="h-6 w-px bg-slate-200"></div>
          <div className="flex bg-slate-100 p-1 rounded-2xl border border-slate-200">
             <EngineBtn active={engine === 'gemini'} onClick={() => setEngine('gemini')} icon={<Zap size={14}/>} label="Gemini 3" />
             <EngineBtn active={engine === 'openai'} onClick={() => setEngine('openai')} icon={<Brain size={14}/>} label="GPT-4o" />
             <EngineBtn active={engine === 'deepseek'} onClick={() => setEngine('deepseek')} icon={<Cpu size={14}/>} label="DeepSeek" />
          </div>
        </div>

        <div className="flex gap-3">
          <button onClick={handleOptimize} disabled={isOptimizing} className="flex items-center gap-2 px-6 py-2.5 rounded-2xl font-black text-xs text-indigo-600 bg-indigo-50 border border-indigo-100 hover:bg-indigo-100 transition-all uppercase shadow-sm">
            {isOptimizing ? <Loader2 className="animate-spin" size={16} /> : <Sparkles size={16} />} 
