function safeDecode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

const formatExportVal = (val: any) => {
  if (val === undefined || val === null || val === '') return '';
  const num = parseFloat(String(val));
  if (isNaN(num)) return val;
  return parseFloat(num.toFixed(2));
};

// New Helper: Convert abbreviations to Amazon-compliant full names with capitalization
const getFullUnitName = (unit: string) => {
  if (!unit) return "";
  const normalized = unit.toLowerCase().trim();
  const map: Record<string, string> = {
    'lb': 'Pounds',
    'lbs': 'Pounds',
    'pound': 'Pounds',
    'pounds': 'Pounds',
    'kg': 'Kilograms',
    'kilogram': 'Kilograms',
    'kilograms': 'Kilograms',
    'oz': 'Ounces',
    'ounce': 'Ounces',
    'ounces': 'Ounces',
    'gr': 'Grams',
    'g': 'Grams',
    'gram': 'Grams',
    'grams': 'Grams',
    'in': 'Inches',
    'inch': 'Inches',
    'inches': 'Inches',
    'cm': 'Centimeters',
    'centimeter': 'Centimeters',
    'centimeters': 'Centimeters',
    'mm': 'Millimeters',
    'millimeter': 'Millimeters',
    'millimeters': 'Millimeters',
    'ft': 'Feet',
    'foot': 'Feet',
    'feet': 'Feet'
  };
  return map[normalized] || unit.charAt(0).toUpperCase() + unit.slice(1);
};

