function safeDecode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

const formatExportVal = (val: any) => {
  if (val === undefined || val === null || val === '') return '';
  const num = parseFloat(String(val));
  if (isNaN(num)) return val;
  return parseFloat(num.toFixed(2));
};

// Mapper: strictly Title Case full names for Amazon Templates
const getFullUnitName = (unit: string | undefined) => {
  if (!unit) return "";
  const u = unit.toLowerCase().trim();
  const map: Record<string, string> = {
    'lb': 'Pounds',
    'lbs': 'Pounds',
    'pound': 'Pounds',
    'pounds': 'Pounds',
    'kg': 'Kilograms',
    'kilogram': 'Kilograms',
    'kilograms': 'Kilograms',
    'oz': 'Ounces',
    'ounce': 'Ounces',
    'ounces': 'Ounces',
    'gr': 'Grams',
    'g': 'Grams',
    'gram': 'Grams',
    'grams': 'Grams',
    'in': 'Inches',
    'inch': 'Inches',
    'inches': 'Inches',
    'cm': 'Centimeters',
    'centimeter': 'Centimeters',
    'centimeters': 'Centimeters',
    'mm': 'Millimeters',
    'millimeter': 'Millimeters',
    'millimeters': 'Millimeters',
    'ft': 'Feet',
    'foot': 'Feet',
    'feet': 'Feet'
  };
  if (map[u]) return map[u];
  return unit.charAt(0).toUpperCase() + unit.slice(1).toLowerCase();
};

const IS_LATIN_MKT = (code: string) => [
  'US', 'CA', 'MX', 'BR', 'UK', 'DE', 'FR', 'IT', 'ES', 'IE', 'PL', 'NL', 'SE', 'BE', 'AU', 'SG'
].includes(code);

const generateRandomValue = (type?: 'alphanumeric' | 'ean13'): string => {
  if (type === 'ean13') {
    const country = "608";
    const manufacturer = Math.floor(Math.random() * 9000 + 1000).toString();
    const sequence = Math.floor(Math.random() * 90000 + 10000).toString();
    const base = country + manufacturer + sequence; 
    let sum = 0;
    for (let i = 0; i < 12; i++) {
      const digit = parseInt(base[i]);
      sum += (i % 2 === 0) ? digit : digit * 3;
    }
    const checkDigit = (10 - (sum % 10)) % 10;
    return base + checkDigit;
  } else {
    const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
    const letters = Array.from({ length: 3 }, () => chars[Math.floor(Math.random() * chars.length)]).join('');
    const numbers = Math.floor(Math.random() * 9000 + 1000).toString();
    return letters + numbers;
  }
};

export const ExportModal: React.FC<ExportModalProps> = ({ uiLang, selectedListings, onClose, onExportSuccess }) => {
  const t = useTranslation(uiLang);
  const [templates, setTemplates] = useState<ExportTemplate[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [adjustments, setAdjustments] = useState<PriceAdjustment[]>([]);
  const [exchangeRates, setExchangeRates] = useState<ExchangeRate[]>([]);
  const [selectedTemplate, setSelectedTemplate] = useState<ExportTemplate | null>(null);
  const [targetMarket, setTargetMarket] = useState('US');
  const [targetCategory, setTargetCategory] = useState('ALL');
  const [exporting, setExporting] = useState(false);
  const [exportStatus, setExportStatus] = useState('');
  const [mktSearch, setMktSearch] = useState('');

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    if (!isSupabaseConfigured()) return;
    const [tplRes, catRes, adjRes, rateRes] = await Promise.all([
      supabase.from('templates').select('*').order('created_at', { ascending: false }),
      supabase.from('categories').select('*'),
      supabase.from('price_adjustments').select('*'),
      supabase.from('exchange_rates').select('*')
    ]);
    if (tplRes.data) setTemplates(tplRes.data);
    if (catRes.data) setCategories(catRes.data);
    if (adjRes.data) setAdjustments(adjRes.data);
    if (rateRes.data) setExchangeRates(rateRes.data);
  };

  const filteredMarketplaces = useMemo(() => {
    return AMAZON_MARKETPLACES.filter(m => 
      m.code.toLowerCase().includes(mktSearch.toLowerCase()) || 
      m.name.toLowerCase().includes(mktSearch.toLowerCase())
    );
  }, [mktSearch]);

  const filteredTemplates = useMemo(() => {
    return templates.filter(t => 
      (t.marketplace === 'ALL' || t.marketplace === targetMarket) &&
      (targetCategory === 'ALL' || t.category_id === targetCategory)
    );
  }, [templates, targetMarket, targetCategory]);

  useEffect(() => {
    if (filteredTemplates.length > 0) setSelectedTemplate(filteredTemplates[0]);
    else setSelectedTemplate(null);
  }, [filteredTemplates]);

  const updateExportHistory = async (marketCode: string) => {
    if (!isSupabaseConfigured()) return;
    try {
      const updates = selectedListings.map(listing => {
        const current = listing.exported_marketplaces || [];
        if (current.includes(marketCode)) return null;
        return supabase
          .from('listings')
          .update({ exported_marketplaces: [...current, marketCode] })
          .eq('id', listing.id);
      }).filter(Boolean);
      if (updates.length > 0) {
        await Promise.all(updates);
        if (onExportSuccess) onExportSuccess();
      }
    } catch (e) {}
  };

  const calculateFinalPrice = (listing: Listing, targetMkt: string) => {
    let basePrice = 0; let baseShipping = 0; let needsRateConversion = true;
    const translation = listing.translations?.[targetMkt];
    if (translation && translation.optimized_price !== undefined && translation.optimized_price !== null) {
      basePrice = translation.optimized_price;
      baseShipping = translation.optimized_shipping || 0;
      needsRateConversion = false; 
    } else {
      basePrice = Number(listing.cleaned.price) || 0;
      baseShipping = Number(listing.cleaned.shipping) || 0;
    }
    let currentTotal = basePrice + baseShipping;
    const applicableAdj = adjustments.filter(adj => {
      const mktMatch = adj.marketplace === 'ALL' || adj.marketplace === targetMkt;
      const catMatch = adj.category_id === 'ALL' || adj.category_id === listing.category_id;
      return mktMatch && catMatch;
    });
    applicableAdj.forEach(adj => { currentTotal *= (1 + (Number(adj.percentage) / 100)); });
    if (needsRateConversion && targetMkt !== 'US') {
      const rateEntry = exchangeRates.find(r => r.marketplace === targetMkt);
      const rate = rateEntry ? Number(rateEntry.rate) : 1;
      currentTotal *= rate;
    }
    if (targetMkt === 'JP') return Math.round(currentTotal);
    return parseFloat(currentTotal.toFixed(2));
  };

  const handleExportCSV = async () => {
    setExporting(true); setExportStatus('Generating CSV...');
    try {
      const allKeys = new Set<string>();
      selectedListings.forEach(l => { Object.keys(l.cleaned).forEach(k => allKeys.add(k)); });
      const headers = Array.from(allKeys);
      const csvData = selectedListings.map(l => {
        const row: Record<string, any> = {};
        headers.forEach(k => {
          let val = l.cleaned[k];
          if (Array.isArray(val)) val = val.join('; ');
          row[k] = val === undefined ? '' : val;
        });
        return row;
      });
      const worksheet = XLSX.utils.json_to_sheet(csvData, { header: headers });
      const workbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(workbook, worksheet, "Listings");
      const outData = XLSX.write(workbook, { bookType: 'csv', type: 'array' });
      const blob = new Blob([outData], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a'); link.href = url;
      link.download = `AMZBot_Export_${Date.now()}.csv`; link.click();
      URL.revokeObjectURL(url);
      await updateExportHistory('CSV-RAW');
    } catch (err: any) { alert("CSV Export failed: " + err.message); } 
    finally { setExporting(false); onClose(); }
  };

  const handleExportTemplate = async () => {
    const fileBinary = selectedTemplate?.mappings?.['__binary'];
    if (!selectedTemplate || !fileBinary) return;
    setExporting(true); setExportStatus('Injecting Data...');
    try {
      const bytes = safeDecode(fileBinary);
      const workbook = XLSX.read(bytes, { type: 'array', cellStyles: true, bookVBA: true, cellNF: true, cellText: true });
      const tplSheetName = selectedTemplate.mappings?.['__sheet_name'] || workbook.SheetNames[0];
      const sheet = workbook.Sheets[tplSheetName];
      const techRowIdx = selectedTemplate.mappings?.['__header_row_idx'] || 4;
      const dataStartRowIdx = selectedTemplate.mappings?.['__data_start_row_idx'] || (targetMarket === 'US' ? techRowIdx + 3 : techRowIdx + 2);
      const mappingKeys = Object.keys(selectedTemplate.mappings || {}).filter(k => k.startsWith('col_'));

      selectedListings.forEach((listing, rowOffset) => {
        const rowIdx = dataStartRowIdx + rowOffset;
        const cleaned = listing.cleaned;
        const localOpt: OptimizedData | null = (targetMarket !== 'US' && listing.translations?.[targetMarket]) 
          ? listing.translations[targetMarket] 
          : (listing.optimized || null);

        mappingKeys.forEach(mappingKey => {
          const colIdx = parseInt(mappingKey.replace('col_', ''));
          const mapping = selectedTemplate.mappings?.[mappingKey] as FieldMapping | undefined;
          if (!mapping || isNaN(colIdx)) return;
          let val: any = "";
          if (mapping.source === 'listing') {
            const f = mapping.listingField;
            if (f === 'asin') val = listing.asin || cleaned.asin || '';
            else if (f === 'title') val = localOpt?.optimized_title || cleaned.title || '';
            else if (f === 'price') val = calculateFinalPrice(listing, targetMarket);
            else if (f === 'shipping') {
              const trans = listing.translations?.[targetMarket];
              if (trans && trans.optimized_shipping !== undefined && trans.optimized_shipping !== null) val = trans.optimized_shipping;
              else {
                const rate = exchangeRates.find(r => r.marketplace === targetMarket)?.rate || 1;
                const calcShip = (cleaned.shipping || 0) * (targetMarket === 'US' ? 1 : rate);
                val = targetMarket === 'JP' ? Math.round(calcShip) : parseFloat(calcShip.toFixed(2));
              }
            }
            else if (f === 'brand') val = cleaned.brand || '';
            else if (f === 'description') val = localOpt?.optimized_description || cleaned.description || '';
            else if (f === 'main_image') val = cleaned.main_image || '';
            else if (f === 'item_weight_value') val = formatExportVal(localOpt?.optimized_weight_value || cleaned.item_weight_value || '');
            else if (f === 'item_weight_unit') val = getFullUnitName(localOpt?.optimized_weight_unit || cleaned.item_weight_unit || '');
            else if (f === 'item_length') val = formatExportVal(localOpt?.optimized_length || cleaned.item_length || '');
            else if (f === 'item_width') val = formatExportVal(localOpt?.optimized_width || cleaned.item_width || '');
            else if (f === 'item_height') val = formatExportVal(localOpt?.optimized_height || cleaned.item_height || '');
            else if (f === 'item_size_unit') val = getFullUnitName(localOpt?.optimized_size_unit || cleaned.item_size_unit || '');
          } else if (mapping.source === 'custom') val = mapping.defaultValue || '';
          else if (mapping.source === 'random') val = generateRandomValue(mapping.randomType);
          else if (mapping.source === 'template_default') val = mapping.templateDefault || '';

          const cellRef = XLSX.utils.encode_cell({ r: rowIdx, c: colIdx });
          sheet[cellRef] = { v: val, t: (typeof val === 'number') ? 'n' : 's' };
        });
      });

      const outData = XLSX.write(workbook, { type: 'array', bookType: 'xlsm', bookVBA: true, cellStyles: true });
      const blob = new Blob([outData], { type: 'application/vnd.ms-excel.sheet.macroEnabled.12' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a'); link.href = url;
      link.download = `Localized_${targetMarket}_${Date.now()}.xlsm`; link.click();
      URL.revokeObjectURL(url);
      await updateExportHistory(targetMarket);
    } catch (err: any) { alert("Template export failed: " + err.message); } 
    finally { setExporting(false); onClose(); }
  };

  return (
    <div className="fixed inset-0 z-[100] bg-slate-900/70 backdrop-blur-md flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-6xl max-h-[90vh] rounded-[3rem] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">
        <div className="px-10 py-7 border-b border-slate-100 flex items-center justify-between">
          <h2 className="text-3xl font-black text-slate-900 tracking-tighter flex items-center gap-4">
            <Download className="text-indigo-600" size={32} /> {t('confirmExport')}
          </h2>
          <button onClick={onClose} className="p-3 hover:bg-slate-100 rounded-full text-slate-400"><X size={28} /></button>
        </div>
        <div className="p-10 space-y-10 flex-1 overflow-y-auto custom-scrollbar">
          <div className="bg-indigo-600 p-8 rounded-[2rem] shadow-2xl shadow-indigo-200 text-white flex items-center gap-6">
            <div className="w-16 h-16 bg-white/20 rounded-2xl flex items-center justify-center text-white backdrop-blur-md"><CheckCircle2 size={32} /></div>
            <div><p className="text-xl font-black">{selectedListings.length} Items Selected</p><p className="text-xs font-bold text-indigo-100 opacity-80 uppercase tracking-widest mt-1">Updating Localization History upon completion</p></div>
          </div>
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
            <div className="lg:col-span-5 space-y-8">
               <div className="space-y-4 flex flex-col h-full">
                  <div className="flex items-center justify-between"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2"><Globe size={14} className="text-blue-500" /> Target Marketplace</label></div>
                  <div className="grid grid-cols-2 sm:grid-cols-3 gap-2 max-h-[450px] overflow-y-auto pr-2 custom-scrollbar p-1 bg-slate-50/50 rounded-3xl border border-slate-100">
                    {filteredMarketplaces.map(m => (
                      <button key={m.code} onClick={() => setTargetMarket(m.code)} className={`px-3 py-4 rounded-2xl border text-left transition-all ${targetMarket === m.code ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl scale-105 z-10' : 'bg-white border-slate-100 text-slate-600 hover:border-indigo-300'}`}>
                        <div className="text-xl mb-1">{m.flag}</div><div className="text-[10px] font-black uppercase tracking-tighter truncate">{m.code} - {m.name}</div>
                      </button>
                    ))}
                  </div>
               </div>
            </div>
            <div className="lg:col-span-7 space-y-8">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-6 h-full">
                  <button onClick={handleExportCSV} className="p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] flex flex-col items-center text-center group hover:border-indigo-500 transition-all hover:bg-white hover:shadow-2xl">
                     <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-sm mb-6"><FileText size={32} /></div>
                     <h3 className="font-black text-slate-900 uppercase tracking-widest mb-2">Default CSV</h3>
                     <p className="text-[10px] text-slate-400 font-bold Gabriel leading-relaxed">Raw data dump without marketplace formatting.</p>
                  </button>
                  <div className="space-y-4 flex flex-col h-full">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><FileSpreadsheet size={14} className="text-emerald-500" /> Template Export</label>
                    <div className="space-y-3 flex-1 max-h-[450px] overflow-y-auto pr-2 custom-scrollbar bg-slate-50/30 p-4 rounded-3xl border border-slate-100">
                      {filteredTemplates.length === 0 ? (
                        <div className="p-12 text-center bg-white rounded-3xl border-dashed border-2 border-slate-100 flex flex-col items-center gap-4">
                          <AlertCircle size={32} className="text-slate-200" /><p className="text-[10px] font-black text-slate-300 uppercase leading-relaxed text-center">No Templates for {targetMarket}</p>
                        </div>
                      ) : (
                        filteredTemplates.map(tmp => (
                          <button key={tmp.id} onClick={() => setSelectedTemplate(tmp)} className={`w-full flex items-center gap-4 p-5 rounded-2xl border text-left transition-all ${selectedTemplate?.id === tmp.id ? 'border-indigo-500 bg-white shadow-lg' : 'border-slate-50 bg-white/70 hover:border-slate-200'}`}>
                            <div className={`p-2 rounded-lg ${selectedTemplate?.id === tmp.id ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}><FileSpreadsheet size={18} /></div>
                            <div className="flex-1 overflow-hidden"><span className="font-black text-xs block truncate">{tmp.name}</span></div>
                          </button>
                        ))
                      )}
                    </div>
                  </div>
               </div>
            </div>
          </div>
        </div>
        <div className="p-10 bg-slate-50 border-t border-slate-100 flex justify-end gap-5">
          {exporting && <div className="mr-auto flex items-center gap-3 text-xs font-black text-indigo-600 uppercase animate-pulse"><Loader2 className="animate-spin" size={16} /> {exportStatus}</div>}
          <button onClick={onClose} className="px-10 py-4 bg-white border border-slate-200 text-slate-600 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-100 transition-all">Cancel</button>
          <button disabled={!selectedTemplate || exporting} onClick={handleExportTemplate} className="px-14 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-3 shadow-2xl active:scale-95 transition-all disabled:opacity-50"><Download size={18} /> Localized Template (.XLSM)</button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { 
  ArrowLeft, Sparkles, Image as ImageIcon, Edit2, Trash2, Plus, X,
  Globe, Languages, Loader2, DollarSign, Truck, Save, ChevronRight,
  Zap, Check, Weight, Ruler, ListFilter, FileText, Wand2, Search, 
  ExternalLink, Link2, Star, Maximize2, Hash, Cpu, Brain, AlertTriangle, Upload, Box
} from 'lucide-react';
import { Listing, OptimizedData, CleanedData, UILanguage, ExchangeRate, SourcingRecord } from '../types';
import { optimizeListingWithAI, translateListingWithAI } from '../services/geminiService';
import { optimizeListingWithOpenAI, translateListingWithOpenAI } from '../services/openaiService';
import { optimizeListingWithDeepSeek, translateListingWithDeepSeek } from '../services/deepseekService';
import { ImageEditor } from './ImageEditor';
import { SourcingModal } from './SourcingModal';
import { SourcingFormModal } from './SourcingFormModal';
import { supabase, isSupabaseConfigured } from '../lib/supabaseClient';
import { useTranslation } from '../lib/i18n';
import { AMAZON_MARKETPLACES } from '../lib/marketplaces';

interface ListingDetailProps {
  listing: Listing;
  onBack: () => void;
  onUpdate: (updatedListing: Listing) => void;
  onNext: () => void;
  uiLang: UILanguage;
}

type AIEngine = 'gemini' | 'openai' | 'deepseek';

const IMAGE_HOST_DOMAIN = 'https://img.hmstu.eu.org';
const CORS_PROXY = 'https://corsproxy.io/?';

// Marketplace standards for units
const METRIC_MARKETS = ['DE', 'FR', 'IT', 'ES', 'JP', 'NL', 'PL', 'SE', 'BE'];

// Helper to normalize unit names to Title Case Full Names
const normalizeUnit = (unit: string | undefined): string => {
  if (!unit) return "";
  const u = unit.toLowerCase().trim();
  if (u === 'lb' || u === 'lbs' || u === 'pounds') return "Pounds";
  if (u === 'kg' || u === 'kilograms') return "Kilograms";
  if (u === 'oz' || u === 'ounces') return "Ounces";
  if (u === 'g' || u === 'grams') return "Grams";
  if (u === 'in' || u === 'inches') return "Inches";
  if (u === 'cm' || u === 'centimeters') return "Centimeters";
  if (u === 'mm' || u === 'millimeters') return "Millimeters";
  return unit.charAt(0).toUpperCase() + unit.slice(1).toLowerCase();
};

export const ListingDetail: React.FC<ListingDetailProps> = ({ listing, onBack, onUpdate, onNext, uiLang }) => {
  const t = useTranslation(uiLang);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [activeMarket, setActiveMarket] = useState('US');

  const [engine, setEngine] = useState<AIEngine>(() => {
    const saved = localStorage.getItem('amzbot_preferred_engine');
    return (saved as AIEngine) || 'gemini';
  });

  useEffect(() => {
    localStorage.setItem('amzbot_preferred_engine', engine);
  }, [engine]);

  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isBatchTranslating, setIsBatchTranslating] = useState(false);
  const [isStandardizing, setIsStandardizing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const [showImageEditor, setShowImageEditor] = useState(false);
  const [showSourcingModal, setShowSourcingModal] = useState(false);
  const [showSourcingForm, setShowSourcingForm] = useState<{show: boolean, data: SourcingRecord | null}>({show: false, data: null});

  const [localListing, setLocalListing] = useState<Listing>(listing);
  const [previewImage, setPreviewImage] = useState<string>(listing.cleaned?.main_image || '');
  const [exchangeRates, setExchangeRates] = useState<ExchangeRate[]>([]);

  useEffect(() => {
    setLocalListing(listing);
    setPreviewImage(listing.cleaned?.main_image || '');
    setActiveMarket('US');
    fetchPricingData();
  }, [listing]);

  const fetchPricingData = async () => {
    if (!isSupabaseConfigured()) return;
    const { data } = await supabase.from('exchange_rates').select('*');
    if (data) setExchangeRates(data);
  };

  const syncToSupabase = async (targetListing: Listing) => {
    if (!isSupabaseConfigured()) return;
    setIsSaving(true);
    try {
      const { error } = await supabase.from('listings').update({
        cleaned: targetListing.cleaned,
        optimized: targetListing.optimized || null,
        translations: targetListing.translations || null,
        status: targetListing.status,
        sourcing_data: targetListing.sourcing_data || [],
        updated_at: new Date().toISOString()
      }).eq('id', targetListing.id);
      if (error) throw error;
      onUpdate({ ...targetListing, updated_at: new Date().toISOString() });
    } catch (e: any) { console.error("Auto-save failed:", e); } 
    finally { setIsSaving(false); }
  };

  // Helper: Correct source selection with regional fallback for units
  const getFieldValue = (optField: string, cleanField: string) => {
    const isMetric = METRIC_MARKETS.includes(activeMarket);

    // Strict logic for units as requested
    if (optField.includes('unit')) {
      if (activeMarket === 'US') {
        const rawUnit = localListing.cleaned[cleanField];
        return normalizeUnit(rawUnit);
      } else {
        const trans = localListing.translations?.[activeMarket];
        const transUnit = trans ? (trans as any)[optField] : null;
        return normalizeUnit(transUnit);
      }
    }

    if (activeMarket === 'US') {
      const optVal = localListing.optimized ? (localListing.optimized as any)[optField] : null;
      if (optVal !== undefined && optVal !== null && (Array.isArray(optVal) ? optVal.length > 0 : optVal !== '')) {
        return optVal;
      }
      const cleanVal = (localListing.cleaned as any)[cleanField];
      if (cleanVal !== undefined && cleanVal !== null) return cleanVal;
      if (optField.includes('features')) return ['', '', '', '', ''];
      return '';
    }

    // Non-US Market: Strictly read from translations
    const trans = localListing.translations?.[activeMarket];
    if (trans && (trans as any)[optField] !== undefined && (trans as any)[optField] !== null) {
      const val = (trans as any)[optField];
      if (Array.isArray(val) ? val.length > 0 : val !== '') {
        return val;
      }
    }

    // Dynamic price calculation fallback for translation sites
    if (optField === 'optimized_price' || optField === 'optimized_shipping') {
      const sourceVal = localListing.cleaned[cleanField] || 0;
      const rate = exchangeRates.find(r => r.marketplace === activeMarket)?.rate || 1;
      const converted = sourceVal * rate;
      return activeMarket === 'JP' ? Math.round(converted) : parseFloat(converted.toFixed(2));
    }

    if (optField.includes('features')) return ['', '', '', '', ''];

    return '';
  };

  const updateField = (field: string, value: any) => {
    const nextListing = { ...localListing };

    if (activeMarket === 'US') {
      if (nextListing.status === 'optimized' && nextListing.optimized) {
        nextListing.optimized = { ...nextListing.optimized, [field]: value };
      } else {
        const cleanKey = field.startsWith('optimized_') ? field.replace('optimized_', '') : field;
        nextListing.cleaned = { ...nextListing.cleaned, [cleanKey]: value };
      }
    } else {
      const currentTranslations = { ...(nextListing.translations || {}) };
      const currentTrans = currentTranslations[activeMarket] || { optimized_title: '', optimized_features: ['', '', '', '', ''], optimized_description: '', search_keywords: '' } as OptimizedData;
      currentTranslations[activeMarket] = { ...currentTrans, [field]: value };
      nextListing.translations = currentTranslations;
    }
    setLocalListing(nextListing);
  };

  const handleBatchStandardize = async () => {
    setIsStandardizing(true);
    try {
      const nextListing = { ...localListing };
      const allImgs = [nextListing.cleaned.main_image, ...(nextListing.cleaned.other_images || [])].filter(Boolean) as string[];
      const processed: string[] = [];

      const processImage = async (url: string): Promise<string> => {
        return new Promise((resolve, reject) => {
          const img = new Image();
          img.crossOrigin = "anonymous";
          img.src = `${CORS_PROXY}${encodeURIComponent(url)}`;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            canvas.width = 1600; canvas.height = 1600;
            const ctx = canvas.getContext('2d');
            if (!ctx) return reject("Canvas failure");
            ctx.fillStyle = "#FFFFFF"; ctx.fillRect(0, 0, 1600, 1600);
            const scale = Math.min(1500 / img.width, 1500 / img.height);
            const w = img.width * scale; const h = img.height * scale;
            ctx.drawImage(img, (1600 - w) / 2, (1600 - h) / 2, w, h);
            resolve(canvas.toDataURL('image/jpeg', 0.9));
          };
          img.onerror = () => reject("Image load error");
        });
      };

      for (const url of allImgs) {
        const newUrl = await processImage(url);
        processed.push(newUrl);
      }

      nextListing.cleaned.main_image = processed[0];
      nextListing.cleaned.other_images = processed.slice(1);
      setLocalListing(nextListing);
      setPreviewImage(processed[0]);
      await syncToSupabase(nextListing);
    } catch (e) { alert("Standardize failed: " + e); } 
    finally { setIsStandardizing(false); }
  };

  const handleAddImage = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsSaving(true);
    try {
      const formDataBody = new FormData();
      formDataBody.append('file', file);
      const response = await fetch(`${CORS_PROXY}${encodeURIComponent(IMAGE_HOST_DOMAIN + '/upload')}`, { method: 'POST', body: formDataBody });
      const data = await response.json();
      const url = Array.isArray(data) && data[0]?.src ? `${IMAGE_HOST_DOMAIN}${data[0].src}` : data.url;
      const nextListing = { ...localListing };
      nextListing.cleaned.other_images = [...(nextListing.cleaned.other_images || []), url];
      setLocalListing(nextListing);
      await syncToSupabase(nextListing);
    } catch (err) { alert("Upload failed"); } 
    finally { setIsSaving(false); }
  };

  const handleOptimize = async () => {
    setIsOptimizing(true);
    try {
      let opt: OptimizedData;
      if (engine === 'openai') opt = await optimizeListingWithOpenAI(localListing.cleaned!);
      else if (engine === 'deepseek') opt = await optimizeListingWithDeepSeek(localListing.cleaned!);
      else opt = await optimizeListingWithAI(localListing.cleaned!);
      const updated: Listing = { ...localListing, status: 'optimized', optimized: opt };
      setLocalListing(updated);
      await syncToSupabase(updated);
    } catch (e: any) { alert(`AI Optimization failed: ` + e.message); } 
    finally { setIsOptimizing(false); }
  };

  const handleBatchTranslate = async () => {
    setIsBatchTranslating(true);
    const nextListing = { ...localListing };
    const currentTranslations = { ...(nextListing.translations || {}) };
    for (const mkt of AMAZON_MARKETPLACES) {
      if (mkt.code === 'US') continue;
      try {
        const sourceData = localListing.optimized || {
          optimized_title: localListing.cleaned.title,
          optimized_features: localListing.cleaned.features || [],
          optimized_description: localListing.cleaned.description || '',
          search_keywords: localListing.cleaned.search_keywords || ''
        } as OptimizedData;

        let trans: Partial<OptimizedData>;
        if (engine === 'openai') trans = await translateListingWithOpenAI(sourceData, mkt.code);
        else if (engine === 'deepseek') trans = await translateListingWithDeepSeek(sourceData, mkt.code);
        else trans = await translateListingWithAI(sourceData, mkt.code);

        const rate = exchangeRates.find(r => r.marketplace === mkt.code)?.rate || 1;
        const isMetric = METRIC_MARKETS.includes(mkt.code);

        currentTranslations[mkt.code] = {
          ...trans,
          optimized_price: parseFloat(((localListing.cleaned.price || 0) * rate).toFixed(2)),
          optimized_shipping: parseFloat(((localListing.cleaned.shipping || 0) * rate).toFixed(2)),
          optimized_weight_value: isMetric ? (parseFloat(localListing.cleaned.item_weight_value || '0') * 0.45359).toFixed(2) : localListing.cleaned.item_weight_value,
          optimized_weight_unit: isMetric ? 'Kilograms' : 'Pounds',
          optimized_length: isMetric ? (parseFloat(localListing.cleaned.item_length || '0') * 2.54).toFixed(2) : localListing.cleaned.item_length,
          optimized_width: isMetric ? (parseFloat(localListing.cleaned.item_width || '0') * 2.54).toFixed(2) : localListing.cleaned.item_width,
          optimized_height: isMetric ? (parseFloat(localListing.cleaned.item_height || '0') * 2.54).toFixed(2) : localListing.cleaned.item_height,
          optimized_size_unit: isMetric ? 'Centimeters' : 'Inches',
        } as OptimizedData;
      } catch (e) {}
    }
    nextListing.translations = currentTranslations;
    setLocalListing(nextListing);
    await syncToSupabase(nextListing);
    setIsBatchTranslating(false);
  };

  const allImages = [localListing.cleaned.main_image, ...(localListing.cleaned.other_images || [])].filter(Boolean) as string[];

  return (
    <div className="flex flex-col h-screen bg-slate-50 font-inter overflow-hidden">
      <header className="flex-shrink-0 bg-white border-b border-slate-200 px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="group flex items-center text-slate-500 hover:text-slate-900 font-black text-xs uppercase tracking-widest transition-all">
            <ArrowLeft size={18} className="mr-2 group-hover:-translate-x-1 transition-transform" /> {t('back')}
          </button> 
          <div className="h-6 w-px bg-slate-200"></div>
          <div className="flex bg-slate-100 p-1 rounded-2xl border border-slate-200">
             <EngineBtn active={engine === 'gemini'} onClick={() => setEngine('gemini')} icon={<Zap size={14}/>} label="Gemini 3" />
             <EngineBtn active={engine === 'openai'} onClick={() => setEngine('openai')} icon={<Brain size={14}/>} label="GPT-4o" />
             <EngineBtn active={engine === 'deepseek'} onClick={() => setEngine('deepseek')} icon={<Cpu size={14}/>} label="DeepSeek" />
          </div>
        </div>

        <div className="flex gap-3">
          {isSaving && <div className="flex items-center gap-2 px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[9px] font-black uppercase animate-pulse"><Loader2 className="animate-spin" size={12} /> Syncing</div>}
          <button onClick={handleOptimize} disabled={isOptimizing} className="flex items-center gap-2 px-6 py-2.5 rounded-2xl font-black text-xs text-indigo-600 bg-indigo-50 border border-indigo-100 hover:bg-indigo-100 transition-all uppercase shadow-sm">
            {isOptimizing ? <Loader2 className="animate-spin" size={16} /> : <Sparkles size={16} />} AI Optimize
          </button>
          <button onClick={() => syncToSupabase(localListing)} disabled={isSaving} className="flex items-center gap-2 px-8 py-2.5 rounded-2xl font-black text-xs text-white bg-slate-900 hover:bg-black shadow-xl active:scale-95 transition-all uppercase tracking-widest">
            {isSaving ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />} {t('save')}
          </button>
          <button onClick={onNext} className="p-2.5 bg-slate-100 text-slate-400 hover:text-slate-900 rounded-xl transition-all border border-slate-200">
            <ChevronRight size={20} />
          </button>
        </div>
      </header>

      <div className="flex-1 overflow-y-auto custom-scrollbar p-8">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
          <div className="lg:col-span-4 space-y-6 sticky top-0">
             <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
                <div className="aspect-square bg-slate-50 rounded-3xl border border-slate-100 overflow-hidden relative flex items-center justify-center group mb-6">
                   <img src={previewImage} className="max-w-full max-h-full object-contain mix-blend-multiply transition-transform duration-700 group-hover:scale-110" />
                   <div className="absolute bottom-4 right-4 flex gap-2">
                      <button onClick={handleBatchStandardize} disabled={isStandardizing} className="px-4 py-2 bg-white/90 backdrop-blur-md rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center gap-2 border border-slate-100 hover:bg-indigo-600 hover:text-white transition-all">
                        {isStandardizing ? <Loader2 className="animate-spin" size={12} /> : <Box size={12} />} 1600 Standard
                      </button>
                      <button onClick={() => setShowImageEditor(true)} className="px-4 py-2 bg-white/90 backdrop-blur-md rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center gap-2 border border-slate-100 hover:bg-indigo-600 hover:text-white transition-all">
                         <Wand2 size={12} /> AI Editor
                      </button>
                   </div>
                </div>
                <div className="flex gap-2 overflow-x-auto custom-scrollbar pb-3">
                   {allImages.map((img, i) => (
                     <div key={i} onMouseEnter={() => setPreviewImage(img)} className={`group/thumb relative w-16 h-16 rounded-xl border-2 shrink-0 cursor-pointer overflow-hidden transition-all ${previewImage === img ? 'border-indigo-500 shadow-lg' : 'border-transparent opacity-60'}`}>
                        <img src={img} className="w-full h-full object-cover" />
                        <div className="absolute inset-0 bg-black/40 flex items-center justify-center gap-1 opacity-0 group-hover/thumb:opacity-100 transition-opacity">
                           <button onClick={(e) => { e.stopPropagation(); updateField('main_image', img); setPreviewImage(img); }} className="p-1 text-white hover:text-amber-400" title="Set as Main"><Star size={12} fill={img === localListing.cleaned.main_image ? "currentColor" : "none"} /></button>
                           <button onClick={(e) => { e.stopPropagation(); const others = (localListing.cleaned.other_images || []).filter(u => u !== img); updateField('other_images', others); }} className="p-1 text-white hover:text-red-400" title="Delete"><Trash2 size={12} /></button>
                        </div>
                     </div>
                   ))}
                   <button onClick={() => fileInputRef.current?.click()} className="w-16 h-16 rounded-xl border-2 border-dashed border-slate-200 flex items-center justify-center text-slate-300 hover:border-indigo-400 hover:text-indigo-600 transition-all shrink-0">
                      <Plus size={20} />
                   </button>
                   <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleAddImage} />
                </div>
             </div>
          </div>

          <div className="lg:col-span-8 space-y-8">
             <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
                <div className="px-10 py-6 border-b border-slate-50 bg-slate-50/50 flex flex-col md:flex-row items-center justify-between gap-6">
                   <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-inner overflow-x-auto custom-scrollbar no-scrollbar">
