import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  X, Eraser, Scissors, PaintBucket, Crop, Save, Undo, 
  Wand2, Loader2, Download, MousePointer2, Maximize, 
  Type, Square, Circle, Minus, Move, Palette, Trash2,
  ZoomIn, ZoomOut, RotateCcw, Box, ArrowUpRight, RefreshCw, 
  Shapes, ChevronRight
} from 'lucide-react';
import { editImageWithAI } from '../services/geminiService';
import { UILanguage } from '../types';

interface ImageEditorProps {
  imageUrl: string;
  onClose: () => void;
  onSave: (newImageUrl: string) => void;
  uiLang: UILanguage;
}

type Tool = 'select' | 'select-fill' | 'brush' | 'ai-erase' | 'crop' | 'rect' | 'circle' | 'line' | 'text' | 'none';

interface EditorObject {
  id: string;
  type: 'rect' | 'circle' | 'line' | 'text';
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number; 
  stroke: string;
  fill: string;
  strokeWidth: number;
  opacity: number; // 0 to 1
  text?: string;
}

interface EditorState {
  canvasData: string;
  objects: EditorObject[];
}

interface SelectionBox {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
}

const CORS_PROXY = 'https://corsproxy.io/?';

export const ImageEditor: React.FC<ImageEditorProps> = ({ imageUrl, onClose, onSave, uiLang }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [currentTool, setCurrentTool] = useState<Tool>('select');
  const [isProcessing, setIsProcessing] = useState(false);
  const [strokeColor, setStrokeColor] = useState('#000000');
  const [fillColor, setFillColor] = useState('#ffffff');
  const [brushSize, setBrushSize] = useState(5);
  const [opacity, setOpacity] = useState(1); // 1.0 = 100%
  const [zoom, setZoom] = useState(1);

  // Shape menu state
  const [showShapeMenu, setShowShapeMenu] = useState(false);
  const [lastUsedShape, setLastUsedShape] = useState<'rect' | 'circle' | 'line'>('rect');

  // Object system
  const [objects, setObjects] = useState<EditorObject[]>([]);
  const [selectedObjectId, setSelectedObjectId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [isRotating, setIsRotating] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const [isDrawing, setIsDrawing] = useState(false);
  const [selection, setSelection] = useState<SelectionBox | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });

  const [history, setHistory] = useState<EditorState[]>([]);

  const saveToHistory = useCallback((currentObjects?: EditorObject[]) => {
    const canvas = canvasRef.current;
    if (canvas) {
      const newState: EditorState = {
        canvasData: canvas.toDataURL('image/png'),
        objects: currentObjects ? [...currentObjects] : [...objects]
      };
      setHistory(prev => [...prev.slice(-30), newState]);
    }
  }, [objects]);

  useEffect(() => {
    const initCanvas = async () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d', { willReadFrequently: true }) as CanvasRenderingContext2D | null;
      if (!ctx) return;

      setIsProcessing(true);
      try {
        const proxyUrl = `${CORS_PROXY}${encodeURIComponent(imageUrl)}`;
        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error("Failed to fetch image through proxy");
        const blob = await response.blob();
        const localUrl = URL.createObjectURL(blob);

        const img = new Image();
        img.src = localUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);

          if (containerRef.current) {
            const padding = 120;
            const availableW = containerRef.current.clientWidth - padding;
            const availableH = containerRef.current.clientHeight - padding;
            const scale = Math.min(availableW / img.width, availableH / img.height, 1);
            setZoom(scale || 1);
          }

          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
          URL.revokeObjectURL(localUrl);
        };
      } catch (err) {
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.src = imageUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          (ctx as CanvasRenderingContext2D).drawImage(img, 0, 0);
          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
        };
      }
    };
    initCanvas();
  }, [imageUrl]);

  const undo = () => {
    if (history.length <= 1) return;
    const newHistory = [...history];
    newHistory.pop(); 
    const prevState = newHistory[newHistory.length - 1];

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (canvas && ctx && prevState) {
      const img = new Image();
      img.src = prevState.canvasData;
      img.onload = () => {
        canvas.width = img.width;
        canvas.height = img.height;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        setObjects(prevState.objects);
        setHistory(newHistory);
      };
    }
  };

  const standardize = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const currentData = canvas.toDataURL();
    const tempImg = new Image();
    tempImg.src = currentData;
    tempImg.onload = () => {
      const targetSize = 1600;
      const safeArea = 1500;
      canvas.width = targetSize;
      canvas.height = targetSize;
      const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, targetSize, targetSize);
      const scale = Math.min(safeArea / tempImg.width, safeArea / tempImg.height);
      const drawW = tempImg.width * scale;
      const drawH = tempImg.height * scale;
      const x = (targetSize - drawW) / 2;
      const y = (targetSize - drawH) / 2;
      ctx.drawImage(tempImg, x, y, drawW, drawH);
      saveToHistory();
      if (containerRef.current) {
        setZoom(Math.min((containerRef.current.clientHeight - 120) / 1600, 1));
      }
    };
  };

  const getMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }
    return {
      x: (clientX - rect.left) / zoom,
      y: (clientY - rect.top) / zoom
    };
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);
    setStartPos(pos);

    if (currentTool === 'select') {
      if (selectedObjectId) {
        const obj = objects.find(o => o.id === selectedObjectId);
        if (obj) {
          const handleSize = 12 / zoom;
          const rotateHandleY = obj.y - 30 / zoom;
          const centerX = obj.x + obj.width / 2;

          const distToRotate = Math.sqrt(Math.pow(pos.x - centerX, 2) + Math.pow(pos.y - rotateHandleY, 2));
          if (distToRotate < handleSize) {
            setIsRotating(true);
            return;
          }

          const isOverResizeHandle = 
            pos.x >= obj.x + obj.width - handleSize && 
            pos.x <= obj.x + obj.width + handleSize && 
            pos.y >= obj.y + obj.height - handleSize && 
            pos.y <= obj.y + obj.height + handleSize;

          if (isOverResizeHandle) {
            setIsResizing(true);
            return;
          }

          const isOverBody = 
            pos.x >= obj.x && pos.x <= obj.x + obj.width &&
            pos.y >= obj.y && pos.y <= obj.y + obj.height;

          if (isOverBody) {
            setIsDragging(true);
            setDragOffset({ x: pos.x - obj.x, y: pos.y - obj.y });
            return;
          }
        }
      }

      const hit = objects.slice().reverse().find(obj => 
        pos.x >= obj.x && pos.x <= obj.x + obj.width &&
        pos.y >= obj.y && pos.y <= obj.y + obj.height
      );

      if (hit) {
        setSelectedObjectId(hit.id);
        setIsDragging(true);
        setDragOffset({ x: pos.x - hit.x, y: pos.y - hit.y });
      } else {
        setSelectedObjectId(null);
      }
      return;
    }

    setIsDrawing(true);
    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection({ x1: pos.x, y1: pos.y, x2: pos.x, y2: pos.y });
    }

    if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.beginPath();
        ctx.moveTo(pos.x, pos.y);
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.globalAlpha = opacity;
        ctx.strokeStyle = currentTool === 'ai-erase' ? 'rgba(255, 0, 0, 0.6)' : strokeColor;
        ctx.lineWidth = brushSize;
      }
    }
  };

  const handleMove = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);

    if (currentTool === 'select' && selectedObjectId) {
      const obj = objects.find(o => o.id === selectedObjectId);
      if (!obj) return;

      if (isDragging) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, x: pos.x - dragOffset.x, y: pos.y - dragOffset.y }
            : o
        ));
      } else if (isResizing) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, width: Math.max(10, pos.x - o.x), height: Math.max(10, pos.y - o.y) }
            : o
        ));
      } else if (isRotating) {
        const centerX = obj.x + obj.width / 2;
        const centerY = obj.y + obj.height / 2;
        const angle = Math.atan2(pos.y - centerY, pos.x - centerX) + Math.PI / 2;
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId ? { ...o, rotation: angle } : o
        ));
      }
      return;
    }

    if (!isDrawing) return;

    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection(prev => prev ? { ...prev, x2: pos.x, y2: pos.y } : null);
    } else if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.lineTo(pos.x, pos.y);
        ctx.stroke();
      }
    }
  };

  const handleEnd = (e: React.MouseEvent | React.TouchEvent) => {
    if (currentTool === 'select') {
      if (isDragging || isResizing || isRotating) {
        saveToHistory(objects);
      }
      setIsDragging(false);
      setIsResizing(false);
      setIsRotating(false);
      return;
    }

    if (!isDrawing) return;
    setIsDrawing(false);

    const pos = getMousePos(e);

    if (['rect', 'circle', 'line'].includes(currentTool)) {
      const newObj: EditorObject = {
        id: crypto.randomUUID(),
        type: currentTool as any,
        x: Math.min(startPos.x, pos.x),
        y: Math.min(startPos.y, pos.y),
        width: Math.abs(startPos.x - pos.x),
        height: Math.abs(startPos.y - pos.y),
        rotation: 0,
        stroke: strokeColor,
        fill: fillColor,
        strokeWidth: brushSize,
        opacity: opacity
      };
      const nextObjects = [...objects, newObj];
      setObjects(nextObjects);
      setSelectedObjectId(newObj.id);
      setCurrentTool('select');
      setSelection(null);
      saveToHistory(nextObjects);
    } else if (currentTool === 'text') {
      const text = window.prompt(uiLang === 'zh' ? "输入文字:" : "Enter text:");
      if (text) {
        const newObj: EditorObject = {
          id: crypto.randomUUID(),
          type: 'text',
          x: pos.x,
          y: pos.y,
          width: text.length * brushSize * 3,
          height: brushSize * 6,
          rotation: 0,
          stroke: strokeColor,
          fill: fillColor,
          strokeWidth: brushSize,
          opacity: opacity,
          text: text
        };
        const nextObjects = [...objects, newObj];
        setObjects(nextObjects);
        setSelectedObjectId(newObj.id);
        setCurrentTool('select');
        saveToHistory(nextObjects);
      }
    } else if (currentTool === 'brush') {
      saveToHistory();
    }
  };

  const handleFill = () => {
    if (currentTool !== 'select-fill' || !selection) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);

    // Core Fix: Direct canvas manipulation to ensure absolute opacity covering
    ctx.save();
    ctx.globalAlpha = opacity;
    ctx.fillStyle = fillColor;
    ctx.fillRect(x, y, w, h);
    ctx.restore();

    saveToHistory();
    setSelection(null); 
    setCurrentTool('select');
  };

  const handleCrop = () => {
    if (!selection) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    if (w < 5 || h < 5) return;
    const imageData = ctx.getImageData(x, y, w, h);
    canvas.width = w;
    canvas.height = h;
    ctx.putImageData(imageData, 0, 0);
    saveToHistory();
    setSelection(null);
    setZoom(1);
    setCurrentTool('select');
  };

  const runAIErase = async () => {
    setIsProcessing(true);
    try {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const base64 = canvas.toDataURL('image/jpeg', 0.9).split(',')[1];
      const result = await editImageWithAI(base64, "Please erase the red highlighted areas cleanly.");
      const img = new Image();
      img.src = `data:image/jpeg;base64,${result}`;
      img.onload = () => {
        const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        saveToHistory();
        setIsProcessing(false);
      };
    } catch (e: any) {
      alert("AI Erase failed: " + e.message);
      setIsProcessing(false);
    }
  };

  const handleFinalSave = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    objects.forEach(obj => {
      ctx.save();
      const cx = obj.x + obj.width / 2;
      const cy = obj.y + obj.height / 2;

      ctx.translate(cx, cy);
      ctx.rotate(obj.rotation);
      ctx.translate(-cx, -cy);

      ctx.globalAlpha = obj.opacity;
      ctx.strokeStyle = obj.stroke;
      ctx.fillStyle = obj.fill;
      ctx.lineWidth = obj.strokeWidth;
      ctx.lineCap = 'round';

      if (obj.type === 'rect') {
        ctx.beginPath();
        ctx.rect(obj.x, obj.y, obj.width, obj.height);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'circle') {
        const r = Math.sqrt(obj.width * obj.width + obj.height * obj.height) / 2;
        ctx.beginPath();
        ctx.arc(obj.x + obj.width/2, obj.y + obj.height/2, r, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'line') {
        ctx.beginPath();
        ctx.moveTo(obj.x, obj.y);
        ctx.lineTo(obj.x + obj.width, obj.y + obj.height);
        ctx.stroke();
      } else if (obj.type === 'text' && obj.text) {
        ctx.font = `bold ${obj.strokeWidth * 6}px Inter, sans-serif`;
        ctx.fillText(obj.text, obj.x, obj.y);
        ctx.strokeText(obj.text, obj.x, obj.y);
      }
      ctx.restore();
    });

    onSave(canvas.toDataURL('image/jpeg', 0.95));
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.key === 'Delete' || e.key === 'Backspace')) {
         if (selectedObjectId) {
            const nextObjects = objects.filter(o => o.id !== selectedObjectId);
            setObjects(nextObjects);
            setSelectedObjectId(null);
            saveToHistory(nextObjects);
         } else if (currentTool === 'select-fill' && selection) {
            handleFill();
         }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedObjectId, objects, saveToHistory, currentTool, selection, fillColor, opacity]);

  const ShapeIcon = lastUsedShape === 'rect' ? Square : lastUsedShape === 'circle' ? Circle : Minus;

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col font-inter">
      <div className="h-16 bg-slate-900 border-b border-slate-800 px-6 flex items-center justify-between text-white shadow-xl z-20">
        <div className="flex items-center gap-6">
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-all"><X size={20} /></button>
          <div className="h-6 w-px bg-slate-800"></div>
          <h2 className="font-black tracking-tighter text-xl bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent uppercase">AI Media Lab</h2>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex bg-slate-800 p-1 rounded-xl">
            <button onClick={() => setZoom(prev => Math.max(0.05, prev - 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomOut size={16} /></button>
            <span className="px-3 flex items-center text-[10px] font-black text-slate-300 w-16 justify-center">{(zoom * 100).toFixed(0)}%</span>
            <button onClick={() => setZoom(prev => Math.min(5, prev + 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomIn size={16} /></button>
          </div>
          <button onClick={undo} disabled={history.length <= 1} className="p-2.5 bg-slate-800 hover:bg-slate-700 disabled:opacity-30 rounded-xl text-slate-300 transition-all"><Undo size={18} /></button>
          <button onClick={standardize} className="px-5 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-black flex items-center gap-2 border border-slate-700"><Maximize size={16} /> 1600*1600</button>
          <button onClick={handleFinalSave} className="px-8 py-2.5 bg-indigo-600 hover:bg-indigo-700 rounded-xl text-xs font-black shadow-lg flex items-center gap-2 transform active:scale-95 transition-all"><Save size={16} /> Save & Apply</button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        <div className="w-24 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-6 z-20 overflow-y-auto no-scrollbar relative">
          <ToolIcon active={currentTool === 'select'} onClick={() => { setCurrentTool('select'); }} icon={<MousePointer2 size={20} />} label="Select" />
          <ToolIcon active={currentTool === 'brush'} onClick={() => { setCurrentTool('brush'); setSelectedObjectId(null); }} icon={<Palette size={20} />} label="Brush" />
          <ToolIcon active={currentTool === 'ai-erase'} onClick={() => { setCurrentTool('ai-erase'); setSelectedObjectId(null); }} icon={<Eraser size={20} />} label="AI Erase" />

          {/* Shapes Entry */}
          <div className="relative">
            <ToolIcon 
              active={['rect', 'circle', 'line'].includes(currentTool)} 
              onClick={() => { setShowShapeMenu(!showShapeMenu); setCurrentTool(lastUsedShape); }} 
              icon={<ShapeIcon size={20} />} 
              label="Shapes" 
            />
            {showShapeMenu && (
              <div className="absolute left-full top-0 ml-2 bg-slate-800 border border-slate-700 p-2 rounded-xl shadow-2xl flex flex-col gap-2 z-50">
                <button onClick={() => { setCurrentTool('rect'); setLastUsedShape('rect'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 ${currentTool === 'rect' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Square size={20} /></button>
                <button onClick={() => { setCurrentTool('circle'); setLastUsedShape('circle'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 ${currentTool === 'circle' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Circle size={20} /></button>
                <button onClick={() => { setCurrentTool('line'); setLastUsedShape('line'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 ${currentTool === 'line' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Minus size={20} /></button>
              </div>
            )}
          </div>

          <ToolIcon active={currentTool === 'text'} onClick={() => { setCurrentTool('text'); setSelectedObjectId(null); }} icon={<Type size={20} />} label="Text" />
          <ToolIcon active={currentTool === 'select-fill'} onClick={() => { setCurrentTool('select-fill'); setSelectedObjectId(null); }} icon={<PaintBucket size={20} />} label="Fill" />
          <ToolIcon active={currentTool === 'crop'} onClick={() => { setCurrentTool('crop'); setSelectedObjectId(null); }} icon={<Scissors size={20} />} label="Crop" />

          <div className="mt-auto flex flex-col gap-4 pb-4">
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Stroke</span>
               <input type="color" value={strokeColor} onChange={(e) => setStrokeColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Fill</span>
               <input type="color" value={fillColor} onChange={(e) => setFillColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
          </div>
        </div>

        <div ref={containerRef} className="flex-1 bg-slate-950 overflow-auto flex items-center justify-center p-20 relative">
          <div className="relative shadow-2xl transition-transform duration-75 origin-center" style={{ transform: `scale(${zoom})` }}>
            <canvas ref={canvasRef} onMouseDown={handleStart} onMouseMove={handleMove} onMouseUp={handleEnd} className="block relative" style={{ cursor: currentTool === 'none' ? 'default' : currentTool === 'select' ? 'default' : 'crosshair' }} />

            <svg 
              className="absolute inset-0 pointer-events-none w-full h-full"
              viewBox={`0 0 ${canvasRef.current?.width || 0} ${canvasRef.current?.height || 0}`}
            >
              {objects.map(obj => (
                <g 
                  key={obj.id} 
                  className={selectedObjectId === obj.id ? 'opacity-100' : 'opacity-80'}
                  transform={`rotate(${(obj.rotation * 180) / Math.PI} ${obj.x + obj.width / 2} ${obj.y + obj.height / 2})`}
                  style={{ opacity: obj.opacity }}
                >
                  {obj.type === 'rect' && <rect x={obj.x} y={obj.y} width={obj.width} height={obj.height} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'circle' && <ellipse cx={obj.x + obj.width/2} cy={obj.y + obj.height/2} rx={obj.width/2} ry={obj.height/2} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'line' && <line x1={obj.x} y1={obj.y} x2={obj.x + obj.width} y2={obj.y + obj.height} stroke={obj.stroke} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'text' && (
                    <text 
                      x={obj.x} 
                      y={obj.y + obj.height/2} 
                      fill={obj.fill} 
                      stroke={obj.stroke} 
                      strokeWidth={obj.strokeWidth/4} 
                      style={{ font: `bold ${obj.strokeWidth * 6}px Inter, sans-serif` }}
                    >
                      {obj.text}
                    </text>
                  )}
                  {selectedObjectId === obj.id && (
                    <>
                      <rect 
                        x={obj.x} y={obj.y} width={obj.width} height={obj.height} 
                        fill="none" stroke="#6366f1" strokeWidth={2 / zoom} strokeDasharray="4"
                      />
                      <circle 
                        cx={obj.x + obj.width} cy={obj.y + obj.height} r={6 / zoom} 
                        fill="#6366f1" className="cursor-nwse-resize pointer-events-auto" 
                      />
                      <line x1={obj.x + obj.width/2} y1={obj.y} x2={obj.x + obj.width/2} y2={obj.y - 30/zoom} stroke="#6366f1" strokeWidth={2/zoom} />
                      <circle 
                        cx={obj.x + obj.width/2} cy={obj.y - 30/zoom} r={8 / zoom} 
                        fill="#6366f1" className="cursor-pointer pointer-events-auto"
                      />
                    </>
                  )}
                </g>
              ))}
            </svg>

            {selection && (['select-fill', 'crop'].includes(currentTool)) && (
               <div className="absolute pointer-events-none border-2 border-white" style={{ left: Math.min(selection.x1, selection.x2), top: Math.min(selection.y1, selection.y2), width: Math.abs(selection.x1 - selection.x2), height: Math.abs(selection.y1 - selection.y2) }}>
                 <div className="absolute inset-0 border-2 border-dashed border-black/50 animate-pulse"></div>
               </div>
            )}
          </div>

          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-8 bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-6 rounded-[2.5rem] shadow-2xl z-30 min-w-[700px]">
             <div className="flex flex-col gap-3 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Brush Size / Stroke</span>
                 <span className="text-[10px] font-black text-blue-400">{brushSize}px</span>
               </div>
               <input type="range" min="1" max="100" value={brushSize} onChange={(e) => setBrushSize(parseInt(e.target.value))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500" />
             </div>

             <div className="w-px h-8 bg-slate-800"></div>

             <div className="flex flex-col gap-3 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Opacity</span>
                 <span className="text-[10px] font-black text-indigo-400">{Math.round(opacity * 100)}%</span>
               </div>
               <input type="range" min="0" max="1" step="0.01" value={opacity} onChange={(e) => {
                 const v = parseFloat(e.target.value);
                 setOpacity(v);
                 if (selectedObjectId) {
                    setObjects(prev => prev.map(o => o.id === selectedObjectId ? { ...o, opacity: v } : o));
                 }
               }} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
             </div>

             {currentTool === 'ai-erase' && (
               <button onClick={runAIErase} disabled={isProcessing} className="px-8 py-3 bg-red-600 hover:bg-red-700 text-white rounded-2xl text-xs font-black shadow-xl flex items-center gap-3 transition-all active:scale-95 disabled:opacity-50">
                 {isProcessing ? <Loader2 className="animate-spin" size={16} /> : <Wand2 size={16} />} AI ERASE
               </button>
             )}
             {currentTool === 'select-fill' && (
               <button onClick={handleFill} disabled={!selection} className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">FILL AREA</button>
             )}
             {currentTool === 'crop' && (
               <button onClick={handleCrop} disabled={!selection} className="px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">CONFIRM CROP</button>
             )}
             {!['ai-erase', 'select-fill', 'crop'].includes(currentTool) && (
                <div className="px-6 text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 animate-pulse"></div>
                  {currentTool === 'select' ? (selectedObjectId ? 'Object Selected' : 'Select Tool') : `${currentTool} tool`}
                </div>
             )}
          </div>

          {isProcessing && <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/70 backdrop-blur-md"><Loader2 size={40} className="text-indigo-500 animate-spin" /><p className="mt-8 text-white font-black tracking-[0.3em] text-sm uppercase">AI Processing...</p></div>}
        </div>
      </div>
    </div>
  );
};

const ToolIcon = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1.5 group transition-all shrink-0 ${active ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>
    <div className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${active ? 'bg-indigo-600/10 border border-indigo-500/50 shadow-lg' : 'bg-slate-800/50 hover:bg-slate-800'}`}>
      {icon}
    </div>
    <span className="text-[8px] font-black uppercase tracking-tighter">{label}</span>
  </button>
);

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { 
  ArrowLeft, Sparkles, Image as ImageIcon, Edit2, Trash2, Plus, X,
  Globe, Languages, Loader2, DollarSign, Truck, Save, ChevronRight,
  Zap, Check, Weight, Ruler, ListFilter, FileText, Wand2, Search, 
  ExternalLink, Link2, Star, Maximize2, Hash, Cpu, Brain, AlertTriangle, Upload, Box
} from 'lucide-react';
import { Listing, OptimizedData, CleanedData, UILanguage, ExchangeRate, SourcingRecord } from '../types';
import { optimizeListingWithAI, translateListingWithAI } from '../services/geminiService';
import { optimizeListingWithOpenAI, translateListingWithOpenAI } from '../services/openaiService';
import { optimizeListingWithDeepSeek, translateListingWithDeepSeek } from '../services/deepseekService';
import { ImageEditor } from './ImageEditor';
import { SourcingModal } from './SourcingModal';
import { SourcingFormModal } from './SourcingFormModal';
import { supabase, isSupabaseConfigured } from '../lib/supabaseClient';
import { useTranslation } from '../lib/i18n';
import { AMAZON_MARKETPLACES } from '../lib/marketplaces';

interface ListingDetailProps {
  listing: Listing;
  onBack: () => void;
  onUpdate: (updatedListing: Listing) => void;
  onNext: () => void;
  uiLang: UILanguage;
}

type AIEngine = 'gemini' | 'openai' | 'deepseek';

const IMAGE_HOST_DOMAIN = 'https://img.hmstu.eu.org';
const TARGET_API = `${IMAGE_HOST_DOMAIN}/upload`; 
const CORS_PROXY = 'https://corsproxy.io/?';
const IMAGE_HOSTING_API = CORS_PROXY + encodeURIComponent(TARGET_API);

// Markets that MUST use Metric units (cm/kg) according to Amazon standards
const METRIC_MARKETS = ['DE', 'FR', 'IT', 'ES', 'JP', 'UK', 'CA', 'MX', 'PL', 'NL', 'SE', 'BE', 'SG', 'AU', 'EG'];

const normalizeUnit = (unit: string | undefined): string => {
  if (!unit) return "";
  const u = unit.toLowerCase().trim();
  if (u === 'lb' || u === 'lbs' || u === 'pounds') return "Pounds";
  if (u === 'kg' || u === 'kilograms') return "Kilograms";
  if (u === 'oz' || u === 'ounces') return "Ounces";
  if (u === 'g' || u === 'grams') return "Grams";
  if (u === 'in' || u === 'inches') return "Inches";
  if (u === 'cm' || u === 'centimeters') return "Centimeters";
  if (u === 'mm' || u === 'millimeters') return "Millimeters";
  return unit.charAt(0).toUpperCase() + unit.slice(1).toLowerCase();
};

export const ListingDetail: React.FC<ListingDetailProps> = ({ listing, onBack, onUpdate, onNext, uiLang }) => {
  const t = useTranslation(uiLang);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [activeMarket, setActiveMarket] = useState('US');
  const lastListingId = useRef(listing.id);

  const [engine, setEngine] = useState<AIEngine>(() => {
    const saved = localStorage.getItem('amzbot_preferred_engine');
    return (saved as AIEngine) || 'gemini';
  });

  useEffect(() => {
    localStorage.setItem('amzbot_preferred_engine', engine);
  }, [engine]);

  const [isOptimizing, setIsOptimizing] = useState(false);
  const [isBatchTranslating, setIsBatchTranslating] = useState(false);
  const [isStandardizing, setIsStandardizing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const [showImageEditor, setShowImageEditor] = useState(false);
  const [showSourcingModal, setShowSourcingModal] = useState(false);
  const [showSourcingForm, setShowSourcingForm] = useState<{show: boolean, data: SourcingRecord | null}>({show: false, data: null});

  const [localListing, setLocalListing] = useState<Listing>(listing);
  const [previewImage, setPreviewImage] = useState<string>(listing.cleaned?.main_image || '');
  const [exchangeRates, setExchangeRates] = useState<ExchangeRate[]>([]);

  useEffect(() => {
    if (lastListingId.current !== listing.id) {
      setActiveMarket('US');
      lastListingId.current = listing.id;
    }
    setLocalListing(listing);
    setPreviewImage(listing.cleaned?.main_image || '');
    fetchPricingData();
  }, [listing]);

  const fetchPricingData = async () => {
    if (!isSupabaseConfigured()) return;
    const { data } = await supabase.from('exchange_rates').select('*');
    if (data) setExchangeRates(data);
  };

  const syncToSupabase = async (targetListing: Listing) => {
    if (!isSupabaseConfigured()) return;
    setIsSaving(true);
    try {
      const { error } = await supabase.from('listings').update({
        cleaned: targetListing.cleaned,
        optimized: targetListing.optimized || null,
        translations: targetListing.translations || null,
        status: targetListing.status,
        sourcing_data: targetListing.sourcing_data || [],
        updated_at: new Date().toISOString()
      }).eq('id', targetListing.id);
      if (error) throw error;
      onUpdate({ ...targetListing, updated_at: new Date().toISOString() });
    } catch (e: any) { console.error("Auto-save failed:", e); } 
    finally { setIsSaving(false); }
  };

  // Centralized image upload helper
  const uploadImageToHost = async (dataUrlOrFile: string | File, asin: string): Promise<string> => {
    let file: File;
    if (typeof dataUrlOrFile === 'string') {
      const res = await fetch(dataUrlOrFile);
      const blob = await res.blob();
      file = new File([blob], `${asin}_${Date.now()}.jpg`, { type: 'image/jpeg' });
    } else {
      file = dataUrlOrFile;
    }

    const formDataBody = new FormData();
    formDataBody.append('file', file);
    const response = await fetch(IMAGE_HOSTING_API, { method: 'POST', body: formDataBody });
    if (!response.ok) throw new Error("Image hosting failed");
    const data = await response.json();
    return Array.isArray(data) && data[0]?.src ? `${IMAGE_HOST_DOMAIN}${data[0].src}` : data.url;
  };

  const getFieldValue = (optField: string, cleanField: string) => {
    const isMetric = METRIC_MARKETS.includes(activeMarket);

    if (optField.includes('unit')) {
      let rawUnit = "";
      if (activeMarket === 'US') {
        rawUnit = localListing.cleaned[cleanField];
      } else {
        const trans = localListing.translations?.[activeMarket];
        rawUnit = trans ? (trans as any)[optField] : '';
      }

      const normalized = normalizeUnit(rawUnit);
      if (normalized) return normalized;

      if (optField.includes('weight')) return isMetric ? "Kilograms" : "Pounds";
      if (optField.includes('size')) return isMetric ? "Centimeters" : "Inches";
      return "";
    }

    if (activeMarket === 'US') {
      const optVal = localListing.optimized ? (localListing.optimized as any)[optField] : null;
      if (optVal !== undefined && optVal !== null && (Array.isArray(optVal) ? optVal.length > 0 : optVal !== '')) {
        return optVal;
      }
      const cleanVal = (localListing.cleaned as any)[cleanField];
      if (cleanVal !== undefined && cleanVal !== null) return cleanVal;
      if (optField.includes('features')) return ['', '', '', '', ''];
      return '';
    }

    const trans = localListing.translations?.[activeMarket];
    if (trans && (trans as any)[optField] !== undefined && (trans as any)[optField] !== null) {
      const val = (trans as any)[optField];
      if (Array.isArray(val) ? val.length > 0 : val !== '') {
        return val;
      }
    }

    if (optField === 'optimized_price' || optField === 'optimized_shipping') {
      const sourceVal = localListing.cleaned[cleanField] || 0;
      const rate = exchangeRates.find(r => r.marketplace === activeMarket)?.rate || 1;
      const converted = sourceVal * rate;
      return activeMarket === 'JP' ? Math.round(converted) : parseFloat(converted.toFixed(2));
    }

    if (optField.includes('features')) return ['', '', '', '', ''];

    return '';
  };

  const getUpdatedListing = (field: string, value: any): Listing => {
    const nextListing = { ...localListing };
    if (activeMarket === 'US') {
      const cleanKey = field.startsWith('optimized_') ? field.replace('optimized_', '') : field;
      if (nextListing.status === 'optimized' && nextListing.optimized) {
        nextListing.optimized = { ...nextListing.optimized, [field]: value };
      } else {
        nextListing.cleaned = { ...nextListing.cleaned, [cleanKey]: value };
      }
    } else {
      const currentTranslations = { ...(nextListing.translations || {}) };
      const currentTrans = currentTranslations[activeMarket] || { optimized_title: '', optimized_features: ['', '', '', '', ''], optimized_description: '', search_keywords: '' } as OptimizedData;
      currentTranslations[activeMarket] = { ...currentTrans, [field]: value };
      nextListing.translations = currentTranslations;
    }
    return nextListing;
  };

  const updateField = (field: string, value: any) => {
    const next = getUpdatedListing(field, value);
    setLocalListing(next);
  };

  const handleImmediateUpdateAndSync = (field: string, value: any) => {
    const next = getUpdatedListing(field, value);
    setLocalListing(next);
    syncToSupabase(next);
  };

  const handleBatchStandardize = async () => {
    setIsStandardizing(true);
    try {
      const nextListing = { ...localListing };
      const allImgs = [nextListing.cleaned.main_image, ...(nextListing.cleaned.other_images || [])].filter(Boolean) as string[];
      const processed: string[] = [];

      const processImage = async (url: string): Promise<string> => {
        return new Promise((resolve, reject) => {
          const img = new Image();
          img.crossOrigin = "anonymous";
          img.src = `${CORS_PROXY}${encodeURIComponent(url)}`;
          img.onload = () => {
            const canvas = document.createElement('canvas');
            canvas.width = 1600; canvas.height = 1600;
            const ctx = canvas.getContext('2d');
            if (!ctx) return reject("Canvas failure");
            ctx.fillStyle = "#FFFFFF"; ctx.fillRect(0, 0, 1600, 1600);
            const scale = Math.min(1500 / img.width, 1500 / img.height);
            const w = img.width * scale; const h = img.height * scale;
            ctx.drawImage(img, (1600 - w) / 2, (1600 - h) / 2, w, h);
            resolve(canvas.toDataURL('image/jpeg', 0.9));
          };
          img.onerror = () => reject("Image load error");
        });
      };

      for (const url of allImgs) {
        const dataUrl = await processImage(url);
        // CRITICAL FIX: Upload the result to host, don't store DataURL in DB
        const hostedUrl = await uploadImageToHost(dataUrl, localListing.asin);
        processed.push(hostedUrl);
      }

      nextListing.cleaned.main_image = processed[0];
      nextListing.cleaned.other_images = processed.slice(1);
      setLocalListing(nextListing);
      setPreviewImage(processed[0]);
      await syncToSupabase(nextListing);
    } catch (e) { alert("Standardize failed: " + e); } 
    finally { setIsStandardizing(false); }
  };

  const handleAddImage = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsSaving(true);
    try {
      const url = await uploadImageToHost(file, localListing.asin);
      const nextListing = { ...localListing };
      nextListing.cleaned.other_images = [...(nextListing.cleaned.other_images || []), url];
      setLocalListing(nextListing);
      await syncToSupabase(nextListing);
    } catch (err) { alert("Upload failed"); } 
    finally { setIsSaving(false); }
  };

  const handleOptimize = async () => {
    setIsOptimizing(true);
    try {
      let opt: OptimizedData;
      if (engine === 'openai') opt = await optimizeListingWithOpenAI(localListing.cleaned!);
      else if (engine === 'deepseek') opt = await optimizeListingWithDeepSeek(localListing.cleaned!);
      else opt = await optimizeListingWithAI(localListing.cleaned!);
      const updated: Listing = { ...localListing, status: 'optimized', optimized: opt };
      setLocalListing(updated);
      await syncToSupabase(updated);
    } catch (e: any) { alert(`AI Optimization failed: ` + e.message); } 
    finally { setIsOptimizing(false); }
  };

  const handleBatchTranslate = async () => {
    setIsBatchTranslating(true);
    const nextListing = { ...localListing };
    const currentTranslations = { ...(nextListing.translations || {}) };
    for (const mkt of AMAZON_MARKETPLACES) {
      if (mkt.code === 'US') continue;
      try {
        const sourceData = localListing.optimized || {
          optimized_title: localListing.cleaned.title,
          optimized_features: localListing.cleaned.features || [],
          optimized_description: localListing.cleaned.description || '',
          search_keywords: localListing.cleaned.search_keywords || ''
        } as OptimizedData;

        let trans: Partial<OptimizedData>;
        if (engine === 'openai') trans = await translateListingWithOpenAI(sourceData, mkt.code);
        else if (engine === 'deepseek') trans = await translateListingWithDeepSeek(sourceData, mkt.code);
        else trans = await translateListingWithAI(sourceData, mkt.code);

        const rate = exchangeRates.find(r => r.marketplace === mkt.code)?.rate || 1;
        const isMetric = METRIC_MARKETS.includes(mkt.code);

        const rawWeight = parseFloat(localListing.optimized?.optimized_weight_value || localListing.cleaned.item_weight_value || '0');
        const rawL = parseFloat(localListing.optimized?.optimized_length || localListing.cleaned.item_length || '0');
        const rawW = parseFloat(localListing.optimized?.optimized_width || localListing.cleaned.item_width || '0');
        const rawH = parseFloat(localListing.optimized?.optimized_height || localListing.cleaned.item_height || '0');

        currentTranslations[mkt.code] = {
          ...trans,
          optimized_price: parseFloat(((localListing.cleaned.price || 0) * rate).toFixed(2)),
          optimized_shipping: parseFloat(((localListing.cleaned.shipping || 0) * rate).toFixed(2)),
          optimized_weight_value: isMetric ? (rawWeight * 0.45359).toFixed(2) : rawWeight.toFixed(2),
          optimized_weight_unit: isMetric ? 'Kilograms' : 'Pounds',
          optimized_length: isMetric ? (rawL * 2.54).toFixed(2) : rawL.toFixed(2),
          optimized_width: isMetric ? (rawW * 2.54).toFixed(2) : rawW.toFixed(2),
          optimized_height: isMetric ? (rawH * 2.54).toFixed(2) : rawH.toFixed(2),
          optimized_size_unit: isMetric ? 'Centimeters' : 'Inches',
        } as OptimizedData;
      } catch (e) {}
    }
    nextListing.translations = currentTranslations;
    setLocalListing(nextListing);
    await syncToSupabase(nextListing);
    setIsBatchTranslating(false);
  };

  const handleEditorSave = async (dataUrl: string) => {
    setIsSaving(true);
    try {
      const hostedUrl = await uploadImageToHost(dataUrl, localListing.asin);
      // Determine if we are editing the main image or one of the others
      const isMain = previewImage === localListing.cleaned.main_image;
      const nextListing = { ...localListing };
      if (isMain) {
        nextListing.cleaned.main_image = hostedUrl;
      } else {
        const others = [...(localListing.cleaned.other_images || [])];
        const idx = others.indexOf(previewImage);
        if (idx !== -1) others[idx] = hostedUrl;
        nextListing.cleaned.other_images = others;
      }
      setLocalListing(nextListing);
      setPreviewImage(hostedUrl);
      await syncToSupabase(nextListing);
      setShowImageEditor(false);
    } catch (e) {
      alert("Failed to save edited image: " + e);
    } finally {
      setIsSaving(false);
    }
  };

  const allImages = [localListing.cleaned.main_image, ...(localListing.cleaned.other_images || [])].filter(Boolean) as string[];

  return (
    <div className="flex flex-col h-screen bg-slate-50 font-inter overflow-hidden">
      <header className="flex-shrink-0 bg-white border-b border-slate-200 px-8 py-4 flex items-center justify-between shadow-sm z-50">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="group flex items-center text-slate-500 hover:text-slate-900 font-black text-xs uppercase tracking-widest transition-all">
            <ArrowLeft size={18} className="mr-2 group-hover:-translate-x-1 transition-transform" /> {t('back')}
          </button> 
          <div className="h-6 w-px bg-slate-200"></div>
          <div className="flex bg-slate-100 p-1 rounded-2xl border border-slate-200">
             <EngineBtn active={engine === 'gemini'} onClick={() => setEngine('gemini')} icon={<Zap size={14}/>} label="Gemini 3" />
             <EngineBtn active={engine === 'openai'} onClick={() => setEngine('openai')} icon={<Brain size={14}/>} label="GPT-4o" />
             <EngineBtn active={engine === 'deepseek'} onClick={() => setEngine('deepseek')} icon={<Cpu size={14}/>} label="DeepSeek" />
          </div>
        </div>

        <div className="flex gap-3">
          {isSaving && <div className="flex items-center gap-2 px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[9px] font-black uppercase animate-pulse"><Loader2 className="animate-spin" size={12} /> Syncing</div>}
          <button onClick={handleOptimize} disabled={isOptimizing} className="flex items-center gap-2 px-6 py-2.5 rounded-2xl font-black text-xs text-indigo-600 bg-indigo-50 border border-indigo-100 hover:bg-indigo-100 transition-all uppercase shadow-sm">
            {isOptimizing ? <Loader2 className="animate-spin" size={16} /> : <Sparkles size={16} />} AI Optimize
          </button>
          <button onClick={() => syncToSupabase(localListing)} disabled={isSaving} className="flex items-center gap-2 px-8 py-2.5 rounded-2xl font-black text-xs text-white bg-slate-900 hover:bg-black shadow-xl active:scale-95 transition-all uppercase tracking-widest">
            {isSaving ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />} {t('save')}
          </button>
          <button onClick={onNext} className="p-2.5 bg-slate-100 text-slate-400 hover:text-slate-900 rounded-xl transition-all border border-slate-200">
            <ChevronRight size={20} />
          </button>
        </div>
      </header>

      <div className="flex-1 overflow-y-auto custom-scrollbar p-8">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
          <div className="lg:col-span-4 space-y-6 sticky top-0">
             <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
                <div className="aspect-square bg-slate-50 rounded-3xl border border-slate-100 overflow-hidden relative flex items-center justify-center group mb-6">
                   <img src={previewImage} className="max-w-full max-h-full object-contain mix-blend-multiply transition-transform duration-700 group-hover:scale-110" />
                   <div className="absolute bottom-4 right-4 flex gap-2">
                      <button onClick={handleBatchStandardize} disabled={isStandardizing} className="px-4 py-2 bg-white/90 backdrop-blur-md rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center gap-2 border border-slate-100 hover:bg-indigo-600 hover:text-white transition-all">
                        {isStandardizing ? <Loader2 className="animate-spin" size={12} /> : <Box size={12} />} 1600 Standard
                      </button>
                      <button onClick={() => setShowImageEditor(true)} className="px-4 py-2 bg-white/90 backdrop-blur-md rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center gap-2 border border-slate-100 hover:bg-indigo-600 hover:text-white transition-all">
                         <Wand2 size={12} /> AI Editor
                      </button>
                   </div>
                </div>
                <div className="flex gap-2 overflow-x-auto custom-scrollbar pb-3">
                   {allImages.map((img, i) => (
                     <div key={i} onMouseEnter={() => setPreviewImage(img)} className={`group/thumb relative w-16 h-16 rounded-xl border-2 shrink-0 cursor-pointer overflow-hidden transition-all ${previewImage === img ? 'border-indigo-500 shadow-lg' : 'border-transparent opacity-60'}`}>
                        <img src={img} className="w-full h-full object-cover" />
                        <div className="absolute inset-0 bg-black/40 flex items-center justify-center gap-1 opacity-0 group-hover/thumb:opacity-100 transition-opacity">
                           <button onClick={(e) => { e.stopPropagation(); updateField('main_image', img); setPreviewImage(img); }} className="p-1 text-white hover:text-amber-400" title="Set as Main"><Star size={12} fill={img === localListing.cleaned.main_image ? "currentColor" : "none"} /></button>
                           <button onClick={(e) => { e.stopPropagation(); const others = (localListing.cleaned.other_images || []).filter(u => u !== img); updateField('other_images', others); }} className="p-1 text-white hover:text-red-400" title="Delete"><Trash2 size={12} /></button>
                        </div>
                     </div>
                   ))}
                   <button onClick={() => fileInputRef.current?.click()} className="w-16 h-16 rounded-xl border-2 border-dashed border-slate-200 flex items-center justify-center text-slate-300 hover:border-indigo-400 hover:text-indigo-600 transition-all shrink-0">
                      <Plus size={20} />
                   </button>
                   <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleAddImage} />
                </div>
             </div>
          </div>

          <div className="lg:col-span-8 space-y-8">
             <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
                <div className="px-10 py-6 border-b border-slate-50 bg-slate-50/50 flex flex-col md:flex-row items-center justify-between gap-6">
                   <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-inner overflow-x-auto custom-scrollbar no-scrollbar">
                      <button onClick={() => setActiveMarket('US')} className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase transition-all shrink-0 ${activeMarket === 'US' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>🇺🇸 US Master</button>
                      {AMAZON_MARKETPLACES.filter(m => m.code !== 'US').map(m => (
                        <button key={m.code} onClick={() => setActiveMarket(m.code)} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase transition-all shrink-0 ${activeMarket === m.code ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}>{m.flag} {m.code}</button>
                      ))}
                   </div>
                   <button onClick={handleBatchTranslate} disabled={isBatchTranslating} className="flex items-center gap-2 px-6 py-2.5 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-lg shrink-0">
                      {isBatchTranslating ? <Loader2 size={14} className="animate-spin" /> : <Languages size={14} />} Batch Translate All
                   </button>
                </div>

                <div className="p-10 space-y-10">
                   <div className="grid grid-cols-2 gap-8 items-end">
                      <div className="space-y-3">
                         <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2"><DollarSign size={14} className="text-emerald-500" /> Price ({activeMarket})</label>
                         <input 
                           type="number" step="0.01" 
                           value={getFieldValue('optimized_price', 'price')}
                           onChange={(e) => updateField('optimized_price', parseFloat(e.target.value))}
                           onBlur={() => syncToSupabase(localListing)}
                           className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-2xl focus:bg-white focus:border-emerald-500 outline-none transition-all" 
                         />
                      </div>
                      <div className="space-y-3">
                         <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2"><Truck size={14} className="text-blue-500" /> Shipping Cost</label>
                         <input 
                           type="number" step="0.01" 
                           value={getFieldValue('optimized_shipping', 'shipping')}
                           onChange={(e) => updateField('optimized_shipping', parseFloat(e.target.value))}
                           onBlur={() => syncToSupabase(localListing)}
                           className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-2xl focus:bg-white focus:border-blue-500 outline-none transition-all" 
                         />
                      </div>
                   </div>

                   <div className="grid grid-cols-2 gap-8 items-end">
                      <div className="space-y-3">
                         <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2"><Weight size={14} className="text-amber-500" /> Weight</label>
                         <div className="flex gap-2">
                           <input 
                            type="text" 
                            value={getFieldValue('optimized_weight_value', 'item_weight_value')} 
                            onChange={e => updateField('optimized_weight_value', e.target.value)} 
                            onBlur={() => syncToSupabase(localListing)}
                            className="flex-1 px-5 py-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold outline-none" 
                           />
                           <select 
                            value={getFieldValue('optimized_weight_unit', 'item_weight_unit')} 
                            onChange={e => handleImmediateUpdateAndSync('optimized_weight_unit', e.target.value)} 
                            className="w-48 px-2 bg-white border border-slate-200 rounded-2xl font-black text-[10px] uppercase"
                           >
                             <option value="Pounds">Pounds</option>
                             <option value="Kilograms">Kilograms</option>
                             <option value="Ounces">Ounces</option>
                             <option value="Grams">Grams</option>
                           </select>
                         </div>
                      </div>
                      <div className="space-y-3">
                         <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2"><Ruler size={14} className="text-indigo-500" /> Dimensions (L / W / H)</label>
                         <div className="flex gap-2">
                           <div className="grid grid-cols-3 gap-1 flex-1">
                              <input placeholder="L" type="text" value={getFieldValue('optimized_length', 'item_length')} onChange={e => updateField('optimized_length', e.target.value)} onBlur={() => syncToSupabase(localListing)} className="w-full px-2 py-4 bg-slate-50 border border-slate-200 rounded-xl text-center font-bold text-xs" />
                              <input placeholder="W" type="text" value={getFieldValue('optimized_width', 'item_width')} onChange={e => updateField('optimized_width', e.target.value)} onBlur={() => syncToSupabase(localListing)} className="w-full px-2 py-4 bg-slate-50 border border-slate-200 rounded-xl text-center font-bold text-xs" />
                              <input placeholder="H" type="text" value={getFieldValue('optimized_height', 'item_height')} onChange={e => updateField('optimized_height', e.target.value)} onBlur={() => syncToSupabase(localListing)} className="w-full px-2 py-4 bg-slate-50 border border-slate-200 rounded-xl text-center font-bold text-xs" />
                           </div>
                           <select 
                            value={getFieldValue('optimized_size_unit', 'item_size_unit')} 
                            onChange={e => handleImmediateUpdateAndSync('optimized_size_unit', e.target.value)} 
                            className="w-48 px-2 bg-white border border-slate-200 rounded-2xl font-black text-[10px] uppercase"
                           >
                             <option value="Inches">Inches</option>
                             <option value="Centimeters">Centimeters</option>
                             <option value="Millimeters">Millimeters</option>
                           </select>
                         </div>
                      </div>
                   </div>

                   <EditSection 
                    label="Product Title" icon={<ImageIcon size={14}/>} 
                    value={getFieldValue('optimized_title', 'title')}
                    onChange={v => updateField('optimized_title', v)}
                    onBlur={() => syncToSupabase(localListing)}
                    limit={200} className="text-xl font-black leading-snug"
                   />

                   <div className="space-y-4">
                      <div className="flex items-center justify-between ml-1">
                         <label className="text-[10px] font-black text-indigo-500 uppercase tracking-widest flex items-center gap-2"><ListFilter size={14} /> Key Features (Bullets)</label>
                         <button onClick={() => {
                            const currentFeatures = getFieldValue('optimized_features', 'features');
                            updateField('optimized_features', [...currentFeatures, ""]);
                         }} className="p-1 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-100 transition-all"><Plus size={16}/></button>
                      </div>
                      <div className="space-y-3">
                         {getFieldValue('optimized_features', 'features').map((f: string, i: number) => (
                           <div key={i} className="flex gap-4 group">
                              <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-[10px] font-black text-slate-400 shrink-0 mt-2 border border-slate-200 group-hover:bg-indigo-600 group-hover:text-white transition-all">{i+1}</div>
                              <div className="flex-1 space-y-1">
                                 <textarea 
                                   value={f || ''}
                                   onChange={(e) => {
                                     const currentFeatures = [...getFieldValue('optimized_features', 'features')];
                                     currentFeatures[i] = e.target.value;
                                     updateField('optimized_features', currentFeatures);
                                   }}
                                   onBlur={() => syncToSupabase(localListing)}
                                   className={`w-full p-4 bg-slate-50 border rounded-2xl text-sm font-bold leading-relaxed focus:bg-white outline-none transition-all border-slate-200 focus:border-indigo-500`}
                                   placeholder={`Bullet Point ${i+1}...`}
                                 />
                                 <div className="flex justify-between items-center px-1">
                                    <span className={`text-[9px] font-black uppercase ${(f || '').length > 500 ? 'text-red-500' : 'text-slate-400'}`}>{(f || '').length} / 500</span>
                                    <button onClick={() => {
                                      const currentFeatures = [...getFieldValue('optimized_features', 'features')].filter((_, idx) => idx !== i);
                                      updateField('optimized_features', currentFeatures);
                                      const next = getUpdatedListing('optimized_features', currentFeatures);
                                      syncToSupabase(next);
                                    }} className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={12}/></button>
                                 </div>
                              </div>
                           </div>
                         ))}
                      </div>
                   </div>

                   <EditSection 
                    label="Product Description (HTML)" icon={<FileText size={14}/>} 
                    value={getFieldValue('optimized_description', 'description')}
                    onChange={v => updateField('optimized_description', v)}
                    onBlur={() => syncToSupabase(localListing)}
                    limit={2000} isMono className="min-h-[250px] text-xs leading-loose"
                   />

                   <EditSection 
                    label="Search Keywords" icon={<Hash size={14}/>} 
                    value={getFieldValue('search_keywords', 'search_keywords')}
                    onChange={v => updateField('search_keywords', v)}
                    onBlur={() => syncToSupabase(localListing)}
                    limit={250} className="bg-amber-50/20 border-amber-100 focus:border-amber-400 text-sm font-bold"
                   />
                </div>
             </div>

             {/* Sourcing Center */}
             <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm p-10 space-y-8 mt-8">
                <div className="flex items-center justify-between">
                   <div className="flex items-center gap-3">
                      <div className="w-12 h-12 bg-orange-500 rounded-2xl flex items-center justify-center text-white shadow-xl"><Link2 size={24} /></div>
                      <div>
                        <h3 className="text-xl font-black text-slate-900 tracking-tight">Supply Chain Discovery</h3>
                        <p className="text-xs text-slate-400 font-bold">Manage wholesale sources and manufacturer benchmarks.</p>
                      </div>
                   </div>
                   <div className="flex gap-3">
                      <button onClick={() => setShowSourcingModal(true)} className="flex items-center gap-2 px-6 py-2.5 bg-orange-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-orange-700 transition-all"><Search size={14} /> AI Visual Search</button>
                      <button onClick={() => setShowSourcingForm({show: true, data: null})} className="flex items-center gap-2 px-6 py-2.5 bg-white border border-slate-200 text-slate-600 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-50 transition-all"><Plus size={14} /> Manual Record</button>
                   </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                   {(localListing.sourcing_data || []).map((s, idx) => (
                     <div key={idx} className="group bg-slate-50 border border-slate-100 p-5 rounded-3xl flex items-center gap-5 relative hover:bg-white hover:shadow-2xl hover:border-orange-200 transition-all">
                        <div className="w-16 h-16 bg-white rounded-xl overflow-hidden border border-slate-200 shrink-0">
                           <img src={s.image} className="w-full h-full object-cover" />
                        </div>
                        <div className="flex-1 overflow-hidden">
                           <p className="text-xs font-black text-slate-900 truncate">{s.title}</p>
                           <p className="text-orange-600 font-black text-lg mt-0.5">{s.price}</p>
                           <div className="flex items-center gap-3 mt-2">
                              <a href={s.url} target="_blank" className="inline-flex items-center gap-1.5 text-[9px] font-black text-slate-400 hover:text-blue-600 uppercase tracking-widest transition-colors">Supplier <ExternalLink size={10} /></a>
                              <button onClick={() => setShowSourcingForm({show: true, data: s})} className="text-[9px] font-black text-slate-400 hover:text-indigo-600 uppercase tracking-widest transition-colors">Edit</button>
                           </div>
                        </div>
                        <button onClick={() => { 
                          const next = { ...localListing, sourcing_data: (localListing.sourcing_data || []).filter((_, i) => i !== idx) }; 
                          setLocalListing(next); syncToSupabase(next); 
                        }} className="absolute top-4 right-4 p-1.5 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={14} /></button>
                     </div>
                   ))}
                   {(localListing.sourcing_data || []).length === 0 && (
                     <div className="col-span-2 py-16 bg-slate-50 border-2 border-dashed border-slate-100 rounded-[2.5rem] flex flex-col items-center justify-center opacity-30"><Link2 size={32} className="mb-3" /><p className="text-[10px] font-black uppercase tracking-widest">No sourcing data attached</p></div>
                   )}
                </div>
             </div>
          </div>
        </div>
      </div>

      {showSourcingForm.show && (
        <SourcingFormModal 
          initialData={showSourcingForm.data} 
          onClose={() => setShowSourcingForm({show: false, data: null})} 
          onSave={(res) => {
            const nextData = [...(localListing.sourcing_data || [])];
            const existingIdx = nextData.findIndex(s => s.id === res.id);
            if (existingIdx >= 0) nextData[existingIdx] = res;
            else nextData.push(res);
            const next = { ...localListing, sourcing_data: nextData };
            setLocalListing(next); syncToSupabase(next); setShowSourcingForm({show: false, data: null});
          }} 
        />
      )}

      {showSourcingModal && (
        <SourcingModal productImage={previewImage} onClose={() => setShowSourcingModal(false)} onAddLink={(res) => {
            const next = { ...localListing, sourcing_data: [...(localListing.sourcing_data || []), res] };
            setLocalListing(next); syncToSupabase(next); setShowSourcingModal(false);
          }}
        />
      )}

      {showImageEditor && <ImageEditor imageUrl={previewImage} onClose={() => setShowImageEditor(false)} onSave={handleEditorSave} uiLang={uiLang} />}
    </div>
  );
};

const EngineBtn = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase flex items-center gap-2 transition-all ${active ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}>
    {icon} {label}
  </button>
);

const EditSection = ({ label, icon, value, onChange, onBlur, limit, isMono, className }: any) => (
  <div className="space-y-3">
    <div className="flex items-center justify-between ml-1">
      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
        {icon} {label}
      </label>
      {limit && (
        <span className={`text-[9px] font-black uppercase ${(value || '').length > limit ? 'text-red-500' : 'text-slate-400'}`}>
          {(value || '').length} / {limit}
        </span>
      )}
    </div>
    <textarea 
      value={value || ''}
      onChange={(e) => onChange(e.target.value)}
      onBlur={onBlur}
      className={`w-full p-6 bg-slate-50 border rounded-[2rem] font-bold outline-none transition-all focus:bg-white ${isMono ? 'font-mono' : ''} ${(value || '').length > (limit || 99999) ? 'border-red-500 ring-2 ring-red-100' : 'border-slate-200 focus:border-indigo-500'} ${className}`}
    />
  </div>
);

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  X, Eraser, Scissors, PaintBucket, Crop, Save, Undo, 
  Wand2, Loader2, Download, MousePointer2, Maximize, 
  Type, Square, Circle, Minus, Move, Palette, Trash2,
  ZoomIn, ZoomOut, RotateCcw, Box, ArrowUpRight, RefreshCw, 
  Shapes, ChevronRight
} from 'lucide-react';
import { editImageWithAI } from '../services/geminiService';
import { UILanguage } from '../types';

interface ImageEditorProps {
  imageUrl: string;
  onClose: () => void;
  onSave: (newImageUrl: string) => void;
  uiLang: UILanguage;
}

type Tool = 'select' | 'select-fill' | 'brush' | 'ai-erase' | 'crop' | 'rect' | 'circle' | 'line' | 'text' | 'none';

interface EditorObject {
  id: string;
  type: 'rect' | 'circle' | 'line' | 'text';
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number; 
  stroke: string;
  fill: string;
  strokeWidth: number;
  opacity: number; // 0 to 1
  text?: string;
}

interface EditorState {
  canvasData: string;
  objects: EditorObject[];
}

interface SelectionBox {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
}

const CORS_PROXY = 'https://corsproxy.io/?';

export const ImageEditor: React.FC<ImageEditorProps> = ({ imageUrl, onClose, onSave, uiLang }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [currentTool, setCurrentTool] = useState<Tool>('select');
  const [isProcessing, setIsProcessing] = useState(false);
  const [strokeColor, setStrokeColor] = useState('#000000');
  const [fillColor, setFillColor] = useState('#ffffff');
  const [brushSize, setBrushSize] = useState(5);
  const [opacity, setOpacity] = useState(1); // 1.0 = 100%
  const [zoom, setZoom] = useState(1);

  // Shape menu state
  const [showShapeMenu, setShowShapeMenu] = useState(false);
  const [lastUsedShape, setLastUsedShape] = useState<'rect' | 'circle' | 'line'>('rect');

  // Object system
  const [objects, setObjects] = useState<EditorObject[]>([]);
  const [selectedObjectId, setSelectedObjectId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [isRotating, setIsRotating] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const [isDrawing, setIsDrawing] = useState(false);
  const [selection, setSelection] = useState<SelectionBox | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });

  const [history, setHistory] = useState<EditorState[]>([]);

  const saveToHistory = useCallback((currentObjects?: EditorObject[]) => {
    const canvas = canvasRef.current;
    if (canvas) {
      const newState: EditorState = {
        canvasData: canvas.toDataURL('image/png'),
        objects: currentObjects ? [...currentObjects] : [...objects]
      };
      setHistory(prev => [...prev.slice(-30), newState]);
    }
  }, [objects]);

  useEffect(() => {
    const initCanvas = async () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d', { willReadFrequently: true }) as CanvasRenderingContext2D | null;
      if (!ctx) return;

      setIsProcessing(true);
      try {
        const proxyUrl = `${CORS_PROXY}${encodeURIComponent(imageUrl)}`;
        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error("Failed to fetch image through proxy");
        const blob = await response.blob();
        const localUrl = URL.createObjectURL(blob);

        const img = new Image();
        img.src = localUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);

          if (containerRef.current) {
            const padding = 120;
            const availableW = containerRef.current.clientWidth - padding;
            const availableH = containerRef.current.clientHeight - padding;
            const scale = Math.min(availableW / img.width, availableH / img.height, 1);
            setZoom(scale || 1);
          }

          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
          URL.revokeObjectURL(localUrl);
        };
      } catch (err) {
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.src = imageUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          (ctx as CanvasRenderingContext2D).drawImage(img, 0, 0);
          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
        };
      }
    };
    initCanvas();
  }, [imageUrl]);

  const undo = () => {
    if (history.length <= 1) return;
    const newHistory = [...history];
    newHistory.pop(); 
    const prevState = newHistory[newHistory.length - 1];

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (canvas && ctx && prevState) {
      const img = new Image();
      img.src = prevState.canvasData;
      img.onload = () => {
        canvas.width = img.width;
        canvas.height = img.height;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        setObjects(prevState.objects);
        setHistory(newHistory);
      };
    }
  };

  const standardize = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const currentData = canvas.toDataURL();
    const tempImg = new Image();
    tempImg.src = currentData;
    tempImg.onload = () => {
      const targetSize = 1600;
      const safeArea = 1500;
      canvas.width = targetSize;
      canvas.height = targetSize;
      const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, targetSize, targetSize);
      const scale = Math.min(safeArea / tempImg.width, safeArea / tempImg.height);
      const drawW = tempImg.width * scale;
      const drawH = tempImg.height * scale;
      const x = (targetSize - drawW) / 2;
      const y = (targetSize - drawH) / 2;
      ctx.drawImage(tempImg, x, y, drawW, drawH);
      saveToHistory();
      if (containerRef.current) {
        setZoom(Math.min((containerRef.current.clientHeight - 120) / 1600, 1));
      }
    };
  };

  const getMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }
    return {
      x: (clientX - rect.left) / zoom,
      y: (clientY - rect.top) / zoom
    };
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);
    setStartPos(pos);

    if (currentTool === 'select') {
      if (selectedObjectId) {
        const obj = objects.find(o => o.id === selectedObjectId);
        if (obj) {
          const handleSize = 12 / zoom;
          const rotateHandleY = obj.y - 30 / zoom;
          const centerX = obj.x + obj.width / 2;

          const distToRotate = Math.sqrt(Math.pow(pos.x - centerX, 2) + Math.pow(pos.y - rotateHandleY, 2));
          if (distToRotate < handleSize) {
            setIsRotating(true);
            return;
          }

          const isOverResizeHandle = 
            pos.x >= obj.x + obj.width - handleSize && 
            pos.x <= obj.x + obj.width + handleSize && 
            pos.y >= obj.y + obj.height - handleSize && 
            pos.y <= obj.y + obj.height + handleSize;

          if (isOverResizeHandle) {
            setIsResizing(true);
            return;
          }

          const isOverBody = 
            pos.x >= obj.x && pos.x <= obj.x + obj.width &&
            pos.y >= obj.y && pos.y <= obj.y + obj.height;

          if (isOverBody) {
            setIsDragging(true);
            setDragOffset({ x: pos.x - obj.x, y: pos.y - obj.y });
            return;
          }
        }
      }

      const hit = objects.slice().reverse().find(obj => 
        pos.x >= obj.x && pos.x <= obj.x + obj.width &&
        pos.y >= obj.y && pos.y <= obj.y + obj.height
      );

      if (hit) {
        setSelectedObjectId(hit.id);
        setIsDragging(true);
        setDragOffset({ x: pos.x - hit.x, y: pos.y - hit.y });
      } else {
        setSelectedObjectId(null);
      }
      return;
    }

    setIsDrawing(true);
    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection({ x1: pos.x, y1: pos.y, x2: pos.x, y2: pos.y });
    }

    if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.beginPath();
        ctx.moveTo(pos.x, pos.y);
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.globalAlpha = opacity;
        ctx.strokeStyle = currentTool === 'ai-erase' ? 'rgba(255, 0, 0, 0.6)' : strokeColor;
        ctx.lineWidth = brushSize;
      }
    }
  };

  const handleMove = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);

    if (currentTool === 'select' && selectedObjectId) {
      const obj = objects.find(o => o.id === selectedObjectId);
      if (!obj) return;

      if (isDragging) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, x: pos.x - dragOffset.x, y: pos.y - dragOffset.y }
            : o
        ));
      } else if (isResizing) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, width: Math.max(10, pos.x - o.x), height: Math.max(10, pos.y - o.y) }
            : o
        ));
      } else if (isRotating) {
        const centerX = obj.x + obj.width / 2;
        const centerY = obj.y + obj.height / 2;
        const angle = Math.atan2(pos.y - centerY, pos.x - centerX) + Math.PI / 2;
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId ? { ...o, rotation: angle } : o
        ));
      }
      return;
    }

    if (!isDrawing) return;

    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection(prev => prev ? { ...prev, x2: pos.x, y2: pos.y } : null);
    } else if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.lineTo(pos.x, pos.y);
        ctx.stroke();
      }
    }
  };

  const handleEnd = (e: React.MouseEvent | React.TouchEvent) => {
    if (currentTool === 'select') {
      if (isDragging || isResizing || isRotating) {
        saveToHistory(objects);
      }
      setIsDragging(false);
      setIsResizing(false);
      setIsRotating(false);
      return;
    }

    if (!isDrawing) return;
    setIsDrawing(false);

    const pos = getMousePos(e);

    if (['rect', 'circle', 'line'].includes(currentTool)) {
      const newObj: EditorObject = {
        id: crypto.randomUUID(),
        type: currentTool as any,
        x: Math.min(startPos.x, pos.x),
        y: Math.min(startPos.y, pos.y),
        width: Math.abs(startPos.x - pos.x),
        height: Math.abs(startPos.y - pos.y),
        rotation: 0,
        stroke: strokeColor,
        fill: fillColor,
        strokeWidth: brushSize,
        opacity: opacity
      };
      const nextObjects = [...objects, newObj];
      setObjects(nextObjects);
      setSelectedObjectId(newObj.id);
      setCurrentTool('select');
      setSelection(null);
      saveToHistory(nextObjects);
    } else if (currentTool === 'text') {
      const text = window.prompt(uiLang === 'zh' ? "输入文字:" : "Enter text:");
      if (text) {
        const newObj: EditorObject = {
          id: crypto.randomUUID(),
          type: 'text',
          x: pos.x,
          y: pos.y,
          width: text.length * brushSize * 3,
          height: brushSize * 6,
          rotation: 0,
          stroke: strokeColor,
          fill: fillColor,
          strokeWidth: brushSize,
          opacity: opacity,
          text: text
        };
        const nextObjects = [...objects, newObj];
        setObjects(nextObjects);
        setSelectedObjectId(newObj.id);
        setCurrentTool('select');
        saveToHistory(nextObjects);
      }
    } else if (currentTool === 'brush') {
      saveToHistory();
    }
  };

  const handleFill = () => {
    if (currentTool !== 'select-fill' || !selection) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);

    ctx.save();
    ctx.globalAlpha = opacity;
    ctx.fillStyle = fillColor;
    ctx.fillRect(x, y, w, h);
    ctx.restore();

    saveToHistory();
    setSelection(null); 
    setCurrentTool('select');
  };

  const handleCrop = () => {
    if (!selection) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    if (w < 5 || h < 5) return;
    const imageData = ctx.getImageData(x, y, w, h);
    canvas.width = w;
    canvas.height = h;
    ctx.putImageData(imageData, 0, 0);
    saveToHistory();
    setSelection(null);
    setZoom(1);
    setCurrentTool('select');
  };

  const runAIErase = async () => {
    setIsProcessing(true);
    try {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const base64 = canvas.toDataURL('image/jpeg', 0.9).split(',')[1];
      const result = await editImageWithAI(base64, "Please erase the red highlighted areas cleanly.");
      const img = new Image();
      img.src = `data:image/jpeg;base64,${result}`;
      img.onload = () => {
        const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        saveToHistory();
        setIsProcessing(false);
      };
    } catch (e: any) {
      alert("AI Erase failed: " + e.message);
      setIsProcessing(false);
    }
  };

  const handleFinalSave = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Draw all objects onto the canvas before saving
    objects.forEach(obj => {
      ctx.save();
      const cx = obj.x + obj.width / 2;
      const cy = obj.y + obj.height / 2;

      ctx.translate(cx, cy);
      ctx.rotate(obj.rotation);
      ctx.translate(-cx, -cy);

      ctx.globalAlpha = obj.opacity;
      ctx.strokeStyle = obj.stroke;
      ctx.fillStyle = obj.fill;
      ctx.lineWidth = obj.strokeWidth;
      ctx.lineCap = 'round';

      if (obj.type === 'rect') {
        ctx.beginPath();
        ctx.rect(obj.x, obj.y, obj.width, obj.height);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'circle') {
        const r = Math.sqrt(obj.width * obj.width + obj.height * obj.height) / 2;
        ctx.beginPath();
        ctx.arc(obj.x + obj.width/2, obj.y + obj.height/2, r, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'line') {
        ctx.beginPath();
        ctx.moveTo(obj.x, obj.y);
        ctx.lineTo(obj.x + obj.width, obj.y + obj.height);
        ctx.stroke();
      } else if (obj.type === 'text' && obj.text) {
        ctx.font = `bold ${obj.strokeWidth * 6}px Inter, sans-serif`;
        ctx.fillText(obj.text, obj.x, obj.y);
        ctx.strokeText(obj.text, obj.x, obj.y);
      }
      ctx.restore();
    });

    onSave(canvas.toDataURL('image/jpeg', 0.95));
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.key === 'Delete' || e.key === 'Backspace')) {
         if (selectedObjectId) {
            const nextObjects = objects.filter(o => o.id !== selectedObjectId);
            setObjects(nextObjects);
            setSelectedObjectId(null);
            saveToHistory(nextObjects);
         } else if (currentTool === 'select-fill' && selection) {
            handleFill();
         }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedObjectId, objects, saveToHistory, currentTool, selection, fillColor, opacity]);

  const ShapeIcon = lastUsedShape === 'rect' ? Square : lastUsedShape === 'circle' ? Circle : Minus;

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col font-inter">
      <div className="h-16 bg-slate-900 border-b border-slate-800 px-6 flex items-center justify-between text-white shadow-xl z-20">
        <div className="flex items-center gap-6">
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-all"><X size={20} /></button>
          <div className="h-6 w-px bg-slate-800"></div>
          <h2 className="font-black tracking-tighter text-xl bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent uppercase">AI Media Lab</h2>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex bg-slate-800 p-1 rounded-xl">
            <button onClick={() => setZoom(prev => Math.max(0.05, prev - 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomOut size={16} /></button>
            <span className="px-3 flex items-center text-[10px] font-black text-slate-300 w-16 justify-center">{(zoom * 100).toFixed(0)}%</span>
            <button onClick={() => setZoom(prev => Math.min(5, prev + 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomIn size={16} /></button>
          </div>
          <button onClick={undo} disabled={history.length <= 1} className="p-2.5 bg-slate-800 hover:bg-slate-700 disabled:opacity-30 rounded-xl text-slate-300 transition-all"><Undo size={18} /></button>
          <button onClick={standardize} className="px-5 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-black flex items-center gap-2 border border-slate-700"><Maximize size={16} /> 1600*1600</button>
          <button onClick={handleFinalSave} className="px-8 py-2.5 bg-indigo-600 hover:bg-indigo-700 rounded-xl text-xs font-black shadow-lg flex items-center gap-2 transform active:scale-95 transition-all"><Save size={16} /> Save & Apply</button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden relative">
        {/* Left Toolbar */}
        <div className="w-24 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-6 z-40 relative">
          <ToolIcon active={currentTool === 'select'} onClick={() => { setCurrentTool('select'); setShowShapeMenu(false); }} icon={<MousePointer2 size={20} />} label="Select" />
          <ToolIcon active={currentTool === 'brush'} onClick={() => { setCurrentTool('brush'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Palette size={20} />} label="Brush" />
          <ToolIcon active={currentTool === 'ai-erase'} onClick={() => { setCurrentTool('ai-erase'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Eraser size={20} />} label="AI Erase" />

          {/* Shapes Entry - Grouped Submenu */}
          <div className="relative group/shape">
            <ToolIcon 
              active={['rect', 'circle', 'line'].includes(currentTool)} 
              onClick={() => { setShowShapeMenu(!showShapeMenu); }} 
              icon={<ShapeIcon size={20} />} 
              label="Shapes" 
            />
            {showShapeMenu && (
              <div 
                className="fixed left-24 top-auto bg-slate-800 border border-slate-700 p-2 rounded-xl shadow-2xl flex flex-col gap-2 z-[100] animate-in slide-in-from-left-2 duration-200"
                style={{ marginTop: '-40px' }}
              >
                <button onClick={() => { setCurrentTool('rect'); setLastUsedShape('rect'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'rect' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Square size={20} /></button>
                <button onClick={() => { setCurrentTool('circle'); setLastUsedShape('circle'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'circle' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Circle size={20} /></button>
                <button onClick={() => { setCurrentTool('line'); setLastUsedShape('line'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'line' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Minus size={20} /></button>
              </div>
            )}
          </div>

          <ToolIcon active={currentTool === 'text'} onClick={() => { setCurrentTool('text'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Type size={20} />} label="Text" />
          <ToolIcon active={currentTool === 'select-fill'} onClick={() => { setCurrentTool('select-fill'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<PaintBucket size={20} />} label="Fill" />
          <ToolIcon active={currentTool === 'crop'} onClick={() => { setCurrentTool('crop'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Scissors size={20} />} label="Crop" />

          <div className="mt-auto flex flex-col gap-4 pb-4">
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Stroke</span>
               <input type="color" value={strokeColor} onChange={(e) => setStrokeColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Fill</span>
               <input type="color" value={fillColor} onChange={(e) => setFillColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
          </div>
        </div>

        {/* Canvas Area */}
        <div ref={containerRef} className="flex-1 bg-slate-950 overflow-auto flex items-center justify-center p-20 relative z-10">
          <div className="relative shadow-2xl transition-transform duration-75 origin-center" style={{ transform: `scale(${zoom})` }}>
            <canvas ref={canvasRef} onMouseDown={handleStart} onMouseMove={handleMove} onMouseUp={handleEnd} className="block relative" style={{ cursor: currentTool === 'none' ? 'default' : currentTool === 'select' ? 'default' : 'crosshair' }} />

            <svg 
              className="absolute inset-0 pointer-events-none w-full h-full"
              viewBox={`0 0 ${canvasRef.current?.width || 0} ${canvasRef.current?.height || 0}`}
            >
              {objects.map(obj => (
                <g 
                  key={obj.id} 
                  className={selectedObjectId === obj.id ? 'opacity-100' : 'opacity-80'}
                  transform={`rotate(${(obj.rotation * 180) / Math.PI} ${obj.x + obj.width / 2} ${obj.y + obj.height / 2})`}
                  style={{ opacity: obj.opacity }}
                >
                  {obj.type === 'rect' && <rect x={obj.x} y={obj.y} width={obj.width} height={obj.height} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'circle' && <ellipse cx={obj.x + obj.width/2} cy={obj.y + obj.height/2} rx={obj.width/2} ry={obj.height/2} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'line' && <line x1={obj.x} y1={obj.y} x2={obj.x + obj.width} y2={obj.y + obj.height} stroke={obj.stroke} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'text' && (
                    <text 
                      x={obj.x} 
                      y={obj.y + obj.height/2} 
                      fill={obj.fill} 
                      stroke={obj.stroke} 
                      strokeWidth={obj.strokeWidth/4} 
                      style={{ font: `bold ${obj.strokeWidth * 6}px Inter, sans-serif` }}
                    >
                      {obj.text}
                    </text>
                  )}
                  {selectedObjectId === obj.id && (
                    <>
                      <rect 
                        x={obj.x} y={obj.y} width={obj.width} height={obj.height} 
                        fill="none" stroke="#6366f1" strokeWidth={2 / zoom} strokeDasharray="4"
                      />
                      <circle 
                        cx={obj.x + obj.width} cy={obj.y + obj.height} r={6 / zoom} 
                        fill="#6366f1" className="cursor-nwse-resize pointer-events-auto" 
                      />
                      <line x1={obj.x + obj.width/2} y1={obj.y} x2={obj.x + obj.width/2} y2={obj.y - 30/zoom} stroke="#6366f1" strokeWidth={2/zoom} />
                      <circle 
                        cx={obj.x + obj.width/2} cy={obj.y - 30/zoom} r={8 / zoom} 
                        fill="#6366f1" className="cursor-pointer pointer-events-auto"
                      />
                    </>
                  )}
                </g>
              ))}
            </svg>

            {selection && (['select-fill', 'crop'].includes(currentTool)) && (
               <div className="absolute pointer-events-none border-2 border-white" style={{ left: Math.min(selection.x1, selection.x2), top: Math.min(selection.y1, selection.y2), width: Math.abs(selection.x1 - selection.x2), height: Math.abs(selection.y1 - selection.y2) }}>
                 <div className="absolute inset-0 border-2 border-dashed border-black/50 animate-pulse"></div>
               </div>
            )}
          </div>

          {/* Bottom Control Bar */}
          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-8 bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-6 rounded-[2.5rem] shadow-2xl z-30 min-w-[700px]">
             <div className="flex flex-col gap-3 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Brush Size / Stroke</span>
                 <span className="text-[10px] font-black text-blue-400">{brushSize}px</span>
               </div>
               <input type="range" min="1" max="100" value={brushSize} onChange={(e) => setBrushSize(parseInt(e.target.value))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500" />
             </div>

             <div className="w-px h-8 bg-slate-800"></div>

             <div className="flex flex-col gap-3 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Opacity</span>
                 <span className="text-[10px] font-black text-indigo-400">{Math.round(opacity * 100)}%</span>
               </div>
               <input type="range" min="0" max="1" step="0.01" value={opacity} onChange={(e) => {
                 const v = parseFloat(e.target.value);
                 setOpacity(v);
                 if (selectedObjectId) {
                    setObjects(prev => prev.map(o => o.id === selectedObjectId ? { ...o, opacity: v } : o));
                 }
               }} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
             </div>

             {currentTool === 'ai-erase' && (
               <button onClick={runAIErase} disabled={isProcessing} className="px-8 py-3 bg-red-600 hover:bg-red-700 text-white rounded-2xl text-xs font-black shadow-xl flex items-center gap-3 transition-all active:scale-95 disabled:opacity-50">
                 {isProcessing ? <Loader2 className="animate-spin" size={16} /> : <Wand2 size={16} />} AI ERASE
               </button>
             )}
             {currentTool === 'select-fill' && (
               <button onClick={handleFill} disabled={!selection} className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">FILL AREA</button>
             )}
             {currentTool === 'crop' && (
               <button onClick={handleCrop} disabled={!selection} className="px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">CONFIRM CROP</button>
             )}
             {!['ai-erase', 'select-fill', 'crop'].includes(currentTool) && (
                <div className="px-6 text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 animate-pulse"></div>
                  {currentTool === 'select' ? (selectedObjectId ? 'Object Selected' : 'Select Tool') : `${currentTool} tool`}
                </div>
             )}
          </div>

          {isProcessing && <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/70 backdrop-blur-md"><Loader2 size={40} className="text-indigo-500 animate-spin" /><p className="mt-8 text-white font-black tracking-[0.3em] text-sm uppercase">AI Processing...</p></div>}
        </div>
      </div>
    </div>
  );
};

const ToolIcon = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1.5 group transition-all shrink-0 ${active ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>
    <div className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${active ? 'bg-indigo-600/10 border border-indigo-500/50 shadow-lg' : 'bg-slate-800/50 hover:bg-slate-800'}`}>
      {icon}
    </div>
    <span className="text-[8px] font-black uppercase tracking-tighter">{label}</span>
  </button>
);

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  X, Eraser, Scissors, PaintBucket, Crop, Save, Undo, 
  Wand2, Loader2, Download, MousePointer2, Maximize, 
  Type, Square, Circle, Minus, Move, Palette, Trash2,
  ZoomIn, ZoomOut, RotateCcw, Box, ArrowUpRight, RefreshCw, 
  Shapes, ChevronRight
} from 'lucide-react';
import { editImageWithAI } from '../services/geminiService';
import { UILanguage } from '../types';

interface ImageEditorProps {
  imageUrl: string;
  onClose: () => void;
  onSave: (newImageUrl: string) => void;
  uiLang: UILanguage;
}

type Tool = 'select' | 'select-fill' | 'brush' | 'ai-erase' | 'crop' | 'rect' | 'circle' | 'line' | 'text' | 'none';

interface EditorObject {
  id: string;
  type: 'rect' | 'circle' | 'line' | 'text';
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number; 
  stroke: string;
  fill: string;
  strokeWidth: number;
  opacity: number; // 0 to 1
  text?: string;
}

interface EditorState {
  canvasData: string;
  objects: EditorObject[];
}

interface SelectionBox {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
}

const CORS_PROXY = 'https://corsproxy.io/?';

export const ImageEditor: React.FC<ImageEditorProps> = ({ imageUrl, onClose, onSave, uiLang }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [currentTool, setCurrentTool] = useState<Tool>('select');
  const [isProcessing, setIsProcessing] = useState(false);
  const [strokeColor, setStrokeColor] = useState('#000000');
  const [fillColor, setFillColor] = useState('#ffffff');
  const [brushSize, setBrushSize] = useState(5);
  const [opacity, setOpacity] = useState(1); // 1.0 = 100%
  const [zoom, setZoom] = useState(1);

  // Shape menu state
  const [showShapeMenu, setShowShapeMenu] = useState(false);
  const [lastUsedShape, setLastUsedShape] = useState<'rect' | 'circle' | 'line'>('rect');

  // Object system
  const [objects, setObjects] = useState<EditorObject[]>([]);
  const [selectedObjectId, setSelectedObjectId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [isRotating, setIsRotating] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const [isDrawing, setIsDrawing] = useState(false);
  const [selection, setSelection] = useState<SelectionBox | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });

  const [history, setHistory] = useState<EditorState[]>([]);

  const saveToHistory = useCallback((currentObjects?: EditorObject[]) => {
    const canvas = canvasRef.current;
    if (canvas) {
      const newState: EditorState = {
        canvasData: canvas.toDataURL('image/png'),
        objects: currentObjects ? [...currentObjects] : [...objects]
      };
      setHistory(prev => [...prev.slice(-30), newState]);
    }
  }, [objects]);

  useEffect(() => {
    const initCanvas = async () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d', { willReadFrequently: true }) as CanvasRenderingContext2D | null;
      if (!ctx) return;

      setIsProcessing(true);
      try {
        const proxyUrl = `${CORS_PROXY}${encodeURIComponent(imageUrl)}`;
        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error("Failed to fetch image through proxy");
        const blob = await response.blob();
        const localUrl = URL.createObjectURL(blob);

        const img = new Image();
        img.src = localUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);

          if (containerRef.current) {
            const padding = 120;
            const availableW = containerRef.current.clientWidth - padding;
            const availableH = containerRef.current.clientHeight - padding;
            const scale = Math.min(availableW / img.width, availableH / img.height, 1);
            setZoom(scale || 1);
          }

          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
          URL.revokeObjectURL(localUrl);
        };
      } catch (err) {
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.src = imageUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          (ctx as CanvasRenderingContext2D).drawImage(img, 0, 0);
          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
        };
      }
    };
    initCanvas();
  }, [imageUrl]);

  const undo = () => {
    if (history.length <= 1) return;
    const newHistory = [...history];
    newHistory.pop(); 
    const prevState = newHistory[newHistory.length - 1];

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (canvas && ctx && prevState) {
      const img = new Image();
      img.src = prevState.canvasData;
      img.onload = () => {
        canvas.width = img.width;
        canvas.height = img.height;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        setObjects(prevState.objects);
        setHistory(newHistory);
      };
    }
  };

  const standardize = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const currentData = canvas.toDataURL();
    const tempImg = new Image();
    tempImg.src = currentData;
    tempImg.onload = () => {
      const targetSize = 1600;
      const safeArea = 1500;

      // Calculate Scale and Offset for relative positioning
      const scale = Math.min(safeArea / tempImg.width, safeArea / tempImg.height);
      const drawW = tempImg.width * scale;
      const drawH = tempImg.height * scale;
      const offsetX = (targetSize - drawW) / 2;
      const offsetY = (targetSize - drawH) / 2;

      // Transform existing objects to keep relative positions
      const transformedObjects = objects.map(obj => ({
        ...obj,
        x: obj.x * scale + offsetX,
        y: obj.y * scale + offsetY,
        width: obj.width * scale,
        height: obj.height * scale,
        strokeWidth: obj.strokeWidth * scale
      }));

      // Update Canvas Dimensions and Content
      canvas.width = targetSize;
      canvas.height = targetSize;
      const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, targetSize, targetSize);
      ctx.drawImage(tempImg, offsetX, offsetY, drawW, drawH);

      setObjects(transformedObjects);
      saveToHistory(transformedObjects);

      if (containerRef.current) {
        setZoom(Math.min((containerRef.current.clientHeight - 120) / 1600, 1));
      }
    };
  };

  const getMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }
    return {
      x: (clientX - rect.left) / zoom,
      y: (clientY - rect.top) / zoom
    };
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);
    setStartPos(pos);

    if (currentTool === 'select') {
      if (selectedObjectId) {
        const obj = objects.find(o => o.id === selectedObjectId);
        if (obj) {
          const handleSize = 12 / zoom;
          const rotateHandleY = obj.y - 30 / zoom;
          const centerX = obj.x + obj.width / 2;

          const distToRotate = Math.sqrt(Math.pow(pos.x - centerX, 2) + Math.pow(pos.y - rotateHandleY, 2));
          if (distToRotate < handleSize) {
            setIsRotating(true);
            return;
          }

          const isOverResizeHandle = 
            pos.x >= obj.x + obj.width - handleSize && 
            pos.x <= obj.x + obj.width + handleSize && 
            pos.y >= obj.y + obj.height - handleSize && 
            pos.y <= obj.y + obj.height + handleSize;

          if (isOverResizeHandle) {
            setIsResizing(true);
            return;
          }

          const isOverBody = 
            pos.x >= obj.x && pos.x <= obj.x + obj.width &&
            pos.y >= obj.y && pos.y <= obj.y + obj.height;

          if (isOverBody) {
            setIsDragging(true);
            setDragOffset({ x: pos.x - obj.x, y: pos.y - obj.y });
            return;
          }
        }
      }

      const hit = objects.slice().reverse().find(obj => 
        pos.x >= obj.x && pos.x <= obj.x + obj.width &&
        pos.y >= obj.y && pos.y <= obj.y + obj.height
      );

      if (hit) {
        setSelectedObjectId(hit.id);
        setIsDragging(true);
        setDragOffset({ x: pos.x - hit.x, y: pos.y - hit.y });
      } else {
        setSelectedObjectId(null);
      }
      return;
    }

    setIsDrawing(true);
    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection({ x1: pos.x, y1: pos.y, x2: pos.x, y2: pos.y });
    }

    if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.beginPath();
        ctx.moveTo(pos.x, pos.y);
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.globalAlpha = opacity;
        ctx.strokeStyle = currentTool === 'ai-erase' ? 'rgba(255, 0, 0, 0.6)' : strokeColor;
        ctx.lineWidth = brushSize;
      }
    }
  };

  const handleMove = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);

    if (currentTool === 'select' && selectedObjectId) {
      const obj = objects.find(o => o.id === selectedObjectId);
      if (!obj) return;

      if (isDragging) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, x: pos.x - dragOffset.x, y: pos.y - dragOffset.y }
            : o
        ));
      } else if (isResizing) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, width: Math.max(10, pos.x - o.x), height: Math.max(10, pos.y - o.y) }
            : o
        ));
      } else if (isRotating) {
        const centerX = obj.x + obj.width / 2;
        const centerY = obj.y + obj.height / 2;
        const angle = Math.atan2(pos.y - centerY, pos.x - centerX) + Math.PI / 2;
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId ? { ...o, rotation: angle } : o
        ));
      }
      return;
    }

    if (!isDrawing) return;

    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection(prev => prev ? { ...prev, x2: pos.x, y2: pos.y } : null);
    } else if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.lineTo(pos.x, pos.y);
        ctx.stroke();
      }
    }
  };

  const handleEnd = (e: React.MouseEvent | React.TouchEvent) => {
    if (currentTool === 'select') {
      if (isDragging || isResizing || isRotating) {
        saveToHistory(objects);
      }
      setIsDragging(false);
      setIsResizing(false);
      setIsRotating(false);
      return;
    }

    if (!isDrawing) return;
    setIsDrawing(false);

    const pos = getMousePos(e);

    if (['rect', 'circle', 'line'].includes(currentTool)) {
      const newObj: EditorObject = {
        id: crypto.randomUUID(),
        type: currentTool as any,
        x: Math.min(startPos.x, pos.x),
        y: Math.min(startPos.y, pos.y),
        width: Math.abs(startPos.x - pos.x),
        height: Math.abs(startPos.y - pos.y),
        rotation: 0,
        stroke: strokeColor,
        fill: fillColor,
        strokeWidth: brushSize,
        opacity: opacity
      };
      const nextObjects = [...objects, newObj];
      setObjects(nextObjects);
      setSelectedObjectId(newObj.id);
      setCurrentTool('select');
      setSelection(null);
      saveToHistory(nextObjects);
    } else if (currentTool === 'text') {
      const text = window.prompt(uiLang === 'zh' ? "输入文字:" : "Enter text:");
      if (text) {
        const newObj: EditorObject = {
          id: crypto.randomUUID(),
          type: 'text',
          x: pos.x,
          y: pos.y,
          width: text.length * brushSize * 3,
          height: brushSize * 6,
          rotation: 0,
          stroke: strokeColor,
          fill: fillColor,
          strokeWidth: brushSize,
          opacity: opacity,
          text: text
        };
        const nextObjects = [...objects, newObj];
        setObjects(nextObjects);
        setSelectedObjectId(newObj.id);
        setCurrentTool('select');
        saveToHistory(nextObjects);
      }
    } else if (currentTool === 'brush') {
      saveToHistory();
    }
  };

  const handleFill = () => {
    if (currentTool !== 'select-fill' || !selection) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);

    ctx.save();
    ctx.globalAlpha = opacity;
    ctx.fillStyle = fillColor;
    ctx.fillRect(x, y, w, h);
    ctx.restore();

    saveToHistory();
    setSelection(null); 
    setCurrentTool('select');
  };

  const handleCrop = () => {
    if (!selection) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    if (w < 5 || h < 5) return;
    const imageData = ctx.getImageData(x, y, w, h);
    canvas.width = w;
    canvas.height = h;
    ctx.putImageData(imageData, 0, 0);
    saveToHistory();
    setSelection(null);
    setZoom(1);
    setCurrentTool('select');
  };

  const runAIErase = async () => {
    setIsProcessing(true);
    try {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const base64 = canvas.toDataURL('image/jpeg', 0.9).split(',')[1];
      const result = await editImageWithAI(base64, "Please erase the red highlighted areas cleanly.");
      const img = new Image();
      img.src = `data:image/jpeg;base64,${result}`;
      img.onload = () => {
        const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        saveToHistory();
        setIsProcessing(false);
      };
    } catch (e: any) {
      alert("AI Erase failed: " + e.message);
      setIsProcessing(false);
    }
  };

  const handleFinalSave = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Draw all objects onto the canvas before saving
    objects.forEach(obj => {
      ctx.save();
      const cx = obj.x + obj.width / 2;
      const cy = obj.y + obj.height / 2;

      ctx.translate(cx, cy);
      ctx.rotate(obj.rotation);
      ctx.translate(-cx, -cy);

      ctx.globalAlpha = obj.opacity;
      ctx.strokeStyle = obj.stroke;
      ctx.fillStyle = obj.fill;
      ctx.lineWidth = obj.strokeWidth;
      ctx.lineCap = 'round';

      if (obj.type === 'rect') {
        ctx.beginPath();
        ctx.rect(obj.x, obj.y, obj.width, obj.height);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'circle') {
        const r = Math.sqrt(obj.width * obj.width + obj.height * obj.height) / 2;
        ctx.beginPath();
        ctx.arc(obj.x + obj.width/2, obj.y + obj.height/2, r, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'line') {
        ctx.beginPath();
        ctx.moveTo(obj.x, obj.y);
        ctx.lineTo(obj.x + obj.width, obj.y + obj.height);
        ctx.stroke();
      } else if (obj.type === 'text' && obj.text) {
        ctx.font = `bold ${obj.strokeWidth * 6}px Inter, sans-serif`;
        ctx.fillText(obj.text, obj.x, obj.y);
        ctx.strokeText(obj.text, obj.x, obj.y);
      }
      ctx.restore();
    });

    onSave(canvas.toDataURL('image/jpeg', 0.95));
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.key === 'Delete' || e.key === 'Backspace')) {
         if (selectedObjectId) {
            const nextObjects = objects.filter(o => o.id !== selectedObjectId);
            setObjects(nextObjects);
            setSelectedObjectId(null);
            saveToHistory(nextObjects);
         } else if (currentTool === 'select-fill' && selection) {
            handleFill();
         }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedObjectId, objects, saveToHistory, currentTool, selection, fillColor, opacity]);

  const ShapeIcon = lastUsedShape === 'rect' ? Square : lastUsedShape === 'circle' ? Circle : Minus;

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col font-inter">
      <div className="h-16 bg-slate-900 border-b border-slate-800 px-6 flex items-center justify-between text-white shadow-xl z-20">
        <div className="flex items-center gap-6">
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-all"><X size={20} /></button>
          <div className="h-6 w-px bg-slate-800"></div>
          <h2 className="font-black tracking-tighter text-xl bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent uppercase">AI Media Lab</h2>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex bg-slate-800 p-1 rounded-xl">
            <button onClick={() => setZoom(prev => Math.max(0.05, prev - 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomOut size={16} /></button>
            <span className="px-3 flex items-center text-[10px] font-black text-slate-300 w-16 justify-center">{(zoom * 100).toFixed(0)}%</span>
            <button onClick={() => setZoom(prev => Math.min(5, prev + 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomIn size={16} /></button>
          </div>
          <button onClick={undo} disabled={history.length <= 1} className="p-2.5 bg-slate-800 hover:bg-slate-700 disabled:opacity-30 rounded-xl text-slate-300 transition-all"><Undo size={18} /></button>
          <button onClick={standardize} className="px-5 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-black flex items-center gap-2 border border-slate-700"><Maximize size={16} /> 1600*1600</button>
          <button onClick={handleFinalSave} className="px-8 py-2.5 bg-indigo-600 hover:bg-indigo-700 rounded-xl text-xs font-black shadow-lg flex items-center gap-2 transform active:scale-95 transition-all"><Save size={16} /> Save & Apply</button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden relative">
        {/* Left Toolbar */}
        <div className="w-24 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-6 z-40 relative">
          <ToolIcon active={currentTool === 'select'} onClick={() => { setCurrentTool('select'); setShowShapeMenu(false); }} icon={<MousePointer2 size={20} />} label="Select" />
          <ToolIcon active={currentTool === 'brush'} onClick={() => { setCurrentTool('brush'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Palette size={20} />} label="Brush" />
          <ToolIcon active={currentTool === 'ai-erase'} onClick={() => { setCurrentTool('ai-erase'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Eraser size={20} />} label="AI Erase" />

          {/* Shapes Entry - Grouped Submenu */}
          <div className="relative group/shape">
            <ToolIcon 
              active={['rect', 'circle', 'line'].includes(currentTool)} 
              onClick={() => { setShowShapeMenu(!showShapeMenu); }} 
              icon={<ShapeIcon size={20} />} 
              label="Shapes" 
            />
            {showShapeMenu && (
              <div 
                className="fixed left-24 top-auto bg-slate-800 border border-slate-700 p-2 rounded-xl shadow-2xl flex flex-col gap-2 z-[100] animate-in slide-in-from-left-2 duration-200"
                style={{ marginTop: '-40px' }}
              >
                <button onClick={() => { setCurrentTool('rect'); setLastUsedShape('rect'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'rect' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Square size={20} /></button>
                <button onClick={() => { setCurrentTool('circle'); setLastUsedShape('circle'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'circle' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Circle size={20} /></button>
                <button onClick={() => { setCurrentTool('line'); setLastUsedShape('line'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'line' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Minus size={20} /></button>
              </div>
            )}
          </div>

          <ToolIcon active={currentTool === 'text'} onClick={() => { setCurrentTool('text'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Type size={20} />} label="Text" />
          <ToolIcon active={currentTool === 'select-fill'} onClick={() => { setCurrentTool('select-fill'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<PaintBucket size={20} />} label="Fill" />
          <ToolIcon active={currentTool === 'crop'} onClick={() => { setCurrentTool('crop'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Scissors size={20} />} label="Crop" />

          <div className="mt-auto flex flex-col gap-4 pb-4">
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Stroke</span>
               <input type="color" value={strokeColor} onChange={(e) => setStrokeColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Fill</span>
               <input type="color" value={fillColor} onChange={(e) => setFillColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700" />
             </div>
          </div>
        </div>

        {/* Canvas Area */}
        <div ref={containerRef} className="flex-1 bg-slate-950 overflow-auto flex items-center justify-center p-20 relative z-10">
          <div className="relative shadow-2xl transition-transform duration-75 origin-center" style={{ transform: `scale(${zoom})` }}>
            <canvas ref={canvasRef} onMouseDown={handleStart} onMouseMove={handleMove} onMouseUp={handleEnd} className="block relative" style={{ cursor: currentTool === 'none' ? 'default' : currentTool === 'select' ? 'default' : 'crosshair' }} />

            <svg 
              className="absolute inset-0 pointer-events-none w-full h-full"
              viewBox={`0 0 ${canvasRef.current?.width || 0} ${canvasRef.current?.height || 0}`}
            >
              {/* Render Temporary Drawing Preview */}
              {isDrawing && selection && ['rect', 'circle', 'line'].includes(currentTool) && (
                <g opacity={opacity * 0.5}>
                  {currentTool === 'rect' && (
                    <rect 
                      x={Math.min(selection.x1, selection.x2)} 
                      y={Math.min(selection.y1, selection.y2)} 
                      width={Math.abs(selection.x1 - selection.x2)} 
                      height={Math.abs(selection.y1 - selection.y2)} 
                      stroke={strokeColor} 
                      fill={fillColor} 
                      strokeWidth={brushSize} 
                      strokeDasharray="5,5"
                    />
                  )}
                  {currentTool === 'circle' && (
                    <ellipse 
                      cx={(selection.x1 + selection.x2) / 2} 
                      cy={(selection.y1 + selection.y2) / 2} 
                      rx={Math.abs(selection.x1 - selection.x2) / 2} 
                      ry={Math.abs(selection.y1 - selection.y2) / 2} 
                      stroke={strokeColor} 
                      fill={fillColor} 
                      strokeWidth={brushSize} 
                      strokeDasharray="5,5"
                    />
                  )}
                  {currentTool === 'line' && (
                    <line 
                      x1={selection.x1} 
                      y1={selection.y1} 
                      x2={selection.x2} 
                      y2={selection.y2} 
                      stroke={strokeColor} 
                      strokeWidth={brushSize} 
                      strokeDasharray="5,5"
                    />
                  )}
                </g>
              )}

              {objects.map(obj => (
                <g 
                  key={obj.id} 
                  className={selectedObjectId === obj.id ? 'opacity-100' : 'opacity-80'}
                  transform={`rotate(${(obj.rotation * 180) / Math.PI} ${obj.x + obj.width / 2} ${obj.y + obj.height / 2})`}
                  style={{ opacity: obj.opacity }}
                >
                  {obj.type === 'rect' && <rect x={obj.x} y={obj.y} width={obj.width} height={obj.height} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'circle' && <ellipse cx={obj.x + obj.width/2} cy={obj.y + obj.height/2} rx={obj.width/2} ry={obj.height/2} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'line' && <line x1={obj.x} y1={obj.y} x2={obj.x + obj.width} y2={obj.y + obj.height} stroke={obj.stroke} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'text' && (
                    <text 
                      x={obj.x} 
                      y={obj.y + obj.height/2} 
                      fill={obj.fill} 
                      stroke={obj.stroke} 
                      strokeWidth={obj.strokeWidth/4} 
                      style={{ font: `bold ${obj.strokeWidth * 6}px Inter, sans-serif` }}
                    >
                      {obj.text}
                    </text>
                  )}
                  {selectedObjectId === obj.id && (
                    <>
                      <rect 
                        x={obj.x} y={obj.y} width={obj.width} height={obj.height} 
                        fill="none" stroke="#6366f1" strokeWidth={2 / zoom} strokeDasharray="4"
                      />
                      <circle 
                        cx={obj.x + obj.width} cy={obj.y + obj.height} r={6 / zoom} 
                        fill="#6366f1" className="cursor-nwse-resize pointer-events-auto" 
                      />
                      <line x1={obj.x + obj.width/2} y1={obj.y} x2={obj.x + obj.width/2} y2={obj.y - 30/zoom} stroke="#6366f1" strokeWidth={2/zoom} />
                      <circle 
                        cx={obj.x + obj.width/2} cy={obj.y - 30/zoom} r={8 / zoom} 
                        fill="#6366f1" className="cursor-pointer pointer-events-auto"
                      />
                    </>
                  )}
                </g>
              ))}
            </svg>

            {selection && (['select-fill', 'crop'].includes(currentTool)) && (
               <div className="absolute pointer-events-none border-2 border-white" style={{ left: Math.min(selection.x1, selection.x2), top: Math.min(selection.y1, selection.y2), width: Math.abs(selection.x1 - selection.x2), height: Math.abs(selection.y1 - selection.y2) }}>
                 <div className="absolute inset-0 border-2 border-dashed border-black/50 animate-pulse"></div>
               </div>
            )}
          </div>

          {/* Bottom Control Bar */}
          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-8 bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-6 rounded-[2.5rem] shadow-2xl z-30 min-w-[700px]">
             <div className="flex flex-col gap-3 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Brush Size / Stroke</span>
                 <span className="text-[10px] font-black text-blue-400">{brushSize}px</span>
               </div>
               <input type="range" min="1" max="100" value={brushSize} onChange={(e) => setBrushSize(parseInt(e.target.value))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500" />
             </div>

             <div className="w-px h-8 bg-slate-800"></div>

             <div className="flex flex-col gap-3 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Opacity</span>
                 <span className="text-[10px] font-black text-indigo-400">{Math.round(opacity * 100)}%</span>
               </div>
               <input type="range" min="0" max="1" step="0.01" value={opacity} onChange={(e) => {
                 const v = parseFloat(e.target.value);
                 setOpacity(v);
                 if (selectedObjectId) {
                    setObjects(prev => prev.map(o => o.id === selectedObjectId ? { ...o, opacity: v } : o));
                 }
               }} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
             </div>

             {currentTool === 'ai-erase' && (
               <button onClick={runAIErase} disabled={isProcessing} className="px-8 py-3 bg-red-600 hover:bg-red-700 text-white rounded-2xl text-xs font-black shadow-xl flex items-center gap-3 transition-all active:scale-95 disabled:opacity-50">
                 {isProcessing ? <Loader2 className="animate-spin" size={16} /> : <Wand2 size={16} />} AI ERASE
               </button>
             )}
             {currentTool === 'select-fill' && (
               <button onClick={handleFill} disabled={!selection} className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">FILL AREA</button>
             )}
             {currentTool === 'crop' && (
               <button onClick={handleCrop} disabled={!selection} className="px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">CONFIRM CROP</button>
             )}
             {!['ai-erase', 'select-fill', 'crop'].includes(currentTool) && (
                <div className="px-6 text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 animate-pulse"></div>
                  {currentTool === 'select' ? (selectedObjectId ? 'Object Selected' : 'Select Tool') : `${currentTool} tool`}
                </div>
             )}
          </div>

          {isProcessing && <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/70 backdrop-blur-md"><Loader2 size={40} className="text-indigo-500 animate-spin" /><p className="mt-8 text-white font-black tracking-[0.3em] text-sm uppercase">AI Processing...</p></div>}
        </div>
      </div>
    </div>
  );
};

const ToolIcon = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1.5 group transition-all shrink-0 ${active ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>
    <div className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${active ? 'bg-indigo-600/10 border border-indigo-500/50 shadow-lg' : 'bg-slate-800/50 hover:bg-slate-800'}`}>
      {icon}
    </div>
    <span className="text-[8px] font-black uppercase tracking-tighter">{label}</span>
  </button>
);

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  X, Eraser, Scissors, PaintBucket, Crop, Save, Undo, 
  Wand2, Loader2, Download, MousePointer2, Maximize, 
  Type, Square, Circle, Minus, Move, Palette, Trash2,
  ZoomIn, ZoomOut, RotateCcw, Box, ArrowUpRight, RefreshCw, 
  Shapes, ChevronRight
} from 'lucide-react';
import { editImageWithAI } from '../services/geminiService';
import { UILanguage } from '../types';

interface ImageEditorProps {
  imageUrl: string;
  onClose: () => void;
  onSave: (newImageUrl: string) => void;
  uiLang: UILanguage;
}

type Tool = 'select' | 'select-fill' | 'brush' | 'ai-erase' | 'crop' | 'rect' | 'circle' | 'line' | 'text' | 'none';

interface EditorObject {
  id: string;
  type: 'rect' | 'circle' | 'line' | 'text';
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number; 
  stroke: string;
  fill: string;
  strokeWidth: number;
  opacity: number; // 0 to 1
  text?: string;
}

interface EditorState {
  canvasData: string;
  objects: EditorObject[];
}

interface SelectionBox {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
}

const CORS_PROXY = 'https://corsproxy.io/?';

export const ImageEditor: React.FC<ImageEditorProps> = ({ imageUrl, onClose, onSave, uiLang }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [currentTool, setCurrentTool] = useState<Tool>('select');
  const [isProcessing, setIsProcessing] = useState(false);
  const [strokeColor, setStrokeColor] = useState('#000000');
  const [fillColor, setFillColor] = useState('#ffffff');
  const [brushSize, setBrushSize] = useState(5);
  const [opacity, setOpacity] = useState(1); // 1.0 = 100%
  const [zoom, setZoom] = useState(1);

  // Shape menu state
  const [showShapeMenu, setShowShapeMenu] = useState(false);
  const [lastUsedShape, setLastUsedShape] = useState<'rect' | 'circle' | 'line'>('rect');

  // Object system
  const [objects, setObjects] = useState<EditorObject[]>([]);
  const [selectedObjectId, setSelectedObjectId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [isRotating, setIsRotating] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const [isDrawing, setIsDrawing] = useState(false);
  const [selection, setSelection] = useState<SelectionBox | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });

  const [history, setHistory] = useState<EditorState[]>([]);

  // Sync controls when selected object changes
  useEffect(() => {
    if (selectedObjectId) {
      const obj = objects.find(o => o.id === selectedObjectId);
      if (obj) {
        setStrokeColor(obj.stroke);
        setFillColor(obj.fill);
        setBrushSize(obj.strokeWidth);
        setOpacity(obj.opacity);
      }
    }
  }, [selectedObjectId]);

  // Real-time update functions
  const updateSelectedObjectProperty = (property: keyof EditorObject, value: any) => {
    if (selectedObjectId) {
      setObjects(prev => prev.map(o => o.id === selectedObjectId ? { ...o, [property]: value } : o));
    }
  };

  const saveToHistory = useCallback((currentObjects?: EditorObject[]) => {
    const canvas = canvasRef.current;
    if (canvas) {
      const newState: EditorState = {
        canvasData: canvas.toDataURL('image/png'),
        objects: currentObjects ? [...currentObjects] : [...objects]
      };
      setHistory(prev => [...prev.slice(-30), newState]);
    }
  }, [objects]);

  useEffect(() => {
    const initCanvas = async () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d', { willReadFrequently: true }) as CanvasRenderingContext2D | null;
      if (!ctx) return;

      setIsProcessing(true);
      try {
        const proxyUrl = `${CORS_PROXY}${encodeURIComponent(imageUrl)}`;
        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error("Failed to fetch image through proxy");
        const blob = await response.blob();
        const localUrl = URL.createObjectURL(blob);

        const img = new Image();
        img.src = localUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);

          if (containerRef.current) {
            const padding = 120;
            const availableW = containerRef.current.clientWidth - padding;
            const availableH = containerRef.current.clientHeight - padding;
            const scale = Math.min(availableW / img.width, availableH / img.height, 1);
            setZoom(scale || 1);
          }

          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
          URL.revokeObjectURL(localUrl);
        };
      } catch (err) {
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.src = imageUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          (ctx as CanvasRenderingContext2D).drawImage(img, 0, 0);
          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
        };
      }
    };
    initCanvas();
  }, [imageUrl]);

  const undo = () => {
    if (history.length <= 1) return;
    const newHistory = [...history];
    newHistory.pop(); 
    const prevState = newHistory[newHistory.length - 1];

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (canvas && ctx && prevState) {
      const img = new Image();
      img.src = prevState.canvasData;
      img.onload = () => {
        canvas.width = img.width;
        canvas.height = img.height;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        setObjects(prevState.objects);
        setHistory(newHistory);
      };
    }
  };

  const standardize = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const currentData = canvas.toDataURL();
    const tempImg = new Image();
    tempImg.src = currentData;
    tempImg.onload = () => {
      const targetSize = 1600;
      const safeArea = 1500;

      const scale = Math.min(safeArea / tempImg.width, safeArea / tempImg.height);
      const drawW = tempImg.width * scale;
      const drawH = tempImg.height * scale;
      const offsetX = (targetSize - drawW) / 2;
      const offsetY = (targetSize - drawH) / 2;

      const transformedObjects = objects.map(obj => ({
        ...obj,
        x: obj.x * scale + offsetX,
        y: obj.y * scale + offsetY,
        width: obj.width * scale,
        height: obj.height * scale,
        strokeWidth: obj.strokeWidth * scale
      }));

      canvas.width = targetSize;
      canvas.height = targetSize;
      const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, targetSize, targetSize);
      ctx.drawImage(tempImg, offsetX, offsetY, drawW, drawH);

      setObjects(transformedObjects);
      saveToHistory(transformedObjects);

      if (containerRef.current) {
        setZoom(Math.min((containerRef.current.clientHeight - 120) / 1600, 1));
      }
    };
  };

  const getMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }
    return {
      x: (clientX - rect.left) / zoom,
      y: (clientY - rect.top) / zoom
    };
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);
    setStartPos(pos);

    if (currentTool === 'select') {
      if (selectedObjectId) {
        const obj = objects.find(o => o.id === selectedObjectId);
        if (obj) {
          const handleSize = 12 / zoom;
          const rotateHandleY = obj.y - 30 / zoom;
          const centerX = obj.x + obj.width / 2;

          const distToRotate = Math.sqrt(Math.pow(pos.x - centerX, 2) + Math.pow(pos.y - rotateHandleY, 2));
          if (distToRotate < handleSize) {
            setIsRotating(true);
            return;
          }

          const isOverResizeHandle = 
            pos.x >= obj.x + obj.width - handleSize && 
            pos.x <= obj.x + obj.width + handleSize && 
            pos.y >= obj.y + obj.height - handleSize && 
            pos.y <= obj.y + obj.height + handleSize;

          if (isOverResizeHandle) {
            setIsResizing(true);
            return;
          }

          const isOverBody = 
            pos.x >= obj.x && pos.x <= obj.x + obj.width &&
            pos.y >= obj.y && pos.y <= obj.y + obj.height;

          if (isOverBody) {
            setIsDragging(true);
            setDragOffset({ x: pos.x - obj.x, y: pos.y - obj.y });
            return;
          }
        }
      }

      const hit = objects.slice().reverse().find(obj => 
        pos.x >= obj.x && pos.x <= obj.x + obj.width &&
        pos.y >= obj.y && pos.y <= obj.y + obj.height
      );

      if (hit) {
        setSelectedObjectId(hit.id);
        setIsDragging(true);
        setDragOffset({ x: pos.x - hit.x, y: pos.y - hit.y });
      } else {
        setSelectedObjectId(null);
      }
      return;
    }

    setIsDrawing(true);
    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection({ x1: pos.x, y1: pos.y, x2: pos.x, y2: pos.y });
    }

    if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.beginPath();
        ctx.moveTo(pos.x, pos.y);
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.globalAlpha = opacity;
        ctx.strokeStyle = currentTool === 'ai-erase' ? 'rgba(255, 0, 0, 0.6)' : strokeColor;
        ctx.lineWidth = brushSize;
      }
    }
  };

  const handleMove = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);

    if (currentTool === 'select' && selectedObjectId) {
      const obj = objects.find(o => o.id === selectedObjectId);
      if (!obj) return;

      if (isDragging) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, x: pos.x - dragOffset.x, y: pos.y - dragOffset.y }
            : o
        ));
      } else if (isResizing) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, width: Math.max(10, pos.x - o.x), height: Math.max(10, pos.y - o.y) }
            : o
        ));
      } else if (isRotating) {
        const centerX = obj.x + obj.width / 2;
        const centerY = obj.y + obj.height / 2;
        const angle = Math.atan2(pos.y - centerY, pos.x - centerX) + Math.PI / 2;
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId ? { ...o, rotation: angle } : o
        ));
      }
      return;
    }

    if (!isDrawing) return;

    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection(prev => prev ? { ...prev, x2: pos.x, y2: pos.y } : null);
    } else if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.lineTo(pos.x, pos.y);
        ctx.stroke();
      }
    }
  };

  const handleEnd = (e: React.MouseEvent | React.TouchEvent) => {
    if (currentTool === 'select') {
      if (isDragging || isResizing || isRotating) {
        saveToHistory(objects);
      }
      setIsDragging(false);
      setIsResizing(false);
      setIsRotating(false);
      return;
    }

    if (!isDrawing) return;
    setIsDrawing(false);

    const pos = getMousePos(e);

    if (['rect', 'circle', 'line'].includes(currentTool)) {
      const newObj: EditorObject = {
        id: crypto.randomUUID(),
        type: currentTool as any,
        x: Math.min(startPos.x, pos.x),
        y: Math.min(startPos.y, pos.y),
        width: Math.abs(startPos.x - pos.x),
        height: Math.abs(startPos.y - pos.y),
        rotation: 0,
        stroke: strokeColor,
        fill: fillColor,
        strokeWidth: brushSize,
        opacity: opacity
      };
      const nextObjects = [...objects, newObj];
      setObjects(nextObjects);
      setSelectedObjectId(newObj.id);
      setCurrentTool('select');
      setSelection(null);
      saveToHistory(nextObjects);
    } else if (currentTool === 'text') {
      const text = window.prompt(uiLang === 'zh' ? "输入文字:" : "Enter text:");
      if (text) {
        const newObj: EditorObject = {
          id: crypto.randomUUID(),
          type: 'text',
          x: pos.x,
          y: pos.y,
          width: text.length * brushSize * 3,
          height: brushSize * 6,
          rotation: 0,
          stroke: strokeColor,
          fill: fillColor,
          strokeWidth: brushSize,
          opacity: opacity,
          text: text
        };
        const nextObjects = [...objects, newObj];
        setObjects(nextObjects);
        setSelectedObjectId(newObj.id);
        setCurrentTool('select');
        saveToHistory(nextObjects);
      }
    } else if (currentTool === 'brush') {
      saveToHistory();
    }
  };

  const handleFill = () => {
    if (currentTool !== 'select-fill' || !selection) return;

    // Core Fix: Convert Fill into a Rectangle Object so it can be re-edited/selected
    const newObj: EditorObject = {
      id: crypto.randomUUID(),
      type: 'rect',
      x: Math.min(selection.x1, selection.x2),
      y: Math.min(selection.y1, selection.y2),
      width: Math.abs(selection.x1 - selection.x2),
      height: Math.abs(selection.y1 - selection.y2),
      rotation: 0,
      stroke: 'transparent',
      fill: fillColor,
      strokeWidth: 0,
      opacity: opacity
    };

    const nextObjects = [...objects, newObj];
    setObjects(nextObjects);
    setSelectedObjectId(newObj.id);
    saveToHistory(nextObjects);
    setSelection(null); 
    setCurrentTool('select');
  };

  const handleCrop = () => {
    if (!selection) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    if (w < 5 || h < 5) return;
    const imageData = ctx.getImageData(x, y, w, h);
    canvas.width = w;
    canvas.height = h;
    ctx.putImageData(imageData, 0, 0);
    saveToHistory();
    setSelection(null);
    setZoom(1);
    setCurrentTool('select');
  };

  const runAIErase = async () => {
    setIsProcessing(true);
    try {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const base64 = canvas.toDataURL('image/jpeg', 0.9).split(',')[1];
      const result = await editImageWithAI(base64, "Please erase the red highlighted areas cleanly.");
      const img = new Image();
      img.src = `data:image/jpeg;base64,${result}`;
      img.onload = () => {
        const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        saveToHistory();
        setIsProcessing(false);
      };
    } catch (e: any) {
      alert("AI Erase failed: " + e.message);
      setIsProcessing(false);
    }
  };

  const handleFinalSave = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Draw all objects onto the canvas before saving
    objects.forEach(obj => {
      ctx.save();
      const cx = obj.x + obj.width / 2;
      const cy = obj.y + obj.height / 2;

      ctx.translate(cx, cy);
      ctx.rotate(obj.rotation);
      ctx.translate(-cx, -cy);

      ctx.globalAlpha = obj.opacity;
      ctx.strokeStyle = obj.stroke;
      ctx.fillStyle = obj.fill;
      ctx.lineWidth = obj.strokeWidth;
      ctx.lineCap = 'round';

      if (obj.type === 'rect') {
        ctx.beginPath();
        ctx.rect(obj.x, obj.y, obj.width, obj.height);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'circle') {
        const r = Math.sqrt(obj.width * obj.width + obj.height * obj.height) / 2;
        ctx.beginPath();
        ctx.arc(obj.x + obj.width/2, obj.y + obj.height/2, r, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'line') {
        ctx.beginPath();
        ctx.moveTo(obj.x, obj.y);
        ctx.lineTo(obj.x + obj.width, obj.y + obj.height);
        ctx.stroke();
      } else if (obj.type === 'text' && obj.text) {
        ctx.font = `bold ${obj.strokeWidth * 6}px Inter, sans-serif`;
        ctx.fillText(obj.text, obj.x, obj.y);
        ctx.strokeText(obj.text, obj.x, obj.y);
      }
      ctx.restore();
    });

    onSave(canvas.toDataURL('image/jpeg', 0.95));
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.key === 'Delete' || e.key === 'Backspace')) {
         if (selectedObjectId) {
            const nextObjects = objects.filter(o => o.id !== selectedObjectId);
            setObjects(nextObjects);
            setSelectedObjectId(null);
            saveToHistory(nextObjects);
         } else if (currentTool === 'select-fill' && selection) {
            handleFill();
         }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedObjectId, objects, saveToHistory, currentTool, selection, fillColor, opacity]);

  const ShapeIcon = lastUsedShape === 'rect' ? Square : lastUsedShape === 'circle' ? Circle : Minus;

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col font-inter">
      <div className="h-16 bg-slate-900 border-b border-slate-800 px-6 flex items-center justify-between text-white shadow-xl z-20">
        <div className="flex items-center gap-6">
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-all"><X size={20} /></button>
          <div className="h-6 w-px bg-slate-800"></div>
          <h2 className="font-black tracking-tighter text-xl bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent uppercase">AI Media Lab</h2>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex bg-slate-800 p-1 rounded-xl">
            <button onClick={() => setZoom(prev => Math.max(0.05, prev - 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomOut size={16} /></button>
            <span className="px-3 flex items-center text-[10px] font-black text-slate-300 w-16 justify-center">{(zoom * 100).toFixed(0)}%</span>
            <button onClick={() => setZoom(prev => Math.min(5, prev + 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomIn size={16} /></button>
          </div>
          <button onClick={undo} disabled={history.length <= 1} className="p-2.5 bg-slate-800 hover:bg-slate-700 disabled:opacity-30 rounded-xl text-slate-300 transition-all"><Undo size={18} /></button>
          <button onClick={standardize} className="px-5 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-black flex items-center gap-2 border border-slate-700"><Maximize size={16} /> 1600*1600</button>
          <button onClick={handleFinalSave} className="px-8 py-2.5 bg-indigo-600 hover:bg-indigo-700 rounded-xl text-xs font-black shadow-lg flex items-center gap-2 transform active:scale-95 transition-all"><Save size={16} /> Save & Apply</button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden relative">
        {/* Left Toolbar */}
        <div className="w-24 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-6 z-40 relative">
          <ToolIcon active={currentTool === 'select'} onClick={() => { setCurrentTool('select'); setShowShapeMenu(false); }} icon={<MousePointer2 size={20} />} label="Select" />
          <ToolIcon active={currentTool === 'brush'} onClick={() => { setCurrentTool('brush'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Palette size={20} />} label="Brush" />
          <ToolIcon active={currentTool === 'ai-erase'} onClick={() => { setCurrentTool('ai-erase'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Eraser size={20} />} label="AI Erase" />

          {/* Shapes Entry - Grouped Submenu */}
          <div className="relative group/shape">
            <ToolIcon 
              active={['rect', 'circle', 'line'].includes(currentTool)} 
              onClick={() => { setShowShapeMenu(!showShapeMenu); }} 
              icon={<ShapeIcon size={20} />} 
              label="Shapes" 
            />
            {showShapeMenu && (
              <div 
                className="fixed left-24 top-auto bg-slate-800 border border-slate-700 p-2 rounded-xl shadow-2xl flex flex-col gap-2 z-[100] animate-in slide-in-from-left-2 duration-200"
                style={{ marginTop: '-40px' }}
              >
                <button onClick={() => { setCurrentTool('rect'); setLastUsedShape('rect'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'rect' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Square size={20} /></button>
                <button onClick={() => { setCurrentTool('circle'); setLastUsedShape('circle'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'circle' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Circle size={20} /></button>
                <button onClick={() => { setCurrentTool('line'); setLastUsedShape('line'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'line' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Minus size={20} /></button>
              </div>
            )}
          </div>

          <ToolIcon active={currentTool === 'text'} onClick={() => { setCurrentTool('text'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Type size={20} />} label="Text" />
          <ToolIcon active={currentTool === 'select-fill'} onClick={() => { setCurrentTool('select-fill'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<PaintBucket size={20} />} label="Fill" />
          <ToolIcon active={currentTool === 'crop'} onClick={() => { setCurrentTool('crop'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Scissors size={20} />} label="Crop" />

          <div className="mt-auto flex flex-col gap-4 pb-4">
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Stroke</span>
               <input 
                type="color" 
                value={strokeColor} 
                onChange={(e) => {
                  const v = e.target.value;
                  setStrokeColor(v);
                  updateSelectedObjectProperty('stroke', v);
                }} 
                className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700 transition-all hover:scale-105" 
               />
             </div>
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Fill</span>
               <input 
                type="color" 
                value={fillColor} 
                onChange={(e) => {
                  const v = e.target.value;
                  setFillColor(v);
                  updateSelectedObjectProperty('fill', v);
                }} 
                className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700 transition-all hover:scale-105" 
               />
             </div>
          </div>
        </div>

        {/* Canvas Area */}
        <div ref={containerRef} className="flex-1 bg-slate-950 overflow-auto flex items-center justify-center p-20 relative z-10">
          <div className="relative shadow-2xl transition-transform duration-75 origin-center" style={{ transform: `scale(${zoom})` }}>
            <canvas ref={canvasRef} onMouseDown={handleStart} onMouseMove={handleMove} onMouseUp={handleEnd} className="block relative" style={{ cursor: currentTool === 'none' ? 'default' : currentTool === 'select' ? 'default' : 'crosshair' }} />

            <svg 
              className="absolute inset-0 pointer-events-none w-full h-full"
              viewBox={`0 0 ${canvasRef.current?.width || 0} ${canvasRef.current?.height || 0}`}
            >
              {/* Render Temporary Drawing Preview */}
              {isDrawing && selection && ['rect', 'circle', 'line'].includes(currentTool) && (
                <g opacity={opacity}>
                  {currentTool === 'rect' && (
                    <rect 
                      x={Math.min(selection.x1, selection.x2)} 
                      y={Math.min(selection.y1, selection.y2)} 
                      width={Math.abs(selection.x1 - selection.x2)} 
                      height={Math.abs(selection.y1 - selection.y2)} 
                      stroke={strokeColor} 
                      fill={fillColor} 
                      strokeWidth={brushSize} 
                      strokeDasharray="5,5"
                    />
                  )}
                  {currentTool === 'circle' && (
                    <ellipse 
                      cx={(selection.x1 + selection.x2) / 2} 
                      cy={(selection.y1 + selection.y2) / 2} 
                      rx={Math.abs(selection.x1 - selection.x2) / 2} 
                      ry={Math.abs(selection.y1 - selection.y2) / 2} 
                      stroke={strokeColor} 
                      fill={fillColor} 
                      strokeWidth={brushSize} 
                      strokeDasharray="5,5"
                    />
                  )}
                  {currentTool === 'line' && (
                    <line 
                      x1={selection.x1} 
                      y1={selection.y1} 
                      x2={selection.x2} 
                      y2={selection.y2} 
                      stroke={strokeColor} 
                      strokeWidth={brushSize} 
                      strokeDasharray="5,5"
                    />
                  )}
                </g>
              )}

              {objects.map(obj => (
                <g 
                  key={obj.id} 
                  className={selectedObjectId === obj.id ? 'opacity-100' : 'opacity-80'}
                  transform={`rotate(${(obj.rotation * 180) / Math.PI} ${obj.x + obj.width / 2} ${obj.y + obj.height / 2})`}
                  style={{ opacity: obj.opacity }}
                >
                  {obj.type === 'rect' && <rect x={obj.x} y={obj.y} width={obj.width} height={obj.height} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'circle' && <ellipse cx={obj.x + obj.width/2} cy={obj.y + obj.height/2} rx={obj.width/2} ry={obj.height/2} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'line' && <line x1={obj.x} y1={obj.y} x2={obj.x + obj.width} y2={obj.y + obj.height} stroke={obj.stroke} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'text' && (
                    <text 
                      x={obj.x} 
                      y={obj.y + obj.height/2} 
                      fill={obj.fill} 
                      stroke={obj.stroke} 
                      strokeWidth={obj.strokeWidth/4} 
                      style={{ font: `bold ${obj.strokeWidth * 6}px Inter, sans-serif` }}
                    >
                      {obj.text}
                    </text>
                  )}
                  {selectedObjectId === obj.id && (
                    <>
                      <rect 
                        x={obj.x} y={obj.y} width={obj.width} height={obj.height} 
                        fill="none" stroke="#6366f1" strokeWidth={2 / zoom} strokeDasharray="4"
                      />
                      <circle 
                        cx={obj.x + obj.width} cy={obj.y + obj.height} r={6 / zoom} 
                        fill="#6366f1" className="cursor-nwse-resize pointer-events-auto" 
                      />
                      <line x1={obj.x + obj.width/2} y1={obj.y} x2={obj.x + obj.width/2} y2={obj.y - 30/zoom} stroke="#6366f1" strokeWidth={2/zoom} />
                      <circle 
                        cx={obj.x + obj.width/2} cy={obj.y - 30/zoom} r={8 / zoom} 
                        fill="#6366f1" className="cursor-pointer pointer-events-auto"
                      />
                    </>
                  )}
                </g>
              ))}
            </svg>

            {selection && (['select-fill', 'crop'].includes(currentTool)) && (
               <div className="absolute pointer-events-none border-2 border-white" style={{ left: Math.min(selection.x1, selection.x2), top: Math.min(selection.y1, selection.y2), width: Math.abs(selection.x1 - selection.x2), height: Math.abs(selection.y1 - selection.y2) }}>
                 <div className="absolute inset-0 border-2 border-dashed border-black/50 animate-pulse" style={{ backgroundColor: currentTool === 'select-fill' ? fillColor : 'transparent', opacity: currentTool === 'select-fill' ? opacity : 1 }}></div>
               </div>
            )}
          </div>

          {/* Bottom Control Bar */}
          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-8 bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-6 rounded-[2.5rem] shadow-2xl z-30 min-w-[700px]">
             <div className="flex flex-col gap-3 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Stroke / Font Size</span>
                 <span className="text-[10px] font-black text-blue-400">{brushSize}px</span>
               </div>
               <input 
                type="range" min="1" max="100" value={brushSize} 
                onChange={(e) => {
                  const v = parseInt(e.target.value);
                  setBrushSize(v);
                  updateSelectedObjectProperty('strokeWidth', v);
                }} 
                className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500" 
               />
             </div>

             <div className="w-px h-8 bg-slate-800"></div>

             <div className="flex flex-col gap-3 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Opacity</span>
                 <span className="text-[10px] font-black text-indigo-400">{Math.round(opacity * 100)}%</span>
               </div>
               <input 
                type="range" min="0" max="1" step="0.01" value={opacity} 
                onChange={(e) => {
                  const v = parseFloat(e.target.value);
                  setOpacity(v);
                  updateSelectedObjectProperty('opacity', v);
                }} 
                className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" 
               />
             </div>

             {currentTool === 'ai-erase' && (
               <button onClick={runAIErase} disabled={isProcessing} className="px-8 py-3 bg-red-600 hover:bg-red-700 text-white rounded-2xl text-xs font-black shadow-xl flex items-center gap-3 transition-all active:scale-95 disabled:opacity-50">
                 {isProcessing ? <Loader2 className="animate-spin" size={16} /> : <Wand2 size={16} />} AI ERASE
               </button>
             )}
             {currentTool === 'select-fill' && (
               <button onClick={handleFill} disabled={!selection} className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">FILL AREA</button>
             )}
             {currentTool === 'crop' && (
               <button onClick={handleCrop} disabled={!selection} className="px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">CONFIRM CROP</button>
             )}
             {!['ai-erase', 'select-fill', 'crop'].includes(currentTool) && (
                <div className="px-6 text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 animate-pulse"></div>
                  {currentTool === 'select' ? (selectedObjectId ? 'Object Selected' : 'Select Tool') : `${currentTool} tool`}
                </div>
             )}
          </div>

          {isProcessing && <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/70 backdrop-blur-md"><Loader2 size={40} className="text-indigo-500 animate-spin" /><p className="mt-8 text-white font-black tracking-[0.3em] text-sm uppercase">AI Processing...</p></div>}
        </div>
      </div>
    </div>
  );
};

const ToolIcon = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1.5 group transition-all shrink-0 ${active ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>
    <div className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${active ? 'bg-indigo-600/10 border border-indigo-500/50 shadow-lg' : 'bg-slate-800/50 hover:bg-slate-800'}`}>
      {icon}
    </div>
    <span className="text-[8px] font-black uppercase tracking-tighter">{label}</span>
  </button>
);

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  X, Eraser, Scissors, PaintBucket, Crop, Save, Undo, 
  Wand2, Loader2, Download, MousePointer2, Maximize, 
  Type, Square, Circle, Minus, Move, Palette, Trash2,
  ZoomIn, ZoomOut, RotateCcw, Box, ArrowUpRight, RefreshCw, 
  Shapes, ChevronRight
} from 'lucide-react';
import { editImageWithAI } from '../services/geminiService';
import { UILanguage } from '../types';

interface ImageEditorProps {
  imageUrl: string;
  onClose: () => void;
  onSave: (newImageUrl: string) => void;
  uiLang: UILanguage;
}

type Tool = 'select' | 'select-fill' | 'brush' | 'ai-erase' | 'crop' | 'rect' | 'circle' | 'line' | 'text' | 'none';

interface EditorObject {
  id: string;
  type: 'rect' | 'circle' | 'line' | 'text';
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number; 
  stroke: string;
  fill: string;
  strokeWidth: number;
  fontSize?: number; // New decoupled property for text
  opacity: number; // 0 to 1
  text?: string;
}

interface EditorState {
  canvasData: string;
  objects: EditorObject[];
}

interface SelectionBox {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
}

const CORS_PROXY = 'https://corsproxy.io/?';

export const ImageEditor: React.FC<ImageEditorProps> = ({ imageUrl, onClose, onSave, uiLang }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [currentTool, setCurrentTool] = useState<Tool>('select');
  const [isProcessing, setIsProcessing] = useState(false);
  const [strokeColor, setStrokeColor] = useState('#000000');
  const [fillColor, setFillColor] = useState('#ffffff');
  const [brushSize, setBrushSize] = useState(24); // Now acts as default fontSize for text or weight for lines
  const [opacity, setOpacity] = useState(1); // 1.0 = 100%
  const [zoom, setZoom] = useState(1);

  // Shape menu state
  const [showShapeMenu, setShowShapeMenu] = useState(false);
  const [lastUsedShape, setLastUsedShape] = useState<'rect' | 'circle' | 'line'>('rect');

  // Object system
  const [objects, setObjects] = useState<EditorObject[]>([]);
  const [selectedObjectId, setSelectedObjectId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [isRotating, setIsRotating] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const [isDrawing, setIsDrawing] = useState(false);
  const [selection, setSelection] = useState<SelectionBox | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });

  const [history, setHistory] = useState<EditorState[]>([]);

  // Sync controls when selected object changes
  useEffect(() => {
    if (selectedObjectId) {
      const obj = objects.find(o => o.id === selectedObjectId);
      if (obj) {
        setStrokeColor(obj.stroke);
        setFillColor(obj.fill);
        // If it's text, the slider represents font size, else it represents stroke width
        setBrushSize(obj.type === 'text' ? (obj.fontSize || 24) : obj.strokeWidth);
        setOpacity(obj.opacity);
      }
    }
  }, [selectedObjectId]);

  // Real-time update functions
  const updateSelectedObjectProperty = (property: keyof EditorObject, value: any) => {
    if (selectedObjectId) {
      setObjects(prev => prev.map(o => o.id === selectedObjectId ? { ...o, [property]: value } : o));
    }
  };

  const saveToHistory = useCallback((currentObjects?: EditorObject[]) => {
    const canvas = canvasRef.current;
    if (canvas) {
      const newState: EditorState = {
        canvasData: canvas.toDataURL('image/png'),
        objects: currentObjects ? [...currentObjects] : [...objects]
      };
      setHistory(prev => [...prev.slice(-30), newState]);
    }
  }, [objects]);

  useEffect(() => {
    const initCanvas = async () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d', { willReadFrequently: true }) as CanvasRenderingContext2D | null;
      if (!ctx) return;

      setIsProcessing(true);
      try {
        const proxyUrl = `${CORS_PROXY}${encodeURIComponent(imageUrl)}`;
        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error("Failed to fetch image through proxy");
        const blob = await response.blob();
        const localUrl = URL.createObjectURL(blob);

        const img = new Image();
        img.src = localUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);

          if (containerRef.current) {
            const padding = 120;
            const availableW = containerRef.current.clientWidth - padding;
            const availableH = containerRef.current.clientHeight - padding;
            const scale = Math.min(availableW / img.width, availableH / img.height, 1);
            setZoom(scale || 1);
          }

          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
          URL.revokeObjectURL(localUrl);
        };
      } catch (err) {
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.src = imageUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          (ctx as CanvasRenderingContext2D).drawImage(img, 0, 0);
          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
        };
      }
    };
    initCanvas();
  }, [imageUrl]);

  const undo = () => {
    if (history.length <= 1) return;
    const newHistory = [...history];
    newHistory.pop(); 
    const prevState = newHistory[newHistory.length - 1];

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (canvas && ctx && prevState) {
      const img = new Image();
      img.src = prevState.canvasData;
      img.onload = () => {
        canvas.width = img.width;
        canvas.height = img.height;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        setObjects(prevState.objects);
        setHistory(newHistory);
      };
    }
  };

  const standardize = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const currentData = canvas.toDataURL();
    const tempImg = new Image();
    tempImg.src = currentData;
    tempImg.onload = () => {
      const targetSize = 1600;
      const safeArea = 1500;

      const scale = Math.min(safeArea / tempImg.width, safeArea / tempImg.height);
      const drawW = tempImg.width * scale;
      const drawH = tempImg.height * scale;
      const offsetX = (targetSize - drawW) / 2;
      const offsetY = (targetSize - drawH) / 2;

      const transformedObjects = objects.map(obj => ({
        ...obj,
        x: obj.x * scale + offsetX,
        y: obj.y * scale + offsetY,
        width: obj.width * scale,
        height: obj.height * scale,
        strokeWidth: obj.strokeWidth * scale,
        fontSize: obj.fontSize ? obj.fontSize * scale : undefined
      }));

      canvas.width = targetSize;
      canvas.height = targetSize;
      const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, targetSize, targetSize);
      ctx.drawImage(tempImg, offsetX, offsetY, drawW, drawH);

      setObjects(transformedObjects);
      saveToHistory(transformedObjects);

      if (containerRef.current) {
        setZoom(Math.min((containerRef.current.clientHeight - 120) / 1600, 1));
      }
    };
  };

  const getMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }
    return {
      x: (clientX - rect.left) / zoom,
      y: (clientY - rect.top) / zoom
    };
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);
    setStartPos(pos);

    if (currentTool === 'select') {
      if (selectedObjectId) {
        const obj = objects.find(o => o.id === selectedObjectId);
        if (obj) {
          const handleSize = 12 / zoom;
          const rotateHandleY = obj.y - 30 / zoom;
          const centerX = obj.x + obj.width / 2;

          const distToRotate = Math.sqrt(Math.pow(pos.x - centerX, 2) + Math.pow(pos.y - rotateHandleY, 2));
          if (distToRotate < handleSize) {
            setIsRotating(true);
            return;
          }

          const isOverResizeHandle = 
            pos.x >= obj.x + obj.width - handleSize && 
            pos.x <= obj.x + obj.width + handleSize && 
            pos.y >= obj.y + obj.height - handleSize && 
            pos.y <= obj.y + obj.height + handleSize;

          if (isOverResizeHandle) {
            setIsResizing(true);
            return;
          }

          const isOverBody = 
            pos.x >= obj.x && pos.x <= obj.x + obj.width &&
            pos.y >= obj.y && pos.y <= obj.y + obj.height;

          if (isOverBody) {
            setIsDragging(true);
            setDragOffset({ x: pos.x - obj.x, y: pos.y - obj.y });
            return;
          }
        }
      }

      const hit = objects.slice().reverse().find(obj => 
        pos.x >= obj.x && pos.x <= obj.x + obj.width &&
        pos.y >= obj.y && pos.y <= obj.y + obj.height
      );

      if (hit) {
        setSelectedObjectId(hit.id);
        setIsDragging(true);
        setDragOffset({ x: pos.x - hit.x, y: pos.y - hit.y });
      } else {
        setSelectedObjectId(null);
      }
      return;
    }

    setIsDrawing(true);
    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection({ x1: pos.x, y1: pos.y, x2: pos.x, y2: pos.y });
    }

    if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.beginPath();
        ctx.moveTo(pos.x, pos.y);
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.globalAlpha = opacity;
        ctx.strokeStyle = currentTool === 'ai-erase' ? 'rgba(255, 0, 0, 0.6)' : strokeColor;
        ctx.lineWidth = brushSize;
      }
    }
  };

  const handleMove = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);

    if (currentTool === 'select' && selectedObjectId) {
      const obj = objects.find(o => o.id === selectedObjectId);
      if (!obj) return;

      if (isDragging) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, x: pos.x - dragOffset.x, y: pos.y - dragOffset.y }
            : o
        ));
      } else if (isResizing) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, width: Math.max(10, pos.x - o.x), height: Math.max(10, pos.y - o.y) }
            : o
        ));
      } else if (isRotating) {
        const centerX = obj.x + obj.width / 2;
        const centerY = obj.y + obj.height / 2;
        const angle = Math.atan2(pos.y - centerY, pos.x - centerX) + Math.PI / 2;
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId ? { ...o, rotation: angle } : o
        ));
      }
      return;
    }

    if (!isDrawing) return;

    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection(prev => prev ? { ...prev, x2: pos.x, y2: pos.y } : null);
    } else if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.lineTo(pos.x, pos.y);
        ctx.stroke();
      }
    }
  };

  const handleEnd = (e: React.MouseEvent | React.TouchEvent) => {
    if (currentTool === 'select') {
      if (isDragging || isResizing || isRotating) {
        saveToHistory(objects);
      }
      setIsDragging(false);
      setIsResizing(false);
      setIsRotating(false);
      return;
    }

    if (!isDrawing) return;
    setIsDrawing(false);

    const pos = getMousePos(e);

    if (['rect', 'circle', 'line'].includes(currentTool)) {
      const newObj: EditorObject = {
        id: crypto.randomUUID(),
        type: currentTool as any,
        x: Math.min(startPos.x, pos.x),
        y: Math.min(startPos.y, pos.y),
        width: Math.abs(startPos.x - pos.x),
        height: Math.abs(startPos.y - pos.y),
        rotation: 0,
        stroke: strokeColor,
        fill: fillColor,
        strokeWidth: brushSize,
        opacity: opacity
      };
      const nextObjects = [...objects, newObj];
      setObjects(nextObjects);
      setSelectedObjectId(newObj.id);
      setCurrentTool('select');
      setSelection(null);
      saveToHistory(nextObjects);
    } else if (currentTool === 'text') {
      const text = window.prompt(uiLang === 'zh' ? "输入文字:" : "Enter text:");
      if (text) {
        const newObj: EditorObject = {
          id: crypto.randomUUID(),
          type: 'text',
          x: pos.x,
          y: pos.y,
          width: text.length * brushSize * 0.6,
          height: brushSize,
          rotation: 0,
          stroke: strokeColor,
          fill: fillColor,
          strokeWidth: 1, // Default thin stroke for text
          fontSize: brushSize, // Use decoupled font size
          opacity: opacity,
          text: text
        };
        const nextObjects = [...objects, newObj];
        setObjects(nextObjects);
        setSelectedObjectId(newObj.id);
        setCurrentTool('select');
        saveToHistory(nextObjects);
      }
    } else if (currentTool === 'brush') {
      saveToHistory();
    }
  };

  const handleFill = () => {
    if (currentTool !== 'select-fill' || !selection) return;

    const newObj: EditorObject = {
      id: crypto.randomUUID(),
      type: 'rect',
      x: Math.min(selection.x1, selection.x2),
      y: Math.min(selection.y1, selection.y2),
      width: Math.abs(selection.x1 - selection.x2),
      height: Math.abs(selection.y1 - selection.y2),
      rotation: 0,
      stroke: 'transparent',
      fill: fillColor,
      strokeWidth: 0,
      opacity: opacity
    };

    const nextObjects = [...objects, newObj];
    setObjects(nextObjects);
    setSelectedObjectId(newObj.id);
    saveToHistory(nextObjects);
    setSelection(null); 
    setCurrentTool('select');
  };

  const handleCrop = () => {
    if (!selection) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    if (w < 5 || h < 5) return;
    const imageData = ctx.getImageData(x, y, w, h);
    canvas.width = w;
    canvas.height = h;
    ctx.putImageData(imageData, 0, 0);
    saveToHistory();
    setSelection(null);
    setZoom(1);
    setCurrentTool('select');
  };

  const runAIErase = async () => {
    setIsProcessing(true);
    try {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const base64 = canvas.toDataURL('image/jpeg', 0.9).split(',')[1];
      const result = await editImageWithAI(base64, "Please erase the red highlighted areas cleanly.");
      const img = new Image();
      img.src = `data:image/jpeg;base64,${result}`;
      img.onload = () => {
        const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        saveToHistory();
        setIsProcessing(false);
      };
    } catch (e: any) {
      alert("AI Erase failed: " + e.message);
      setIsProcessing(false);
    }
  };

  const handleFinalSave = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Draw all objects onto the canvas before saving
    objects.forEach(obj => {
      ctx.save();
      const cx = obj.x + obj.width / 2;
      const cy = obj.y + obj.height / 2;

      ctx.translate(cx, cy);
      ctx.rotate(obj.rotation);
      ctx.translate(-cx, -cy);

      ctx.globalAlpha = obj.opacity;
      ctx.strokeStyle = obj.stroke;
      ctx.fillStyle = obj.fill;
      ctx.lineWidth = obj.strokeWidth;
      ctx.lineCap = 'round';

      if (obj.type === 'rect') {
        ctx.beginPath();
        ctx.rect(obj.x, obj.y, obj.width, obj.height);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'circle') {
        const r = Math.sqrt(obj.width * obj.width + obj.height * obj.height) / 2;
        ctx.beginPath();
        ctx.arc(obj.x + obj.width/2, obj.y + obj.height/2, r, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'line') {
        ctx.beginPath();
        ctx.moveTo(obj.x, obj.y);
        ctx.lineTo(obj.x + obj.width, obj.y + obj.height);
        ctx.stroke();
      } else if (obj.type === 'text' && obj.text) {
        const fs = obj.fontSize || 24;
        ctx.font = `bold ${fs}px Inter, sans-serif`;
        // Draw fill first, then stroke to prevent stroke from over-expanding inwards
        ctx.fillText(obj.text, obj.x, obj.y + obj.height);
        if (obj.stroke !== 'transparent' && obj.strokeWidth > 0) {
           ctx.strokeText(obj.text, obj.x, obj.y + obj.height);
        }
      }
      ctx.restore();
    });

    onSave(canvas.toDataURL('image/jpeg', 0.95));
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.key === 'Delete' || e.key === 'Backspace')) {
         if (selectedObjectId) {
            const nextObjects = objects.filter(o => o.id !== selectedObjectId);
            setObjects(nextObjects);
            setSelectedObjectId(null);
            saveToHistory(nextObjects);
         } else if (currentTool === 'select-fill' && selection) {
            handleFill();
         }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedObjectId, objects, saveToHistory, currentTool, selection, fillColor, opacity]);

  const ShapeIcon = lastUsedShape === 'rect' ? Square : lastUsedShape === 'circle' ? Circle : Minus;

  // Context-aware slider labels
  const selectedObject = objects.find(o => o.id === selectedObjectId);
  const isTextSelected = selectedObject?.type === 'text' || currentTool === 'text';

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col font-inter">
      <div className="h-16 bg-slate-900 border-b border-slate-800 px-6 flex items-center justify-between text-white shadow-xl z-20">
        <div className="flex items-center gap-6">
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-all"><X size={20} /></button>
          <div className="h-6 w-px bg-slate-800"></div>
          <h2 className="font-black tracking-tighter text-xl bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent uppercase">AI Media Lab</h2>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex bg-slate-800 p-1 rounded-xl">
            <button onClick={() => setZoom(prev => Math.max(0.05, prev - 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomOut size={16} /></button>
            <span className="px-3 flex items-center text-[10px] font-black text-slate-300 w-16 justify-center">{(zoom * 100).toFixed(0)}%</span>
            <button onClick={() => setZoom(prev => Math.min(5, prev + 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomIn size={16} /></button>
          </div>
          <button onClick={undo} disabled={history.length <= 1} className="p-2.5 bg-slate-800 hover:bg-slate-700 disabled:opacity-30 rounded-xl text-slate-300 transition-all"><Undo size={18} /></button>
          <button onClick={standardize} className="px-5 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-black flex items-center gap-2 border border-slate-700"><Maximize size={16} /> 1600*1600</button>
          <button onClick={handleFinalSave} className="px-8 py-2.5 bg-indigo-600 hover:bg-indigo-700 rounded-xl text-xs font-black shadow-lg flex items-center gap-2 transform active:scale-95 transition-all"><Save size={16} /> Save & Apply</button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden relative">
        {/* Left Toolbar */}
        <div className="w-24 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-6 z-40 relative">
          <ToolIcon active={currentTool === 'select'} onClick={() => { setCurrentTool('select'); setShowShapeMenu(false); }} icon={<MousePointer2 size={20} />} label="Select" />
          <ToolIcon active={currentTool === 'brush'} onClick={() => { setCurrentTool('brush'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Palette size={20} />} label="Brush" />
          <ToolIcon active={currentTool === 'ai-erase'} onClick={() => { setCurrentTool('ai-erase'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Eraser size={20} />} label="AI Erase" />

          {/* Shapes Entry - Grouped Submenu */}
          <div className="relative group/shape">
            <ToolIcon 
              active={['rect', 'circle', 'line'].includes(currentTool)} 
              onClick={() => { setShowShapeMenu(!showShapeMenu); }} 
              icon={<ShapeIcon size={20} />} 
              label="Shapes" 
            />
            {showShapeMenu && (
              <div 
                className="fixed left-24 top-auto bg-slate-800 border border-slate-700 p-2 rounded-xl shadow-2xl flex flex-col gap-2 z-[100] animate-in slide-in-from-left-2 duration-200"
                style={{ marginTop: '-40px' }}
              >
                <button onClick={() => { setCurrentTool('rect'); setLastUsedShape('rect'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'rect' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Square size={20} /></button>
                <button onClick={() => { setCurrentTool('circle'); setLastUsedShape('circle'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'circle' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Circle size={20} /></button>
                <button onClick={() => { setCurrentTool('line'); setLastUsedShape('line'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'line' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Minus size={20} /></button>
              </div>
            )}
          </div>

          <ToolIcon active={currentTool === 'text'} onClick={() => { setCurrentTool('text'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Type size={20} />} label="Text" />
          <ToolIcon active={currentTool === 'select-fill'} onClick={() => { setCurrentTool('select-fill'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<PaintBucket size={20} />} label="Fill" />
          <ToolIcon active={currentTool === 'crop'} onClick={() => { setCurrentTool('crop'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Scissors size={20} />} label="Crop" />

          <div className="mt-auto flex flex-col gap-4 pb-4">
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Stroke</span>
               <input 
                type="color" 
                value={strokeColor} 
                onChange={(e) => {
                  const v = e.target.value;
                  setStrokeColor(v);
                  updateSelectedObjectProperty('stroke', v);
                }} 
                className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700 transition-all hover:scale-105" 
               />
             </div>
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Fill</span>
               <input 
                type="color" 
                value={fillColor} 
                onChange={(e) => {
                  const v = e.target.value;
                  setFillColor(v);
                  updateSelectedObjectProperty('fill', v);
                }} 
                className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700 transition-all hover:scale-105" 
               />
             </div>
          </div>
        </div>

        {/* Canvas Area */}
        <div ref={containerRef} className="flex-1 bg-slate-950 overflow-auto flex items-center justify-center p-20 relative z-10">
          <div className="relative shadow-2xl transition-transform duration-75 origin-center" style={{ transform: `scale(${zoom})` }}>
            <canvas ref={canvasRef} onMouseDown={handleStart} onMouseMove={handleMove} onMouseUp={handleEnd} className="block relative" style={{ cursor: currentTool === 'none' ? 'default' : currentTool === 'select' ? 'default' : 'crosshair' }} />

            <svg 
              className="absolute inset-0 pointer-events-none w-full h-full"
              viewBox={`0 0 ${canvasRef.current?.width || 0} ${canvasRef.current?.height || 0}`}
            >
              {/* Render Temporary Drawing Preview */}
              {isDrawing && selection && ['rect', 'circle', 'line'].includes(currentTool) && (
                <g opacity={opacity}>
                  {currentTool === 'rect' && (
                    <rect 
                      x={Math.min(selection.x1, selection.x2)} 
                      y={Math.min(selection.y1, selection.y2)} 
                      width={Math.abs(selection.x1 - selection.x2)} 
                      height={Math.abs(selection.y1 - selection.y2)} 
                      stroke={strokeColor} 
                      fill={fillColor} 
                      strokeWidth={brushSize} 
                      strokeDasharray="5,5"
                    />
                  )}
                  {currentTool === 'circle' && (
                    <ellipse 
                      cx={(selection.x1 + selection.x2) / 2} 
                      cy={(selection.y1 + selection.y2) / 2} 
                      rx={Math.abs(selection.x1 - selection.x2) / 2} 
                      ry={Math.abs(selection.y1 - selection.y2) / 2} 
                      stroke={strokeColor} 
                      fill={fillColor} 
                      strokeWidth={brushSize} 
                      strokeDasharray="5,5"
                    />
                  )}
                  {currentTool === 'line' && (
                    <line 
                      x1={selection.x1} 
                      y1={selection.y1} 
                      x2={selection.x2} 
                      y2={selection.y2} 
                      stroke={strokeColor} 
                      strokeWidth={brushSize} 
                      strokeDasharray="5,5"
                    />
                  )}
                </g>
              )}

              {objects.map(obj => (
                <g 
                  key={obj.id} 
                  className={selectedObjectId === obj.id ? 'opacity-100' : 'opacity-80'}
                  transform={`rotate(${(obj.rotation * 180) / Math.PI} ${obj.x + obj.width / 2} ${obj.y + obj.height / 2})`}
                  style={{ opacity: obj.opacity }}
                >
                  {obj.type === 'rect' && <rect x={obj.x} y={obj.y} width={obj.width} height={obj.height} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'circle' && <ellipse cx={obj.x + obj.width/2} cy={obj.y + obj.height/2} rx={obj.width/2} ry={obj.height/2} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'line' && <line x1={obj.x} y1={obj.y} x2={obj.x + obj.width} y2={obj.y + obj.height} stroke={obj.stroke} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'text' && (
                    <text 
                      x={obj.x} 
                      y={obj.y + obj.height} 
                      fill={obj.fill} 
                      stroke={obj.stroke} 
                      strokeWidth={obj.strokeWidth} 
                      style={{ font: `bold ${obj.fontSize || 24}px Inter, sans-serif` }}
                    >
                      {obj.text}
                    </text>
                  )}
                  {selectedObjectId === obj.id && (
                    <>
                      <rect 
                        x={obj.x} y={obj.y} width={obj.width} height={obj.height} 
                        fill="none" stroke="#6366f1" strokeWidth={2 / zoom} strokeDasharray="4"
                      />
                      <circle 
                        cx={obj.x + obj.width} cy={obj.y + obj.height} r={6 / zoom} 
                        fill="#6366f1" className="cursor-nwse-resize pointer-events-auto" 
                      />
                      <line x1={obj.x + obj.width/2} y1={obj.y} x2={obj.x + obj.width/2} y2={obj.y - 30/zoom} stroke="#6366f1" strokeWidth={2/zoom} />
                      <circle 
                        cx={obj.x + obj.width/2} cy={obj.y - 30/zoom} r={8 / zoom} 
                        fill="#6366f1" className="cursor-pointer pointer-events-auto"
                      />
                    </>
                  )}
                </g>
              ))}
            </svg>

            {selection && (['select-fill', 'crop'].includes(currentTool)) && (
               <div className="absolute pointer-events-none border-2 border-white" style={{ left: Math.min(selection.x1, selection.x2), top: Math.min(selection.y1, selection.y2), width: Math.abs(selection.x1 - selection.x2), height: Math.abs(selection.y1 - selection.y2) }}>
                 <div className="absolute inset-0 border-2 border-dashed border-black/50 animate-pulse" style={{ backgroundColor: currentTool === 'select-fill' ? fillColor : 'transparent', opacity: currentTool === 'select-fill' ? opacity : 1 }}></div>
               </div>
            )}
          </div>

          {/* Bottom Control Bar */}
          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-8 bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-6 rounded-[2.5rem] shadow-2xl z-30 min-w-[700px]">
             <div className="flex flex-col gap-3 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{isTextSelected ? 'Font Size' : 'Stroke / Size'}</span>
                 <span className="text-[10px] font-black text-blue-400">{brushSize}px</span>
               </div>
               <input 
                type="range" min={isTextSelected ? 8 : 1} max={isTextSelected ? 200 : 100} value={brushSize} 
                onChange={(e) => {
                  const v = parseInt(e.target.value);
                  setBrushSize(v);
                  if (selectedObject?.type === 'text') {
                    updateSelectedObjectProperty('fontSize', v);
                    // Also update bounding box roughly for text
                    updateSelectedObjectProperty('width', (selectedObject.text?.length || 1) * v * 0.6);
                    updateSelectedObjectProperty('height', v);
                  } else {
                    updateSelectedObjectProperty('strokeWidth', v);
                  }
                }} 
                className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500" 
               />
             </div>

             <div className="w-px h-8 bg-slate-800"></div>

             <div className="flex flex-col gap-3 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Opacity</span>
                 <span className="text-[10px] font-black text-indigo-400">{Math.round(opacity * 100)}%</span>
               </div>
               <input 
                type="range" min="0" max="1" step="0.01" value={opacity} 
                onChange={(e) => {
                  const v = parseFloat(e.target.value);
                  setOpacity(v);
                  updateSelectedObjectProperty('opacity', v);
                }} 
                className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" 
               />
             </div>

             {currentTool === 'ai-erase' && (
               <button onClick={runAIErase} disabled={isProcessing} className="px-8 py-3 bg-red-600 hover:bg-red-700 text-white rounded-2xl text-xs font-black shadow-xl flex items-center gap-3 transition-all active:scale-95 disabled:opacity-50">
                 {isProcessing ? <Loader2 className="animate-spin" size={16} /> : <Wand2 size={16} />} AI ERASE
               </button>
             )}
             {currentTool === 'select-fill' && (
               <button onClick={handleFill} disabled={!selection} className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">FILL AREA</button>
             )}
             {currentTool === 'crop' && (
               <button onClick={handleCrop} disabled={!selection} className="px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">CONFIRM CROP</button>
             )}
             {!['ai-erase', 'select-fill', 'crop'].includes(currentTool) && (
                <div className="px-6 text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 animate-pulse"></div>
                  {currentTool === 'select' ? (selectedObjectId ? 'Object Selected' : 'Select Tool') : `${currentTool} tool`}
                </div>
             )}
          </div>

          {isProcessing && <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/70 backdrop-blur-md"><Loader2 size={40} className="text-indigo-500 animate-spin" /><p className="mt-8 text-white font-black tracking-[0.3em] text-sm uppercase">AI Processing...</p></div>}
        </div>
      </div>
    </div>
  );
};

const ToolIcon = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1.5 group transition-all shrink-0 ${active ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>
    <div className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${active ? 'bg-indigo-600/10 border border-indigo-500/50 shadow-lg' : 'bg-slate-800/50 hover:bg-slate-800'}`}>
      {icon}
    </div>
    <span className="text-[8px] font-black uppercase tracking-tighter">{label}</span>
  </button>
);

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  X, Eraser, Scissors, PaintBucket, Crop, Save, Undo, 
  Wand2, Loader2, Download, MousePointer2, Maximize, 
  Type, Square, Circle, Minus, Move, Palette, Trash2,
  ZoomIn, ZoomOut, RotateCcw, Box, ArrowUpRight, RefreshCw, 
  Shapes, ChevronRight
} from 'lucide-react';
import { editImageWithAI } from '../services/geminiService';
import { UILanguage } from '../types';

interface ImageEditorProps {
  imageUrl: string;
  onClose: () => void;
  onSave: (newImageUrl: string) => void;
  uiLang: UILanguage;
}

type Tool = 'select' | 'select-fill' | 'brush' | 'ai-erase' | 'crop' | 'rect' | 'circle' | 'line' | 'text' | 'none';

interface EditorObject {
  id: string;
  type: 'rect' | 'circle' | 'line' | 'text';
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number; 
  stroke: string;
  fill: string;
  strokeWidth: number;
  fontSize?: number; 
  opacity: number; // 0 to 1
  text?: string;
}

interface EditorState {
  canvasData: string;
  objects: EditorObject[];
}

interface SelectionBox {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
}

const CORS_PROXY = 'https://corsproxy.io/?';

export const ImageEditor: React.FC<ImageEditorProps> = ({ imageUrl, onClose, onSave, uiLang }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [currentTool, setCurrentTool] = useState<Tool>('select');
  const [isProcessing, setIsProcessing] = useState(false);
  const [strokeColor, setStrokeColor] = useState('#000000');
  const [fillColor, setFillColor] = useState('#ffffff');

  // Decoupled size states
  const [strokeWidth, setStrokeWidth] = useState(5); // For shapes/lines
  const [fontSize, setFontSize] = useState(40);      // For text (Standard px)

  const [opacity, setOpacity] = useState(1); 
  const [zoom, setZoom] = useState(1);

  const [showShapeMenu, setShowShapeMenu] = useState(false);
  const [lastUsedShape, setLastUsedShape] = useState<'rect' | 'circle' | 'line'>('rect');

  const [objects, setObjects] = useState<EditorObject[]>([]);
  const [selectedObjectId, setSelectedObjectId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [isRotating, setIsRotating] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const [isDrawing, setIsDrawing] = useState(false);
  const [selection, setSelection] = useState<SelectionBox | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });

  const [history, setHistory] = useState<EditorState[]>([]);

  // Derived state to determine which size property we are currently editing
  const selectedObject = objects.find(o => o.id === selectedObjectId);
  const isEditingText = selectedObject?.type === 'text' || (currentTool === 'text' && !selectedObject);

  // Sync controls when selected object changes
  useEffect(() => {
    if (selectedObjectId) {
      const obj = objects.find(o => o.id === selectedObjectId);
      if (obj) {
        setStrokeColor(obj.stroke);
        setFillColor(obj.fill);
        setOpacity(obj.opacity);
        if (obj.type === 'text') {
          setFontSize(obj.fontSize || 40);
        } else {
          setStrokeWidth(obj.strokeWidth);
        }
      }
    }
  }, [selectedObjectId]);

  const updateSelectedObjectProperty = (property: keyof EditorObject, value: any) => {
    if (selectedObjectId) {
      setObjects(prev => prev.map(o => o.id === selectedObjectId ? { ...o, [property]: value } : o));
    }
  };

  const saveToHistory = useCallback((currentObjects?: EditorObject[]) => {
    const canvas = canvasRef.current;
    if (canvas) {
      const newState: EditorState = {
        canvasData: canvas.toDataURL('image/png'),
        objects: currentObjects ? [...currentObjects] : [...objects]
      };
      setHistory(prev => [...prev.slice(-30), newState]);
    }
  }, [objects]);

  useEffect(() => {
    const initCanvas = async () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d', { willReadFrequently: true }) as CanvasRenderingContext2D | null;
      if (!ctx) return;

      setIsProcessing(true);
      try {
        const proxyUrl = `${CORS_PROXY}${encodeURIComponent(imageUrl)}`;
        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error("Failed to fetch image through proxy");
        const blob = await response.blob();
        const localUrl = URL.createObjectURL(blob);

        const img = new Image();
        img.src = localUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);

          if (containerRef.current) {
            const padding = 120;
            const availableW = containerRef.current.clientWidth - padding;
            const availableH = containerRef.current.clientHeight - padding;
            const scale = Math.min(availableW / img.width, availableH / img.height, 1);
            setZoom(scale || 1);
          }

          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
          URL.revokeObjectURL(localUrl);
        };
      } catch (err) {
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.src = imageUrl;
        img.onload = () => {
          canvas.width = img.width;
          canvas.height = img.height;
          (ctx as CanvasRenderingContext2D).drawImage(img, 0, 0);
          const initialState: EditorState = {
            canvasData: canvas.toDataURL('image/png'),
            objects: []
          };
          setHistory([initialState]);
          setIsProcessing(false);
        };
      }
    };
    initCanvas();
  }, [imageUrl]);

  const undo = () => {
    if (history.length <= 1) return;
    const newHistory = [...history];
    newHistory.pop(); 
    const prevState = newHistory[newHistory.length - 1];

    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d') as CanvasRenderingContext2D | null;
    if (canvas && ctx && prevState) {
      const img = new Image();
      img.src = prevState.canvasData;
      img.onload = () => {
        canvas.width = img.width;
        canvas.height = img.height;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        setObjects(prevState.objects);
        setHistory(newHistory);
      };
    }
  };

  const standardize = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const currentData = canvas.toDataURL();
    const tempImg = new Image();
    tempImg.src = currentData;
    tempImg.onload = () => {
      const targetSize = 1600;
      const safeArea = 1500;

      const scale = Math.min(safeArea / tempImg.width, safeArea / tempImg.height);
      const drawW = tempImg.width * scale;
      const drawH = tempImg.height * scale;
      const offsetX = (targetSize - drawW) / 2;
      const offsetY = (targetSize - drawH) / 2;

      const transformedObjects = objects.map(obj => ({
        ...obj,
        x: obj.x * scale + offsetX,
        y: obj.y * scale + offsetY,
        width: obj.width * scale,
        height: obj.height * scale,
        strokeWidth: obj.strokeWidth * scale,
        fontSize: obj.fontSize ? obj.fontSize * scale : undefined
      }));

      canvas.width = targetSize;
      canvas.height = targetSize;
      const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, targetSize, targetSize);
      ctx.drawImage(tempImg, offsetX, offsetY, drawW, drawH);

      setObjects(transformedObjects);
      saveToHistory(transformedObjects);

      if (containerRef.current) {
        setZoom(Math.min((containerRef.current.clientHeight - 120) / 1600, 1));
      }
    };
  };

  const getMousePos = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }
    return {
      x: (clientX - rect.left) / zoom,
      y: (clientY - rect.top) / zoom
    };
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);
    setStartPos(pos);

    if (currentTool === 'select') {
      if (selectedObjectId) {
        const obj = objects.find(o => o.id === selectedObjectId);
        if (obj) {
          const handleSize = 12 / zoom;
          const rotateHandleY = obj.y - 30 / zoom;
          const centerX = obj.x + obj.width / 2;

          const distToRotate = Math.sqrt(Math.pow(pos.x - centerX, 2) + Math.pow(pos.y - rotateHandleY, 2));
          if (distToRotate < handleSize) {
            setIsRotating(true);
            return;
          }

          const isOverResizeHandle = 
            pos.x >= obj.x + obj.width - handleSize && 
            pos.x <= obj.x + obj.width + handleSize && 
            pos.y >= obj.y + obj.height - handleSize && 
            pos.y <= obj.y + obj.height + handleSize;

          if (isOverResizeHandle) {
            setIsResizing(true);
            return;
          }

          const isOverBody = 
            pos.x >= obj.x && pos.x <= obj.x + obj.width &&
            pos.y >= obj.y && pos.y <= obj.y + obj.height;

          if (isOverBody) {
            setIsDragging(true);
            setDragOffset({ x: pos.x - obj.x, y: pos.y - obj.y });
            return;
          }
        }
      }

      const hit = objects.slice().reverse().find(obj => 
        pos.x >= obj.x && pos.x <= obj.x + obj.width &&
        pos.y >= obj.y && pos.y <= obj.y + obj.height
      );

      if (hit) {
        setSelectedObjectId(hit.id);
        setIsDragging(true);
        setDragOffset({ x: pos.x - hit.x, y: pos.y - hit.y });
      } else {
        setSelectedObjectId(null);
      }
      return;
    }

    setIsDrawing(true);
    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection({ x1: pos.x, y1: pos.y, x2: pos.x, y2: pos.y });
    }

    if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.beginPath();
        ctx.moveTo(pos.x, pos.y);
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.globalAlpha = opacity;
        ctx.strokeStyle = currentTool === 'ai-erase' ? 'rgba(255, 0, 0, 0.6)' : strokeColor;
        ctx.lineWidth = strokeWidth;
      }
    }
  };

  const handleMove = (e: React.MouseEvent | React.TouchEvent) => {
    const pos = getMousePos(e);

    if (currentTool === 'select' && selectedObjectId) {
      const obj = objects.find(o => o.id === selectedObjectId);
      if (!obj) return;

      if (isDragging) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, x: pos.x - dragOffset.x, y: pos.y - dragOffset.y }
            : o
        ));
      } else if (isResizing) {
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId 
            ? { ...o, width: Math.max(10, pos.x - o.x), height: Math.max(10, pos.y - o.y) }
            : o
        ));
      } else if (isRotating) {
        const centerX = obj.x + obj.width / 2;
        const centerY = obj.y + obj.height / 2;
        const angle = Math.atan2(pos.y - centerY, pos.x - centerX) + Math.PI / 2;
        setObjects(prev => prev.map(o => 
          o.id === selectedObjectId ? { ...o, rotation: angle } : o
        ));
      }
      return;
    }

    if (!isDrawing) return;

    if (['rect', 'circle', 'line', 'select-fill', 'crop'].includes(currentTool)) {
      setSelection(prev => prev ? { ...prev, x2: pos.x, y2: pos.y } : null);
    } else if (currentTool === 'brush' || currentTool === 'ai-erase') {
      const ctx = canvasRef.current?.getContext('2d') as CanvasRenderingContext2D | null;
      if (ctx) {
        ctx.lineTo(pos.x, pos.y);
        ctx.stroke();
      }
    }
  };

  const handleEnd = (e: React.MouseEvent | React.TouchEvent) => {
    if (currentTool === 'select') {
      if (isDragging || isResizing || isRotating) {
        saveToHistory(objects);
      }
      setIsDragging(false);
      setIsResizing(false);
      setIsRotating(false);
      return;
    }

    if (!isDrawing) return;
    setIsDrawing(false);

    const pos = getMousePos(e);

    if (['rect', 'circle', 'line'].includes(currentTool)) {
      const newObj: EditorObject = {
        id: crypto.randomUUID(),
        type: currentTool as any,
        x: Math.min(startPos.x, pos.x),
        y: Math.min(startPos.y, pos.y),
        width: Math.abs(startPos.x - pos.x),
        height: Math.abs(startPos.y - pos.y),
        rotation: 0,
        stroke: strokeColor,
        fill: fillColor,
        strokeWidth: strokeWidth,
        opacity: opacity
      };
      const nextObjects = [...objects, newObj];
      setObjects(nextObjects);
      setSelectedObjectId(newObj.id);
      setCurrentTool('select');
      setSelection(null);
      saveToHistory(nextObjects);
    } else if (currentTool === 'text') {
      const text = window.prompt(uiLang === 'zh' ? "输入文字:" : "Enter text:");
      if (text) {
        const newObj: EditorObject = {
          id: crypto.randomUUID(),
          type: 'text',
          x: pos.x,
          y: pos.y,
          // Roughly estimate size for text box
          width: text.length * fontSize * 0.6,
          height: fontSize,
          rotation: 0,
          stroke: strokeColor,
          fill: fillColor,
          strokeWidth: 1, // Fix stroke weight for text to standard 1
          fontSize: fontSize, 
          opacity: opacity,
          text: text
        };
        const nextObjects = [...objects, newObj];
        setObjects(nextObjects);
        setSelectedObjectId(newObj.id);
        setCurrentTool('select');
        saveToHistory(nextObjects);
      }
    } else if (currentTool === 'brush') {
      saveToHistory();
    }
  };

  const handleFill = () => {
    if (currentTool !== 'select-fill' || !selection) return;

    const newObj: EditorObject = {
      id: crypto.randomUUID(),
      type: 'rect',
      x: Math.min(selection.x1, selection.x2),
      y: Math.min(selection.y1, selection.y2),
      width: Math.abs(selection.x1 - selection.x2),
      height: Math.abs(selection.y1 - selection.y2),
      rotation: 0,
      stroke: 'transparent',
      fill: fillColor,
      strokeWidth: 0,
      opacity: opacity
    };

    const nextObjects = [...objects, newObj];
    setObjects(nextObjects);
    setSelectedObjectId(newObj.id);
    saveToHistory(nextObjects);
    setSelection(null); 
    setCurrentTool('select');
  };

  const handleCrop = () => {
    if (!selection) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d') as CanvasRenderingContext2D | null;
    if (!ctx) return;
    const x = Math.min(selection.x1, selection.x2);
    const y = Math.min(selection.y1, selection.y2);
    const w = Math.abs(selection.x1 - selection.x2);
    const h = Math.abs(selection.y1 - selection.y2);
    if (w < 5 || h < 5) return;
    const imageData = ctx.getImageData(x, y, w, h);
    canvas.width = w;
    canvas.height = h;
    ctx.putImageData(imageData, 0, 0);
    saveToHistory();
    setSelection(null);
    setZoom(1);
    setCurrentTool('select');
  };

  const runAIErase = async () => {
    setIsProcessing(true);
    try {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const base64 = canvas.toDataURL('image/jpeg', 0.9).split(',')[1];
      const result = await editImageWithAI(base64, "Please erase the red highlighted areas cleanly.");
      const img = new Image();
      img.src = `data:image/jpeg;base64,${result}`;
      img.onload = () => {
        const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
        saveToHistory();
        setIsProcessing(false);
      };
    } catch (e: any) {
      alert("AI Erase failed: " + e.message);
      setIsProcessing(false);
    }
  };

  const handleFinalSave = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Draw all objects onto the canvas before saving
    objects.forEach(obj => {
      ctx.save();
      const cx = obj.x + obj.width / 2;
      const cy = obj.y + obj.height / 2;

      ctx.translate(cx, cy);
      ctx.rotate(obj.rotation);
      ctx.translate(-cx, -cy);

      ctx.globalAlpha = obj.opacity;
      ctx.strokeStyle = obj.stroke;
      ctx.fillStyle = obj.fill;
      ctx.lineWidth = obj.strokeWidth;
      ctx.lineCap = 'round';

      if (obj.type === 'rect') {
        ctx.beginPath();
        ctx.rect(obj.x, obj.y, obj.width, obj.height);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'circle') {
        const r = Math.sqrt(obj.width * obj.width + obj.height * obj.height) / 2;
        ctx.beginPath();
        ctx.arc(obj.x + obj.width/2, obj.y + obj.height/2, r, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
      } else if (obj.type === 'line') {
        ctx.beginPath();
        ctx.moveTo(obj.x, obj.y);
        ctx.lineTo(obj.x + obj.width, obj.y + obj.height);
        ctx.stroke();
      } else if (obj.type === 'text' && obj.text) {
        const fs = obj.fontSize || 40;
        ctx.font = `bold ${fs}px Inter, sans-serif`;
        ctx.fillText(obj.text, obj.x, obj.y + obj.height);
        if (obj.stroke !== 'transparent' && obj.strokeWidth > 0) {
           ctx.strokeText(obj.text, obj.x, obj.y + obj.height);
        }
      }
      ctx.restore();
    });

    onSave(canvas.toDataURL('image/jpeg', 0.95));
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.key === 'Delete' || e.key === 'Backspace')) {
         if (selectedObjectId) {
            const nextObjects = objects.filter(o => o.id !== selectedObjectId);
            setObjects(nextObjects);
            setSelectedObjectId(null);
            saveToHistory(nextObjects);
         } else if (currentTool === 'select-fill' && selection) {
            handleFill();
         }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedObjectId, objects, saveToHistory, currentTool, selection, fillColor, opacity]);

  const ShapeIcon = lastUsedShape === 'rect' ? Square : lastUsedShape === 'circle' ? Circle : Minus;

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col font-inter">
      <div className="h-16 bg-slate-900 border-b border-slate-800 px-6 flex items-center justify-between text-white shadow-xl z-20">
        <div className="flex items-center gap-6">
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-all"><X size={20} /></button>
          <div className="h-6 w-px bg-slate-800"></div>
          <h2 className="font-black tracking-tighter text-xl bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent uppercase">AI Media Lab</h2>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex bg-slate-800 p-1 rounded-xl">
            <button onClick={() => setZoom(prev => Math.max(0.05, prev - 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomOut size={16} /></button>
            <span className="px-3 flex items-center text-[10px] font-black text-slate-300 w-16 justify-center">{(zoom * 100).toFixed(0)}%</span>
            <button onClick={() => setZoom(prev => Math.min(5, prev + 0.1))} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400"><ZoomIn size={16} /></button>
          </div>
          <button onClick={undo} disabled={history.length <= 1} className="p-2.5 bg-slate-800 hover:bg-slate-700 disabled:opacity-30 rounded-xl text-slate-300 transition-all"><Undo size={18} /></button>
          <button onClick={standardize} className="px-5 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-black flex items-center gap-2 border border-slate-700"><Maximize size={16} /> 1600*1600</button>
          <button onClick={handleFinalSave} className="px-8 py-2.5 bg-indigo-600 hover:bg-indigo-700 rounded-xl text-xs font-black shadow-lg flex items-center gap-2 transform active:scale-95 transition-all"><Save size={16} /> Save & Apply</button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden relative">
        {/* Left Toolbar */}
        <div className="w-24 bg-slate-900 border-r border-slate-800 flex flex-col items-center py-6 gap-6 z-40 relative">
          <ToolIcon active={currentTool === 'select'} onClick={() => { setCurrentTool('select'); setShowShapeMenu(false); }} icon={<MousePointer2 size={20} />} label="Select" />
          <ToolIcon active={currentTool === 'brush'} onClick={() => { setCurrentTool('brush'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Palette size={20} />} label="Brush" />
          <ToolIcon active={currentTool === 'ai-erase'} onClick={() => { setCurrentTool('ai-erase'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Eraser size={20} />} label="AI Erase" />

          <div className="relative group/shape">
            <ToolIcon 
              active={['rect', 'circle', 'line'].includes(currentTool)} 
              onClick={() => { setShowShapeMenu(!showShapeMenu); }} 
              icon={<ShapeIcon size={20} />} 
              label="Shapes" 
            />
            {showShapeMenu && (
              <div 
                className="fixed left-24 top-auto bg-slate-800 border border-slate-700 p-2 rounded-xl shadow-2xl flex flex-col gap-2 z-[100] animate-in slide-in-from-left-2 duration-200"
                style={{ marginTop: '-40px' }}
              >
                <button onClick={() => { setCurrentTool('rect'); setLastUsedShape('rect'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'rect' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Square size={20} /></button>
                <button onClick={() => { setCurrentTool('circle'); setLastUsedShape('circle'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'circle' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Circle size={20} /></button>
                <button onClick={() => { setCurrentTool('line'); setLastUsedShape('line'); setShowShapeMenu(false); }} className={`p-3 rounded-lg hover:bg-indigo-600 transition-all ${currentTool === 'line' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}><Minus size={20} /></button>
              </div>
            )}
          </div>

          <ToolIcon active={currentTool === 'text'} onClick={() => { setCurrentTool('text'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Type size={20} />} label="Text" />
          <ToolIcon active={currentTool === 'select-fill'} onClick={() => { setCurrentTool('select-fill'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<PaintBucket size={20} />} label="Fill" />
          <ToolIcon active={currentTool === 'crop'} onClick={() => { setCurrentTool('crop'); setSelectedObjectId(null); setShowShapeMenu(false); }} icon={<Scissors size={20} />} label="Crop" />

          <div className="mt-auto flex flex-col gap-4 pb-4">
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Stroke</span>
               <input 
                type="color" 
                value={strokeColor} 
                onChange={(e) => {
                  const v = e.target.value;
                  setStrokeColor(v);
                  updateSelectedObjectProperty('stroke', v);
                }} 
                className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700 transition-all hover:scale-105" 
               />
             </div>
             <div className="space-y-1">
               <span className="text-[8px] font-black text-slate-500 uppercase text-center block">Fill</span>
               <input 
                type="color" 
                value={fillColor} 
                onChange={(e) => {
                  const v = e.target.value;
                  setFillColor(v);
                  updateSelectedObjectProperty('fill', v);
                }} 
                className="w-10 h-10 rounded-xl cursor-pointer bg-slate-800 p-1 border border-slate-700 transition-all hover:scale-105" 
               />
             </div>
          </div>
        </div>

        {/* Canvas Area */}
        <div ref={containerRef} className="flex-1 bg-slate-950 overflow-auto flex items-center justify-center p-20 relative z-10">
          <div className="relative shadow-2xl transition-transform duration-75 origin-center" style={{ transform: `scale(${zoom})` }}>
            <canvas ref={canvasRef} onMouseDown={handleStart} onMouseMove={handleMove} onMouseUp={handleEnd} className="block relative" style={{ cursor: currentTool === 'none' ? 'default' : currentTool === 'select' ? 'default' : 'crosshair' }} />

            <svg 
              className="absolute inset-0 pointer-events-none w-full h-full"
              viewBox={`0 0 ${canvasRef.current?.width || 0} ${canvasRef.current?.height || 0}`}
            >
              {/* Render Temporary Drawing Preview */}
              {isDrawing && selection && ['rect', 'circle', 'line'].includes(currentTool) && (
                <g opacity={opacity}>
                  {currentTool === 'rect' && (
                    <rect 
                      x={Math.min(selection.x1, selection.x2)} 
                      y={Math.min(selection.y1, selection.y2)} 
                      width={Math.abs(selection.x1 - selection.x2)} 
                      height={Math.abs(selection.y1 - selection.y2)} 
                      stroke={strokeColor} 
                      fill={fillColor} 
                      strokeWidth={strokeWidth} 
                      strokeDasharray="5,5"
                    />
                  )}
                  {currentTool === 'circle' && (
                    <ellipse 
                      cx={(selection.x1 + selection.x2) / 2} 
                      cy={(selection.y1 + selection.y2) / 2} 
                      rx={Math.abs(selection.x1 - selection.x2) / 2} 
                      ry={Math.abs(selection.y1 - selection.y2) / 2} 
                      stroke={strokeColor} 
                      fill={fillColor} 
                      strokeWidth={strokeWidth} 
                      strokeDasharray="5,5"
                    />
                  )}
                  {currentTool === 'line' && (
                    <line 
                      x1={selection.x1} 
                      y1={selection.y1} 
                      x2={selection.x2} 
                      y2={selection.y2} 
                      stroke={strokeColor} 
                      strokeWidth={strokeWidth} 
                      strokeDasharray="5,5"
                    />
                  )}
                </g>
              )}

              {objects.map(obj => (
                <g 
                  key={obj.id} 
                  className={selectedObjectId === obj.id ? 'opacity-100' : 'opacity-80'}
                  transform={`rotate(${(obj.rotation * 180) / Math.PI} ${obj.x + obj.width / 2} ${obj.y + obj.height / 2})`}
                  style={{ opacity: obj.opacity }}
                >
                  {obj.type === 'rect' && <rect x={obj.x} y={obj.y} width={obj.width} height={obj.height} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'circle' && <ellipse cx={obj.x + obj.width/2} cy={obj.y + obj.height/2} rx={obj.width/2} ry={obj.height/2} stroke={obj.stroke} fill={obj.fill} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'line' && <line x1={obj.x} y1={obj.y} x2={obj.x + obj.width} y2={obj.y + obj.height} stroke={obj.stroke} strokeWidth={obj.strokeWidth} />}
                  {obj.type === 'text' && (
                    <text 
                      x={obj.x} 
                      y={obj.y + obj.height} 
                      fill={obj.fill} 
                      stroke={obj.stroke} 
                      strokeWidth={obj.strokeWidth} 
                      style={{ font: `bold ${obj.fontSize || 40}px Inter, sans-serif` }}
                    >
                      {obj.text}
                    </text>
                  )}
                  {selectedObjectId === obj.id && (
                    <>
                      <rect 
                        x={obj.x} y={obj.y} width={obj.width} height={obj.height} 
                        fill="none" stroke="#6366f1" strokeWidth={2 / zoom} strokeDasharray="4"
                      />
                      <circle 
                        cx={obj.x + obj.width} cy={obj.y + obj.height} r={6 / zoom} 
                        fill="#6366f1" className="cursor-nwse-resize pointer-events-auto" 
                      />
                      <line x1={obj.x + obj.width/2} y1={obj.y} x2={obj.x + obj.width/2} y2={obj.y - 30/zoom} stroke="#6366f1" strokeWidth={2/zoom} />
                      <circle 
                        cx={obj.x + obj.width/2} cy={obj.y - 30/zoom} r={8 / zoom} 
                        fill="#6366f1" className="cursor-pointer pointer-events-auto"
                      />
                    </>
                  )}
                </g>
              ))}
            </svg>

            {selection && (['select-fill', 'crop'].includes(currentTool)) && (
               <div className="absolute pointer-events-none border-2 border-white" style={{ left: Math.min(selection.x1, selection.x2), top: Math.min(selection.y1, selection.y2), width: Math.abs(selection.x1 - selection.x2), height: Math.abs(selection.y1 - selection.y2) }}>
                 <div className="absolute inset-0 border-2 border-dashed border-black/50 animate-pulse" style={{ backgroundColor: currentTool === 'select-fill' ? fillColor : 'transparent', opacity: currentTool === 'select-fill' ? opacity : 1 }}></div>
               </div>
            )}
          </div>

          {/* Bottom Control Bar */}
          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-8 bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-6 rounded-[2.5rem] shadow-2xl z-30 min-w-[700px]">
             <div className="flex flex-col gap-3 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">
                   {isEditingText ? 'Standard Font Size (px)' : 'Stroke Weight (px)'}
                 </span>
                 <span className="text-[10px] font-black text-blue-400">
                   {isEditingText ? `${fontSize}px` : `${strokeWidth}px`}
                 </span>
               </div>
               <input 
                type="range" 
                min={isEditingText ? 12 : 1} 
                max={isEditingText ? 150 : 50} 
                value={isEditingText ? fontSize : strokeWidth} 
                onChange={(e) => {
                  const v = parseInt(e.target.value);
                  if (isEditingText) {
                    setFontSize(v);
                    if (selectedObject?.type === 'text') {
                      updateSelectedObjectProperty('fontSize', v);
                      // Update estimated bbox
                      updateSelectedObjectProperty('width', (selectedObject.text?.length || 1) * v * 0.6);
                      updateSelectedObjectProperty('height', v);
                    }
                  } else {
                    setStrokeWidth(v);
                    if (selectedObject && selectedObject.type !== 'text') {
                      updateSelectedObjectProperty('strokeWidth', v);
                    }
                  }
                }} 
                className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500" 
               />
             </div>

             <div className="w-px h-8 bg-slate-800"></div>

             <div className="flex flex-col gap-3 flex-1">
               <div className="flex justify-between">
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Opacity</span>
                 <span className="text-[10px] font-black text-indigo-400">{Math.round(opacity * 100)}%</span>
               </div>
               <input 
                type="range" min="0" max="1" step="0.01" value={opacity} 
                onChange={(e) => {
                  const v = parseFloat(e.target.value);
                  setOpacity(v);
                  updateSelectedObjectProperty('opacity', v);
                }} 
                className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" 
               />
             </div>

             {currentTool === 'ai-erase' && (
               <button onClick={runAIErase} disabled={isProcessing} className="px-8 py-3 bg-red-600 hover:bg-red-700 text-white rounded-2xl text-xs font-black shadow-xl flex items-center gap-3 transition-all active:scale-95 disabled:opacity-50">
                 {isProcessing ? <Loader2 className="animate-spin" size={16} /> : <Wand2 size={16} />} AI ERASE
               </button>
             )}
             {currentTool === 'select-fill' && (
               <button onClick={handleFill} disabled={!selection} className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">FILL AREA</button>
             )}
             {currentTool === 'crop' && (
               <button onClick={handleCrop} disabled={!selection} className="px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl text-xs font-black shadow-xl active:scale-95 transition-all">CONFIRM CROP</button>
             )}
             {!['ai-erase', 'select-fill', 'crop'].includes(currentTool) && (
                <div className="px-6 text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 animate-pulse"></div>
                  {currentTool === 'select' ? (selectedObjectId ? 'Object Selected' : 'Select Tool') : `${currentTool} tool`}
                </div>
             )}
          </div>

          {isProcessing && <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-950/70 backdrop-blur-md"><Loader2 size={40} className="text-indigo-500 animate-spin" /><p className="mt-8 text-white font-black tracking-[0.3em] text-sm uppercase">AI Processing...</p></div>}
        </div>
      </div>
    </div>
  );
};

const ToolIcon = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1.5 group transition-all shrink-0 ${active ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>
    <div className={`w-12 h-12 rounded-xl flex items-center justify-center transition-all ${active ? 'bg-indigo-600/10 border border-indigo-500/50 shadow-lg' : 'bg-slate-800/50 hover:bg-slate-800'}`}>
      {icon}
    </div>
    <span className="text-[8px] font-black uppercase tracking-tighter">{label}</span>
  </button>
);
